Templates.PromptCss:
#__container_id .cf-survey-prompt {
    box-sizing: border-box;
}

#__container_id .cf-survey-prompt {
    position: fixed;
    z-index: 101;

    font: 14px Arial;
    background: rgb(246, 247, 248);
    border: 1px solid  #383d45;
    border-radius: 2px;
    box-shadow: 0 0 4px #383d45;
}

#__container_id .cf-survey-prompt--title,
#__container_id .cf-survey-prompt--text,
#__container_id .cf-survey-prompt--buttons {
    padding: 10px 20px;
}

#__container_id .cf-survey-prompt--title {
    background:  #383d45;
    font-weight: bold;
    color: #fff;
}

#__container_id .cf-survey-prompt--accept,
#__container_id .cf-survey-prompt--decline {
    -webkit-appearance: none;
    border: none;
    display: inline-block;
    font-weight: bold;
    border-radius: 2px;
    color: #fff;
    text-align: center;
    padding: 4px 30px;
    line-height: normal;
    height: 33px;
    cursor: pointer;
}

#__container_id .cf-survey-prompt--accept {
    background-color: #00a8f0;
    border-bottom: 1px solid #3c74b5;
}

#__container_id .cf-survey-prompt--decline {
    background-color: #adb6b5;
    border-bottom: 1px solid #383d45;
}

#__container_id .cf-survey-prompt--close {
    position: absolute;
    top: 0;
    width: 24px;
    height: 24px;
    cursor: pointer;
}

#__container_id .cf-survey-prompt--close circle {
    fill: #fff;
    stroke:#383d45;
    stroke-width:2px;
    stroke-linecap: round;
}

#__container_id .cf-survey-prompt--close path {
    stroke-width:2px;
    stroke-linecap: round;
    fill:none;
    stroke: #383d45;
}

#__container_id .cf-survey-prompt--bottom-right {
    bottom: 20px;
    right: 20px;
}

#__container_id .cf-survey-prompt--bottom-left {
    bottom: 20px;
    left: 20px;
}

#__container_id .cf-survey-prompt--top-right {
    top: 20px;
    right: 20px;
}

#__container_id .cf-survey-prompt--top-left {
    top: 20px;
    left: 20px;
}

#__container_id .cf-survey-prompt--centered .cf-survey-prompt--close,
#__container_id .cf-survey-prompt--top-left .cf-survey-prompt--close,
#__container_id .cf-survey-prompt--bottom-left .cf-survey-prompt--close {
    left: auto;
    right: -30px;
}

#__container_id .cf-survey-prompt--top-right .cf-survey-prompt--close,
#__container_id .cf-survey-prompt--bottom-right .cf-survey-prompt--close {
    left: -30px;
    right: auto;
}

#__container_id .cf-survey-prompt--centered {
    left: 0;
    right: 0;
    top: 0;
    bottom: 0;
    width: 305px;
    height: 130px;
    margin: auto;
}

Templates.OverlayCss:
body.cf-has-survey-overlay {
    overflow: hidden;
}

#__container_id .cf-survey-overlay {
    position: fixed;
    z-index: 101;
    left: 0;
    right: 0;
    top: 0;
    bottom: 0;
    width: 960px;
    height: 600px;
    margin: auto;
    border: 1px solid  #383d45;
    box-shadow: 0 0 2px #383d45;
    background: #fff;
}

#__container_id .cf-survey-overlay-content {
    width: 100%;
    height: 100%;
}

#__container_id .cf-survey-overlay-shim {
    position: fixed;
    z-index: 100;
    left: 0;
    top: 0;
    right: 0;
    bottom: 0;
    background-color: #383d45;
    opacity: 0.4;
}

#__container_id .cf-survey-overlay--close {
    position: absolute;
    top: 0;
    right: -60px;
    width: 48px;
    height: 48px;
    cursor: pointer;
}

#__container_id .cf-survey-overlay--close circle {
    stroke-width:2px;
    stroke-linecap: round;
    fill: #fff;
    stroke:#383d45;
}

#__container_id .cf-survey-overlay--close path {
    stroke-width:2px;
    stroke-linecap: round;
    fill:none;
    stroke: #383d45;
}

@keyframes cf-loading-animation {
    0% {
        opacity: 0;
    }

    50% {
        opacity: .8;
    }

    100% {
        opacity: 0;
    }
}

#__container_id .cf-survey-loading {
    position: absolute;
    left: 0;
    top: 0;
    right: 0;
    bottom: 0;
    width: 100px;
    height: 50px;
    margin: auto;
}

#__container_id .cf-survey-loading-items {
    font-size: 60px;
    display: -webkit-inline-box;
    display: -webkit-inline-flex;
    display: -ms-inline-flexbox;
    display: inline-flex;
    -webkit-box-align: center;
    -webkit-align-items: center;
    -ms-flex-align: center;
    align-items: center;
}

#__container_id .cf-survey-loading-items--item {
    animation: cf-loading-animation 1.8s infinite;
    animation-play-state: inherit;
    border-radius: 50%;
    opacity: 0;
    width: .4em;
    height: .4em;
    background: #777;
}

#__container_id .cf-survey-loading-items--item:nth-child(1) {
    animation-delay: 0s;
}

#__container_id .cf-survey-loading-items--item:nth-child(2) {
    animation-delay: .3s;
    margin: 0.6ex;
}

#__container_id .cf-survey-loading-items--item:nth-child(3) {
    animation-delay: .6s;
}
    
#__container_id .cf-survey-frame {
    display: block;
    width: 100%;
    height: 100%;
    border: none;
}

PageMaster.StartupScript:
document.documentElement.setAttribute('translate','no');
document.body.setAttribute('translate','no');
document.documentElement.style.setProperty('--sampsource-color', '^getColorsMain()^');
document.documentElement.style.setProperty('--sampsource-shade-color','^getColorsShade()^');
var qid = "^f('sampsource').get()^";

$(".finishlater").click(function(){
 $(this).text(' ');
 var delay = 0; 
 var url = "^f('xMESSAGES_10').label()^";
 setTimeout(function(){ window.location = url; }, delay);
});

$(function(){
  $("#dvlp_echoArea").draggable();
});

$(document).ready(function(){

  var splitOTS = $('#OTScheck').text();
  if(splitOTS == 'true')
  {
   var others = document.querySelectorAll(".cf-checkbox-answer__other.cf-text-box, .cf-text-box.cf-radio-answer__other, .cf-grid-3d-desktop__answer-other-input.cf-text-box, .cf-text-box, .cf-desktop-grid__answer-other");
   for (let i = 0; i < others.length; i++) {
      var other = others[i];
      var parent = other.parentNode
      var text = other.placeholder;
      other.placeholder = "";
      var newElement = document.createElement("div");
      newElement.style.display = 'inline'
      newElement.innerHTML = text;
      newElement.style.marginRight = '10px';
      parent.insertBefore(newElement, other);
   } 
  }
    var runMe = "^updateTimeTracker()^"; // Run in Call Block "Time Tacker"
 var IFwidth = 800; // default
    var IFheight = 500; // default
    var sWidth = screen.width;
    var sHeight = screen.height;


    if(IFwidth>sWidth) 
 {
  IFwidth = sWidth*0.98;
       IFheight = sHeight*0.75;
 }

 $('#ccpaZoneClose').css('display','none');
 $('#ccpaArea').css('display','none');
 $('#ccpaZone').css('display','none');
 $('#ccpamodal-bg').css('display','none');

 var ccpaURL = "^f('CCPAurl').toBoolean() ? f('CCPAurl') : 'https://ssrs.com'^";
    $('#ccpaLink').click(function(){
  $('#ccpaZoneClose').css('display','inline-block');
  $('#ccpaZoneFrame').prepend($('<div><iframe src="'+ccpaURL+'" frameborder="1" scrolling="yes" width="'+IFwidth+'" height="'+IFheight+'" id="ccpaFrame"></iframe></div>'));
  $('#ccpaArea').css('display','block');
  $('#ccpaZone').css('display','block');
  $('#ccpamodal-bg').css('display','block');
 });

 $('#ccpaZoneClose').click(function(){
  $('#ccpaArea').css('display','none');
  $('#ccpaZone').css('display','none');
  $('#ccpaZoneClose').css('display','none');
  $('#ccpamodal-bg').css('display','none');
  $('#ccpaZoneFrame').html($(''));
 });

   /////////////////// START CODE FOR CLICK AWAY COUNTER ///////////////////
 var qid = Confirmit.page.questions[0].id; 
    Confirmit.page.serverVariables.add("counterqid", qid); 
    $("<div id='onPageCounter' style='display:none;'></div>").insertAfter("#" + qid); 
    var counter = Number("^getCount()^"); 
    if(counter == null) { 
        counter = 0; 
    } 
    $(window).blur(function () { 
        counter += 1; 
        $("#onPageCounter").text(counter); 
    }); 
    $(window).focus(function () { 
        Confirmit.page.serverVariables.remove("counter"); 
        Confirmit.page.serverVariables.add("counter", counter); 
    });
   /////////////////// END CODE FOR CLICK AWAY COUNTER ///////////////////


    ///////////////////// DYNATQUALITY SCORE CODE //////////////////////////

  if( "^f('hQualityScoreSettings')['switch'].get() == 1^" == "True" ){
    var originalNavigate = Confirmit.pageView._pageView._navigate; 
    var boundOriginalNavigate = originalNavigate.bind(Confirmit.pageView._pageView);

    function qualityScoreCheck (confirmitEvent) {
        var disableCollect = document.getElementById('qualityscore_collect_disabled');
        if (!disableCollect && document.forms[0]) {
            try {
                var pageId = derivePageId();
                var matrixData = getMatrixData();
                imperium_qualityscore.CollectData(pageId, matrixData, CollectQSDataResponse);
            }
            catch (e) {
                console.error(e);
            }
        }
       else
          boundOriginalNavigate(confirmitEvent);
       function CollectQSDataResponse(data) { boundOriginalNavigate(confirmitEvent); }
        function derivePageId() {
            var p = "^CurrentForm()^";
            var loopId = $('input[name=__loopProgress]').val();
            if (loopId) p += "_" + loopId.split('=')[1].replace(';', '_');
            return p + "page";
        }
        function getMatrixData() {
            try {
                var d = {};
                var data = [];
                $('.cf-grid-layout, .cf-desktop-grid, .cf-desktop-multi-grid, .cf-grid-3d-desktop, .cf-desktop-hrs-grid, .cf-desktop-gb-grid, .cf-desktop-sr-grid, .cf-carousel, .cf-card-sort').each(function () {
                    var $this = $(this);
                    var qid = '';
                    var loopId = $('input[name=__loopProgress]').val();
                    $this.find('.cf-single-answer--selected, .cf-radio-answer--selected, .cf-checkbox-answer--selected, .cf-grid-answer__scale-item--selected, .cf-grid-single-answer--selected, .cf-grid-multi-answer--selected, .cf-answer-button--selected, .cf-button-answer--selected, .cf-card-sort-answer--selected, .cf-hrs-single__scale-item--selected, .cf-gb-single__scale-item--selected, .cf-star-rating-item--selected, .cf-hrs-grid-answer__scale-item--selected, .cf-gb-grid-answer__scale-item--selected, .cf-sr-grid-answer__scale-item--selected, .cf-grid-bars-item--selected, .cf-horizontal-rating-item--selected, .cf-slider').each(function () {
                        var $this = $(this);
                        if (['cf-gb-single__scale-item--selected', 'cf-gb-grid-answer__scale-item--selected', 'cf-sr-grid-answer__scale-item--selected', 'cf-grid-bars-item--selected', 'cf-horizontal-rating-item--selected', 'cf-star-rating-item--selected'].some(el => $this.attr("class").includes(el))) {
                            if ($this.attr('aria-checked') == 'false') { return true; }
                        }
                        var valueNow;
                        if ($this.attr('class').includes('cf-slider')) {
                            valueNow = $this.find('.cf-slider__handle').attr('aria-valuenow');
                            if (valueNow == -1) { return true; }
                        }
                        var rowId = '';
                        var idParts = $this.attr('id').split('_');
                        if (idParts[0].includes("mobile") || idParts[0].includes("desktop")) {
                            qid = idParts[1];
                            rowId = idParts[2];
                        }
                        else {
                            qid = idParts[0];
                            rowId = idParts[1];
                        }
                        if (loopId) {
                            qid += "_" + loopId.split('=')[1].replace(';', '_');
                        }
                        d[qid] = d[qid] || {};
                        d[qid][rowId] = d[qid][rowId] || [];
                        if ($this.attr('class').includes('cf-slider')) {
                            d[qid][rowId].push(valueNow);
                        } else if ($this.attr('class').includes('cf-card-sort-answer--selected')) {
                            d[qid][rowId].push($this.closest('.cf-card-sort__layout-cell').index());
                        } else if (['cf-horizontal-rating-item--selected', 'cf-grid-bars-item--selected', 'cf-star-rating-item--selected'].some(el => $this.attr("class").includes(el))) {
                            var scaleValue = $this.parent().attr('id').split('_');
                            d[qid][rowId].push(scaleValue[scaleValue.length - 1]);
                        } else {
                            d[qid][rowId].push(idParts[idParts.length - 1]);
                        }
                    })
                })
                for (var qid in d) {
                    var qData = [];
                    for (var rid in d[qid]) {
                        qData.push(qid + "_" + rid + '-' + d[qid][rid].join(','));
                    }
                    data.push(qid + ":" + qData.join(';'))
                }
                return data.length > 0 ? data.join('|') : '';
            }
            catch (e) {
              console.error(e);
              return '';
            }
        }
    }

    Confirmit.pageView._pageView._navigate = function(e) {
         qualityScoreCheck (e);
    }
  }

  function qsRaAttributes(QID, parameters, precodes = []){
     for(var i=0;i<precodes.length;i++)
        precodes[i] = (precodes[i]+'').toLowerCase();

     $('.imperium-ra-question').each(function(){
        var $this=$(this), elemId;
        elemId = $this.attr('id') || '';
        var splits = elemId.split('_');
        if(QID!=splits[0])
           return;

        if(precodes.length > 0){
           var rowId = splits[1];
           if(precodes.indexOf(rowId)<0)
             return;
        }
        var qsRaAttrs = $this.prop('imperium-ra-attrs') || {};
        $.extend(qsRaAttrs, parameters);
        $this.prop('imperium-ra-attrs', qsRaAttrs);
     });
  }  
});

PageMaster.CustomCSS:
:root {
  --sampsource-color: #02A1E2;
  --sampsource-shade-color: #CDEDFB;
  --hover-color: #CC0033;
  /* default color... is overriden by JavaScript tab, which reads the colours entered in 'Theme colours (survey)' resuable list */
}

.cf-searchable-question__answer-list-wrapper--filtered-answers {height: fit-content;}

.cf-table-layout__row--head, .cf-table-layout__head-spacer {
	background-color: #ffffff !important;
}
  
.catifont {
	/*color: var(--sampsource-color) !important;*/ /*uncomment this and comment out the line below if the CATI font should be the same color as radio/nav buttons*/
  	color: #02a1e2;
    font-weight: bold !important;
}

#pageTimerFrameArea {
  	display: none;
  	width: 0px;
  	height:0px;
}

input[type=number] {
  opacity: 1;
  text-align: left;
}
    
.cf-navigation {
	width: 100%;
}

.cf-navigation-next {
	float: right;
}

.cf-navigation-back {
	float: left;
}
  
.cf-radio-answer__other,
.cf-checkbox-answer__other, 
.cf-multi-answer__other-input {
    width: 30em;
}

.cf-error-block--bottom, .cf-error-block--absolute-bottom {
    margin-top: 0.5em;
    margin-bottom: 0;
    border-top: 1px solid #fff;
    border-bottom: none;
}

.cf-page__main {
    background-color: white;
    border-radius: 30px;
    padding: 0px 0px 20px 0px;
    -webkit-box-shadow: 0px 0px 18px 7px rgba(0,0,0,0.34); 
	box-shadow: 0px 0px 18px 7px rgba(0,0,0,0.34);
    margin: 24px auto 34px auto;
  	width: 80%;
}

.cf-error-list__item {
	font-size: 1.2em;
	font-weight: bold;
}

.cf-toast--error, .cf-powered-by-confirmit__link, .hide, #welcome_input {
	display: none; 
}

.cf-error-block--bottom, .cf-error-block--absolute-bottom {
    border-top: none;
}

.cf-question--error {
    border-color: transparent;
    box-shadow: 0px 0px 19px #ffb8b8 inset;
    border-radius: 10px;
}

.cf-page {
	font-family: 'Roboto', sans-serif;
	font-size: 1em;
	margin: auto;
}

.cf-page__header {
	min-height: 0em;
}

.cf-question {
  	text-align: left;
    margin-bottom: 10px;
  	border-bottom: 1px solid #ebebeb;
}

.cf-question__text {
	font-weight: 400;
	font-size: 1.05em;
}

.cf-question--rtl {
    text-align: right;
}

.cf-navigation--rtl .cf-navigation__button:first-child {
    margin-left: auto;
    margin-right: auto;
}
 
.cf-dropdown {
	background-color: #f8f7f7;
}

.cf-navigation__button {
  	margin: 0px auto 5px auto;
	vertical-align: top;
  	border: 0;
    background-color: var(--sampsource-color);
    font: normal 400 16px/44px 'Roboto Condensed', Arial, Helvetica, 'Nimbus Sans L', sans-serif;
    padding: 0 20px 3px;
    cursor: pointer;
    -webkit-border-radius: 5px;
    border-radius: 5px;
    -webkit-box-shadow: inset 0 -3px 0 0 rgba(0, 0, 0, 0.2);
    box-shadow: inset 0 -3px 0 0 rgba(0, 0, 0, 0.2);
    font-family: 'Roboto Condensed', Arial, Helvetica, 'Nimbus Sans L', sans-serif;
    font-size: 16px;
    line-height: 44px;
    text-transform: uppercase;
    color: #ffffff;
    font-weight: 400;
    font-style: normal;
    padding-right: 20px;
    padding-left: 20px;
    height: auto;
    width: auto;
    -webkit-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    -moz-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    -ms-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    -o-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
}

.cf-navigation__button:hover {
	color: #ffffff;
    padding-bottom: 0;
    margin-top: 3px;
    -webkit-box-shadow: inset 0 0 0 0 rgba(0, 0, 0, 0.02);
    box-shadow: inset 0 0 0 0 rgba(0, 0, 0, 0.02);
  	-webkit-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    -moz-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    -ms-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    -o-transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
    transition: margin-top .1s ease-in-out, margin-bottom .1s ease-in-out, padding-bottom .1s ease-in-out, box-shadow .1s ease-in-out;
}

.cf-navigation__button:first-child {
