var p = 'hParent';

//prime parent
f(p).set(2);

//default not parent
f(q).set(3);

if (f('pg1a').any('1')) {
    f(p).set(1);
    if (f('pg1b_4').toNumber()>0) {
        f(q).set(1);
    } else {
