    }
}

//copy ALL to Complete and then check pg3 and update as needed
f(comp).set(f(q));

if (f('pg3').any('1')) {
    f(comp).set(4)
}

var q = 'final_age';
var a1b = f('a1b').toNumber();
var child = 'pg5';

var pg5Codes = [2,3,4,5,7,8,9];
var finAgeCodes = [12,13,14,15,16,17];

/*
(PN: CREATE ‘FINAL_AGE’ VARIABLE
IF PG5=2, THEN FINAL_AGE=12
IF PG5=3, THEN FINAL_AGE=13
IF PG5=4, THEN FINAL_AGE=14
IF PG5=5, THEN FINAL_AGE=15
IF PG5=7 OR A1b=16, THEN FINAL_AGE=16
IF PG5=8 OR A1b=17, THEN FINAL_AGE=17
IF A1b=18-99, THEN FINAL_AGE=18-99)
*/

//a1b punching
f(q).set(a1b)

//pg5 punching
for (var i=0;i<pg5Codes.length;i++) {
    if (f(child).any(pg5Codes[i])) {
        f(q).set(finAgeCodes[i]);
    }
}

var q = 'qage';
var finAge = f('final_age').toNumber();

/*
(PN: CREATE ‘QAGE’ VARIABLE
IF FINAL_AGE=12-14 THEN QAGE=2 “12 to 14”
IF FINAL_AGE=15-17 THEN QAGE=3 “15 to 17”
IF FINAL_AGE=18-24 THEN QAGE=4 “18 to 24”
IF FINAL_AGE=25-34 THEN QAGE=5 “25 to 34”
IF FINAL_AGE=35-44 THEN QAGE=6 “35 to 44”
IF FINAL_AGE=45-54 THEN QAGE=7 “45 to 54”
IF FINAL_AGE=55-64 THEN QAGE=8 “55 to 64”
IF FINAL_AGE=65-99 THEN QAGE=9 “65+”)
*/

if (finAge<15)                {f(q).set(2)}
if (finAge>14 && finAge<18)   {f(q).set(3)}
if (finAge>17 && finAge<25)   {f(q).set(4)}
if (finAge>24 && finAge<35)   {f(q).set(5)}
if (finAge>34 && finAge<45)   {f(q).set(6)}
if (finAge>44 && finAge<55)   {f(q).set(7)}
if (finAge>54 && finAge<65)   {f(q).set(8)}
if (finAge>64 && finAge<=999) {f(q).set(9)}

//quota field
/*
12-17  (QAGE=2-3)
18-34  (QAGE=4-5)
35-64  (QAGE=6-8)
65+ (QAGE=9)
*/

if (f(q).any('2','3'))      {f('hAgeQuota').set(1)}
if (f(q).any('4','5'))      {f('hAgeQuota').set(2)}
if (f(q).any('6','7','8'))  {f('hAgeQuota').set(3)}
if (f(q).any('9'))          {f('hAgeQuota').set(4)}

var q = 'Final_gender';
var a2aSize = f('a2a').categories();
dvlp_echo('a2a size: ' + a2aSize,"green");

//default to other
f(q).set(7)

//if male/female punch
if (f('a2a').any('1')) {f(q).set(1)}
if (f('a2a').any('2')) {f(q).set(2)}

//if male and female go back to other
if (f('a2a').any('1') && f('a2a').any('2')) {f(q).set(7)}

var q = 'eth';
var d10Size = f('d10').categories();
dvlp_echo('d10 size: ' + d10Size,"green");

/*
(PN: CREATE ‘ETH’ VARIABLE
IF (D9=2 or 9) AND (D10_1=1 AND D1_2 / D1_3 / D1_4 / D1_5 / D1_9=0) OR (D10_2=1 AND ANY D1_1/D1_3/D1_4/D1_5=1), THEN ETH=1 “White Non Hispanic”
IF (D9=2 or 9) AND (D10_2=1 AND D1_1 / D1_3 / D1_4 / D1_5 / D1_9=0), THEN ETH=2 “Black Non Hispanic” 
IF D9=1, THEN ETH=3 “Hispanic”
IF [(D9=2 or 9) AND (D10_3=1 AND D1_1 / D1_2 / D1_4 / D1_5 / D1_9=0)] OR [(D9=2 or 9) AND (D10_4=1 AND D1_1 / D1_2 / D1_3 / D1_5 / D1_9=0)] OR (D10_5=1 AND D1_1 / D1_2 / D1_3 / D1_4 / D1_9=0)]; THEN ETH=4 “Other Non-Hispanic”
IF [(D9=2 or 9) AND (TWO OR MORE D1_1 / D1_2 / D1_3 / D1_4 / D1_5) THEN ETH=4 “Other Non-Hispanic”)
*/

//hierarchy set up
    if (d10Size.length>1) {
        f(q).set(4)
    } else {
        if (f('d10').any('1','2')) {
            if (f('d10').any('1')) {f(q).set(1)}
            if (f('d10').any('2')) {f(q).set(2)}
        } else {
            f(q).set(4)
        }
    }    

if (f('d10').any('999')) {f(q).set(9)}

//set hispanic if d9=1 regardless of what is at d10
