function maskBroadcast_awareness_SBLoop()
{
    var s = nset(4);
    var hweek = f("hWeek");

    if(hweek.isect(nnset(1,14)).size() > 0){ s = s.union(set(18)); }
    if(hweek.isect(nnset(8,17)).size() > 0){ s = s.union(set(19)); }
    if(hweek.isect(nnset(6,15)).size() > 0){ s = s.union(set(12,13)); }
    if(hweek.isect(nnset(14,19)).size() > 0){ s = s.union(set(14)); }
    if(hweek.isect(nnset(14,20)).size() > 0){ s = s.union(set(15)); }
    if(hweek.isect(nnset(14,21)).size() > 0){ s = s.union(set(16)); }
    if(hweek.isect(nnset(8,21)).size() > 0){ s = s.union(set(17)); }

    return s;
}

