function MatchUpGame(val) {
    var week = f('hWeek');    
    var weekNum = week.value();
    var mList = 'hWeekMatch_' + weekNum;

    var txt = "";
    if (week.any(weekNum)) {
        txt = f(mList).domainLabels()[val]
    }

