function maskWHY_WATCH_SPECIFICLoop()
{
    var wwCode = f("WHY_WATCH_PRIMARY").toNumber();
    var WWPArr = [14,16,15,18];
    var WWSArr = [1,2,3,4];
    var s = new Set();

    for(var i = 0; i < WWPArr.length; i++)
    {
        if(WWPArr[i] == wwCode)
        {
            s.add(WWSArr[i]);
        }
    }

    if(wwCode == 7 && f("x3aaAsk",2).any('8', '18', '144', '242', '244', '342'))
    {
        s.add(5);
    }
    if(f("hWeek").any('17') && f("WHY_WATCH_PRIMARY").any('14'))
    {
        s.add(6);
        s.add(7);
        s.add(8);
        s = s.diff(set('1','2','3','4'))
    }

    return s;
}

