function forceMultiGridQs(qid,codesArr)
{
    var ans = f(qid+"_1").domainValues();
    var count = 0;

    dvlp_echo('ans = ' + ans, 'orange');
    dvlp_echo('codesArr = ' + codesArr, 'orange');
    dvlp_echo('count = ' + count, 'orange');

    for(var i = 0; i < codesArr.length; i++)
    {
        var qidCount = 0;

        for(var j = 0; j < ans.length; j++)
        {
            if(f(qid+"_"+codesArr[i]).any(ans[j]))
            {
                qidCount++;
            }
        }

        dvlp_echo('qidCount = ' + qidCount, 'orange');

        if(qidCount > 0)
        {
            count++;
        }
    }

    dvlp_echo('count = ' + count, 'orange');

    if(count != codesArr.length)
    {
        ErrorMsg(GetCustomText(287));
    }
}

