function checkSL(qid,answer,scale)
{
    if (Forward())
    {
        f('hStraightLine')[qid].set(null);

        for(var i = 1; i <= answer; i++)
        {
            if (GetGridSetEqualTo(qid, i).size() == GetGridSetBetween(qid, 1, scale).size())
            { 
                f('hStraightLine')[qid].set(1); 
                dvlp_echo("Straightlining: " + qid, "red");
            }
        }
    }
}

function checkSLLetter(qid,scale)
{
    if (Forward())
    {
        f('hStraightLine')[qid].set(null);
        var codes = f(qid).domainValues();

        for(var i = 1; i <= codes.length; i++)
        {
            if (GetGridSetEqualTo(qid, codes[i-1]).size() == GetGridSetBetween(qid, 1, scale).size())
            { 
                f('hStraightLine')[qid].set(1); 
                dvlp_echo("Straightlining: " + qid, "red");
            }
        }
    }
}


function checkLoopSL(qid, loop, answer, scale)
{
    if (Forward())
    {
        var code = qid+"x"+loop;
        f('hStraightLine')[code].set(null);

        for (var i = 1; i <= answer; i++)
        {
            if (GetGridSetEqualTo(qid, i).size() == GetGridSetBetween(qid, 1, scale).size())
            { 
                f('hStraightLine')[code].set(1); 
                dvlp_echo("Straightlining: " + code, "red");
            }
        }
    }
}


function checkMCSL(qid)
{
    if (Forward())
    {
        f('hStraightLine')[qid].set(null);
        
        var codes = f(qid).domainValues();
        var codeCount = 0;

        for(var i = 0; i < codes.length; i++)
        {
            if(codes[i] < 900)
            {
                codeCount++;
            }
        }

        if(codeCount == f(qid).size())
        {
            f('hStraightLine')[qid].set(1);
            dvlp_echo("Straightlining: " + qid, "red");

        }
    }
}

