function DisplayCallHistory()
{
	var str = "<div class=callHistoryArea>";
	var tries : int = GetCallAttemptCount();
	var start : int = 1;

	if (tries > 10)
	{
		start = tries-10;
	}

	if (tries > 1)
	{
  		str += "<table>";
      	str += "<thead>";
		str += "<tr><th>Call ID</th><th>Call Date/Time</th><th>Interviewer</th><th>Call Outcome</th><th>App Date/Time</th><th>Comments</th><th>Contact</th></tr>";
		str += "</thead>";
      	str += "<tbody>";

		for(var i=start; i<=(tries-1); i++)
		{
			// var z = i % 2;
			// var CSSrow = (z==0) ? "gridlabelalter" : "gridlabel";
  
			var dateAll : String = f('CallDateTime',i).get();
			var DateArray : Array = dateAll.split(" ");
			var DateFmt : String = DateArray[0]+" "+DateArray[1]+" "+DateArray[2]+" "+DateArray[3];
			var datetime = DateFmt != null ? DateFmt : "";
			var interviewer = f('Int_Name',i).toBoolean() ? f('Int_Name',i).get() : "";
			var its = f('CallExtendedStatus',i).toBoolean() ? f('CallExtendedStatus',i).valueLabel() : "";
			var AppAll : String = f('CallAppTime',i).get();
			var ADateArray : Array = AppAll.split(" ");
			var ADateFmt : String = ADateArray[0]+" "+ADateArray[1]+" "+ADateArray[2]+" "+ADateArray[3];
			var apptime = f('CallAppTime',i).toBoolean() ? ADateFmt : "";
			var comments = f('CallComments',i).toBoolean() ? f('CallComments',i).get() : "";
			var contactperson = f('Contactperson',i).toBoolean() ? f('Contactperson',i).get() : "";
          
			str += "<tr><th>"+i+"</th><td>"+datetime+"</td><td>"+interviewer+"</td><td>"+its+"</td><td>"+apptime+"</td><td>"+comments+"</td><td>"+contactperson+"</td></tr>";
		}
      
      	str += "</tbody>";
      	str += "</table>";
      	str += "</div>";
	}
  
	return str;
}

