function shuffleArray(array)
{
	for(var i = array.length - 1; i > 0; i--)
    {
      	var j = Math.floor(Math.random() * (i + 1));
      	var temp = array[i];
      	array[i] = array[j];
      	array[j] = temp;
	}
   	
  	return array; 
}

function randomQuestionOrderGenerator(qn, qIDs, qnRandom) {
    if (qn.size() == 0) {
        var suffleOrderOfQIDs = shuffleArray(qIDs);
        var suffleOrderOfQIDsAsStr = suffleOrderOfQIDs.toString();
        qnRandom.set(suffleOrderOfQIDsAsStr);

        for (var i = 0; i < suffleOrderOfQIDs.length; i++) {
            var eachQID = suffleOrderOfQIDs[i];
            var orderNumber = i + 1;
            qn[eachQID].set(orderNumber);
        }
    }
}

function maxCode(qid) 
{
    var allCodes = a(qid).members();
    var highCode = 0;

    for(var i = 0; i < allCodes.length; i++)
    {
        var code = allCodes[i];
        var codeInt = parseInt(code);

        if(codeInt > highCode)
        {
            highCode = codeInt;
        }
    }

    return highCode;
}

function maxLength(codes)
{
    var longestStringCode : int = 0;

    for(var i=0; i<codes.length; i++)
    {
        var code = codes[i];
        var codeLength : int = code.ToString().length;

        if(codeLength>longestStringCode)
        {
            longestStringCode = codeLength;
        }
    }

    return longestStringCode;
}

function SetRandomization(qid)
{
  	// NEED HELP? See working example demo survey:p660554654948
	var qnRandom = f('hRandom');
  	var qn = f(qid);
  	var qnType = qn.getType();
  	var hasAnswers : Boolean = false;
  
  	if(qnType=='CODED' || qnType=='COMPOUND' || qnType=='3DGrid')
    {
    	hasAnswers = true;
      
	  	if(qnType=='3DGrid')
    	{
			var qn3G = Get3DGridQuestionIds(qid);
          	qid = qn3G[0]; // make the new qID - NOTE: if wanting to store the 3Dgrid answer order, please enter the first qID inside the 3Dgrid instead
      		qn = f(qid);
        }
	}
  	
  	if(hasAnswers)
    {
      	if(checkIfQidExists(qid))
        {
			var getQidCodesInRandomOrder = f(qid).domainValues(); // get codes available to show in random order
          	var getQidAllCodes = a(qid).members(); // get all answer codes used in the question
          	var maxCodeLength = maxLength(getQidAllCodes); // return the largest length of all codes in the question
			var qidCodesInRandomOrderWithLeadingZeros = processleadingZeros(getQidCodesInRandomOrder,maxCodeLength); // process leading zeros of the random codes to show
			qnRandom[qid].set(qidCodesInRandomOrderWithLeadingZeros);
            dvlp_echo('hRandom_'+qid + ' = ' + qidCodesInRandomOrderWithLeadingZeros,'orange');
          
			// Now check to see if there's a matching qidLoop for the same question
			var qidLoop = qid+"Loop"; // if Q1 was in a loop, the loopID needs to be Q1Loop

			if(checkIfQidExists(qidLoop))
			{
				var getQidLoopCodesInRandomOrder = f(qidLoop).domainValues();
				var getQidLoopAllCodes = a(qidLoop).members(); // get all answer codes used in the question
				var maxCodeLengthLoop = maxLength(getQidLoopAllCodes); // return the largest length of all codes in the question
				var qidLoopCodesInRandomOrderWithLeadingZeros = processleadingZeros(getQidLoopCodesInRandomOrder, maxCodeLengthLoop);
				qnRandom[qidLoop].set(qidLoopCodesInRandomOrderWithLeadingZeros);
                dvlp_echo('hRandom_'+qidLoop + ' = ' + qidLoopCodesInRandomOrderWithLeadingZeros,'orange');
			}
          
          	if(qnType=="COMPOUND")
            {
              	var codes = qn.domainValues()
                var firstCode = codes[0];
              	var firstQnAns = qn[firstCode];
              
              	if(!firstQnAns.DICHOTOMY && !firstQnAns.OPEN)
                {
                  	// Must be a grid question
                	// Now check to see if there's a matching qidScale for the same question
                	var qidScale = qid+"Scale";
    
                	if(checkIfQidExists(qidScale))
                	{
                    	var getQidScaleCodesInRandomOrder = firstQnAns.domainValues(); // The scale answer order or the first item is the same as the rest
						var qidScaleCodesInRandomOrderWithLeadingZeros = processleadingZeros(getQidScaleCodesInRandomOrder);
						qnRandom[qidScale].set(qidScaleCodesInRandomOrderWithLeadingZeros);
                        dvlp_echo('hRandom_'+qidScale + ' = ' + qidScaleCodesInRandomOrderWithLeadingZeros,'orange');
                    }
                }
            }
        }
	}
  
  	function checkIfQidExists(qid)
	{
      	var qidLower = qid.ToLower();
      	var qnRandom = f('hRandom');
  		var qnRandomAllCodes = qnRandom.domainValues();
      	var checkVal = false;

      	for(var i=0; i<qnRandomAllCodes.length; i++)
        {
			var code = qnRandomAllCodes[i];
          	var codeLower = code.ToLower();
          	
          	if(codeLower==qidLower)
            {
              	checkVal = true;
              	break;
            }
        }
      
		return checkVal;
    }
}

function processleadingZeros(codes,maxCodeLength)
{
    var rtnDomainArrayAsStringWithLeadingZeros = "";
    var leadingZeros = "";
    var i = 0;
      
    for(i=0; i<maxCodeLength; i++)
    {
        leadingZeros += "0";
    }
    
    for(i=0; i<codes.length; i++)
    {
        var code = codes[i];
        var thisCodeLength = code.length;
        var codeAsDouble : Double = Double(code);
        var newCodeWithLeadingZeros : String = "";

        if(!Double.IsNaN(codeAsDouble))
        {
            newCodeWithLeadingZeros = codeAsDouble.ToString(leadingZeros);
        }
        else
        {
            var diffInLength : int = maxCodeLength-thisCodeLength;
            var generateZeros : String = "";

            for(var j=0; j<diffInLength; j++)
            {
                generateZeros += "0";
            }

            newCodeWithLeadingZeros = generateZeros+code; // Is adding leading zeros to a letter string correct?
        }

        if(i==0)
        {
            rtnDomainArrayAsStringWithLeadingZeros = newCodeWithLeadingZeros;
        }
        else
        {
            rtnDomainArrayAsStringWithLeadingZeros += ","+newCodeWithLeadingZeros;
        }
    }

  	return rtnDomainArrayAsStringWithLeadingZeros;
}

function SetOrder(qid)
{
  	// NEED HELP? See working example demo survey:p168007158230
	var qnOrder = f('hOrder');
  	var qn = f(qid);
  	var qnType = qn.getType();
  	var hasAnswers : Boolean = false;
  
  	if(qnType=='CODED' || qnType=='COMPOUND' || qnType=='3DGrid')
    {
    	hasAnswers = true;
      
