    	{
			var qn3G = Get3DGridQuestionIds(qid);
          	qid = qn3G[0]; // make the new qID - NOTE: if wanting to store the 3Dgrid answer order, please enter the first qID inside the 3Dgrid instead
      		qn = f(qid);
        }
	}
  	
  	if(hasAnswers)
    {
      	if(checkIfQidExists(qid))
        {
			var getQidCodesInRandomOrder = f(qid).domainValues();
            var getNumQidCodes = f(qid).size();
			var qidCodesInRandomOrderWithLeadingZeros = processleadingZeros(getQidCodesInRandomOrder);
            var order = '';
            for (var i=0;i<getQidCodesInRandomOrder.length;i++) {
              var iter = i + 1;
              if (iter>1 && getNumQidCodes>i ) { //add comma
                order = order + ',';
              }
              order = order + Nth(qid,iter);
            }
			qnOrder[qid].set(order);
            dvlp_echo('hOrder_'+qid + ' = ' +order ,'orange');
        }
	}
  
  	function checkIfQidExists(qid)
	{
      	var qidLower = qid.ToLower();
      	var qnOrder = f('hOrder');
