      	var checkVal = false;

      	for(var i=0; i<qnOrderAllCodes.length; i++)
        {
			var code = qnOrderAllCodes[i];
          	var codeLower = code.ToLower();
          	
          	if(codeLower==qidLower)
            {
              	checkVal = true;
              	break;
            }
        }
      
		return checkVal;
    }
}

