function convertArrOrderCodes()
{
  	var qID1 = CurrentForm();
  	var qID2 = "hOrder_"+qID1;
  	var qn1 = f(qID1);
  	var qn2 = f(qID2);
  	var buildUpVals = "";
  	qn2.set(null);
  
  	if(qn1.toBoolean())
    {
      	var valAsStr = qn1.get();
