        if (Request("counter") != null) {
            f("counter_" + qid).set(Request("counter"));
        }
    }
}

function checkQidToRunBrowserLeaveCode(qid) {
    var outcome = false;

    if (qid != undefined) {
        if (qid != null) {
            var codes = f("counter").domainValues();

            for (var i = 0; i < codes.length; i++) {
                var code = codes[i];

                if (code == qid) {
                    outcome = true;
                }
            }
        }
    }

    return outcome;
}

function StoreTime(section)
{

//if section in function, set current section, else just use current section
  if (section) { 
   f('xCurrentSection').set(section);
  } else {
   var section = f('xCurrentSection'); 
  }

//if no section set, don't continue  
  if (!f('xCurrentSection').toBoolean()) {
    return
  } 
  
  
	var str = "";
	var start = f('hid_LastLoadTime')[section];
	var qts = f('hid_SectionTime')[section];
	var loi = f('hid_LOI');  

	if(!start.toBoolean())
	{
		var d = new Date();
		start.set(d.getTime());
		var d1 = d;
	}
	else
	{
		var d1 = new Date(start.toNumber());
	}
	
	var d2 = new Date();
	var t1 = d1.getTime();
	var t2 = d2.getTime();
	var interval = Math.round((t2-t1)/1000);
	
    //mark last load time as now for next question
	start.set(t2);
	
    //exclude time that is greater than 300/600
    if (IsCati()) {
	  var threshold = survey_setting()['CatiPageTimeLimit']
    } else { 
	  var threshold = survey_setting()['WebPageTimeLimit']
    }
       
    //add time to stored time for section and LOI
	if(interval < threshold)
	{
	var tot1 = qts.toBoolean() ? qts.toNumber() : 0;
	var tot2 = tot1 + interval;
	qts.set(tot2);
      
	var loi1 = loi.toBoolean() ? loi.toNumber() : 0;      
	var loi2 = loi1 + interval;      
    loi.set(loi2);
	}
}

