var loi = f('hid_LOI');    
loi.set(null);  
}

function StartTimer(sect){
  if (Forward()) {
	  clearSLT();
  }

  StoreTime(sect);
  var cursect = f('xCurrentSection');
  cursect.set(sect);
  dvlp_echo('start ' + sect, 'blue');
}

function EndTimer(sect){
  if (Forward()) {
	  StoreTime(sect);
  }

  clearSLT();
  
  if (!Forward()) {
  	StoreTime(sect);
  }

  var cursect = f('xCurrentSection');
  cursect.set(sect);
}

