function SetxTIMES() 
{
	if(!IsInProductionMode())
    {
      	return false;  //exclude for testing
    }
	
	//ENDDATE
	var d2 = new Date();
	var starttime = f("xTimestamp_1").toNumber();

	var endtime = Math.floor((d2.getTime())); 
	f('xTimestamp_2').set(endtime);
	
	
	var diff = (endtime - starttime)/1000;
	var secs = Math.floor(diff);
    
    
    var date = OurDate(-5);
	var time = OurTime(-5);
	f("xTimestamp_4").set(date + "|" + time);  
    

	//dvlp_echo('xtimestamp_1 = ' + f('xTimestamp_1'),'red');
	//dvlp_echo('xTimestamp_2 = ' + f('xTimestamp_2'),'red');
	//dvlp_echo('xTimestamp_3 = ' + f('xTimestamp_3'),'red');
	//dvlp_echo('xTimestamp_4 = ' + f('xTimestamp_4'),'red');
	//dvlp_echo('secs = ' + secs,'red');
	
  	var timer = secs	
					
		var hours = Math.floor(timer / 3600);
		timer -= hours * 3600;
		//dvlp_echo('hours = ' + hours,'red');
		
		var minutes = Math.floor(timer / 60);
		timer -= minutes * 60;
		//dvlp_echo('minutes = ' + minutes,'red');
		
		var seconds = parseInt(timer % 60, 10);
		//dvlp_echo('seconds = ' + seconds,'red');
		
		//dvlp_echo('diff = ' + diff,'red');
		//dvlp_echo('','red');
		//dvlp_echo('duration = ' + hours + ':' + (minutes < 10 ? '0' + minutes : minutes) + ':' + (seconds < 10 ? '0' + seconds : seconds),'red');
	
  
	if(!f('xQuestionHistory').toBoolean()){
		f('LOI').set(secs);
		return;
	}

	//calculate Times in seconds for xQuestionTimeHistory
	var xq = f('xQuestionTimeHistory');
	if (xq[1].toBoolean()) {
		if (!xq[2].toBoolean()) xq[1].set(xq[1] + ',' + new Date().getTime());
		var arr1 = xq[1].toString().split(',');
		xq[2].set(null);
		for (var i = 1; i < arr1.length; i++) xq[2].toBoolean() ? xq[2].set(xq[2] + ',' + ((arr1[i] - arr1[i - 1]) / 1000).toFixed(3) ) : xq[2].set(((arr1[i] - arr1[i - 1]) / 1000).toFixed(3));
	}

  	var qtimes, quests, validQ;

	if (!f('LOI').toBoolean()) {
		//Search QID function definition ****END****

		//definition of variables for calculations
		qtimes = f('xQuestionTimeHistory')['2'].toString().split(',');
		quests = f('xQuestionHistory').toString().split(',');
		validQ = f('xQuestionHistoryValid').toBoolean()?f('xQuestionHistoryValid').toString().split(","):f('xQuestionHistory').toString().split(",");
		var infohold = new Array();
		var realsecs = 0;
		

		//loop through all and calculate
		for (var k in qtimes) if(questionTypes(quests[k].split("|")[0])=='INFO' || isIn_array_splice(quests[k], validQ)) {
			var popul = indxqid(infohold, quests[k]);
			var tmpsec = qtimes[k];
			var currqtime = parseFloat(tmpsec);
			if (popul != -1) {
				currqtime = parseFloat(infohold[popul].qtime) + parseFloat(tmpsec);
			}
			var scrnum = 0;
			if (popul != -1) {
				scrnum = parseInt(infohold[popul].nofscr) + 1;
			}
			var scrt = '' + parseFloat(tmpsec).toFixed(3);
			if (popul != -1) {
				scrt = infohold[popul].scrtimes + ', ' + scrt;
			}
			var mlimit = false;
			//question limiter check and re-set value
			if (currqtime > f('xQuesTimeLimit').toNumber()) {
				currqtime = currqtime % f('xQuesTimeLimit').toNumber();
				mlimit = true;
			}
			if (popul != -1) {
				infohold[popul] = {
					qid: quests[k],
					qtime: currqtime,
					nofscr: scrnum,
					scrtimes: scrt,
					limiter: mlimit
				};
			} else {
				infohold.push({
					qid: quests[k],
					qtime: currqtime,
					nofscr: scrnum,
					scrtimes: scrt,
					limiter: mlimit
				});
			}
		}
		//end loop

		for (var p in infohold) {
			f('xQuestionTimeHistory_3').set(f('xQuestionTimeHistory_3').toBoolean() ? f('xQuestionTimeHistory_3').get() + '; ' + infohold[p].qid + '-' + infohold[p].qtime.toFixed(3) + '[' + infohold[p].scrtimes + ']' : infohold[p].qid + '-' + infohold[p].qtime.toFixed(3));
			f('xQuestionTimeHistory_4').set(f('xQuestionTimeHistory_4').toBoolean() ? f('xQuestionTimeHistory_4').get() + '; ' + infohold[p].qid + '-' + infohold[p].qtime.toFixed(3)									 : infohold[p].qid + '-' + infohold[p].qtime.toFixed(3));
			realsecs += infohold[p].qtime;
		}

		var tmpdouble = realsecs * 2;
		//set all recorded times
		f('xLOIinfo_1').set(secs); //Custom calculated time spend on survey without limiter
		f('xLOIinfo_2').set(realsecs); //Custom calculated time spend with max limiter per question
		//end recorded times
		
		dvlp_echo('xLOIinfo_1 = ' + f('xLOIinfo_1'),'green');
		dvlp_echo('xLOIinfo_2 = ' + f('xLOIinfo_2'),'green');

		//check if more than 2 times or less than OLD LOI
		if (secs > tmpdouble) {
			//set final result based on Limited LOI
			f('LOI').set(realsecs); //New calculation
		} else {
			f('LOI').set(secs); //Original calculation
		}
		//END LOI CALCULATION LIMITER
	}

	function isIn_array_splice(needle,haystack){
		for(var i=0;i<haystack.length;i++) if(needle==haystack[i]) {
			validQ.splice(i,1);
			return true;
		}
		return false
	}
}



//Search QID function definition ****START****
function indxqid(arr, tmpqid) {
	var res = -1;
	for (var i = 0; i < arr.length; i++) {
		if (arr[i].qid && arr[i].qid == tmpqid) {
			res = i;
			break;
		}
	}
	return res;
}

 function CaptureQuestions() {
   
	var cq = CurrentForm();
	if(cq==null) return;

	var dt = new Date();
	var lp = CurrentLoops().ToString();
	var xq = f('xQuestionTimeHistory');
	var q = f('xQuestionHistory');  

	xq[1].toBoolean()? xq[1].set(xq[1] + ',' + dt.getTime()):xq[1].set(dt.getTime());
