function isUnique(needle, haystack) {
	var search = haystack.split(",");
	var found = false;
	for (var i in search) {
		if (search[i] == needle) {
			found = true;
			break;
		}
	}
	return !found;
}

function CaptureValidQuestions() {

  	var cq = CurrentForm();
	if(cq==null) return;

	var lp = CurrentLoops().ToString();
	var loopInfo="";
	if (lp!=""){
		var lid=lp.split(",");
		for(var i=0,loops=[];i<lid.length;i++) loops.push(lid[i]+"="+f(lid[i]).get());
		loopInfo="|"+loops.join(";")
	}

	if(f('xQuestionHistoryValid').toBoolean())	f('xQuestionHistoryValid').set(f('xQuestionHistoryValid').get() + "," + cq+loopInfo)
	else										f('xQuestionHistoryValid').set(cq+loopInfo);
}


function questionTypes(qid){
	try{
		var type=f(qid).getType();
		var ret=type;
		switch(type){
			case 'CODED'			 : ret='SINGLE';	break;
			case 'COMPOUND' 		 :
				var codes =	f(qid).domainValues();
				var innerType=f(qid)[codes[0]].getType();
				switch(innerType) {
					case 'DICHOTOMY' : ret='MULTI'; break;
					case 'CODED'	 : ret='GRID'; break;
					case 'OPEN'		 : ret='RANKING/OPENTEXTLIST'; break;
					case 'NUMERIC'	 : ret='NUMERICLIST'; break;
				} 
				break;
			case '3DGrid' :
				var l3dgrid = Get3DGridQuestionIds(qid)
				for(var i=0,isMultGrid=true;i<l3dgrid.length;i++) {
					if(f(l3dgrid[i]).getType()!="COMPOUND") 										{isMultGrid=false; break;}
					else if(f(l3dgrid[i])[f(l3dgrid[i]).domainValues()[0]].getType()!="DICHOTOMY")  {isMultGrid=false; break;}
				}
				if(isMultGrid) ret='MULTIGRID'
				break;
			case ''	: ret = 'INFO'; break;
		}
		
	}catch(err){
		ret = 'INFO';
	}
	//dvlp_echo(ret,'blue');
	return ret; 
}

