// set update quota variable and counter variable
f('xDevice_updateForQuota').set(1);


getBrowserCollection(f('xDevice_updateForQuota').get());



function getBrowserCollection(bUpdateQuota){

var httpAgentVar='';
var httpOsPlatform='';

	if(IsInProductionMode()){
		// Browser Language detection
		try{
			var BrowsLangDet = Request.ServerVariables("HTTP_ACCEPT_LANGUAGE");
			if(BrowsLangDet.length > 150){BrowsLangDet = BrowsLangDet.substring(0,145) + "...";}
			f('xbrowser_Language').set(BrowsLangDet);
		}catch(err){}
		
		// Browser JavaScript detection
		try{f('xbrowser_JavaScript').set(Request.Browser.JavaScript);}catch(err){}	
		
		// get user agent string
		
		try{
		  httpAgentVar = Request.ServerVariables("HTTP_USER_AGENT").ToString().ToLower();
		  //f('xuser_agent').set(httpAgentVar);
		  setFormData(null,httpAgentVar,bUpdateQuota,false);
		}catch(err){}	

		// get http browser platform
		try{
		  httpOsPlatform=Request.Browser.Platform.ToLower();
		  // testing only	  
		}catch(err){}	
		
		// Browser Build detection .net frame work only update once
		try{f('xbrowser_Build').set(Request.Browser.Type);}catch(err){} 

		// Mobile Device detection .net frame work only update once
		try{f('xbrowser_Mobile').set(Request.Browser.IsMobileDevice);}catch(err){}		
		
		// recode device info based on USstring
		getDeviceInfo(httpOsPlatform,httpAgentVar,bUpdateQuota);
	   
	} 
} 

	/*********** detect browser Platform************/
   function getDeviceInfo(osPlatform,UAStr,bUpdateQuota){
	
	/****** Device info description*******/
	var deviceType={
		"undetermined"	:0,
		"PC"			:1,//PC/laptop/large screen device
		"iPhone"		:2,//iPhone/iPod
		"iPad"			:3,//iPad/iPad mini
		"androidPhone"	:4,//android phone
		"androidTablet"	:5,//android Tablet
		"oSmartPhone"	:6,//other smart phone- blackberry etc
		"oSmartTablet"	:7,//Other smart tablet-e.g. Nook Kindle etc
		"genericPhone"	:8,//Generic phones (none touch+ orientation)+ windows phone none touch
		"genericDevice"	:9,//none touchable small screen devices (e.g PDA, E-readers etc)+ windows tablet none touch
		"smWindowsPhone":10,//windows phone touch supported
		"smWindowsTablet":11,//windows tablet	touch supported	
		"ntWindowsPhone":12,//windows phone touch NOT supported
		"ntWindowsTablet":13,//windows tablet	touch NOT supported	
		"tinySMDevice"	:14	//very small screen smart device	
	}	
	var platformCode={
		"other"			:99,
		"ios"			:1,
		"android"		:2,
		"windowsphone"	:3,
		"windowsTablet"	:4,	
		"windows"		:5,				
		"blackBerry"	:6
	}	
			
	var deviceInfo={
			type		: deviceType.undetermined,
			os			:{
			 name		:'',
			 version	:null,
			 category	:{
				 isIOS			:false,
				 isLinux		:false,
				 isAndroid		:false,
				 isMac			:false,
				 isWindows		:false,
				 isTV			:false,
				 isElectronicbook :false,
				 iCode			:platformCode.other			 
				}
			},
			browserBuild:{
				name   :'',
				version:null
			},
			compView   :0,
			model	   :''
		};
		getDevicePlatform(osPlatform, UAStr,deviceInfo,deviceType,platformCode)	;
		get_browser(deviceInfo,deviceType,osPlatform,UAStr);	
		//var deviceStr=setFormData(deviceInfo,null);		
		setFormData(deviceInfo,null,bUpdateQuota,true);	
		//return deviceStr;				
	}
	
	function getDevicePlatform(osPlatform, UAStr,deviceObj,dType,platformCode){
		var isPlatFormSet=false;
		// ios
		deviceObj.os.category.isIOS=detectIOS(osPlatform,UAStr,deviceObj,dType);
		deviceObj.os.category.isElectronicbook=detectEbook(osPlatform,UAStr,deviceObj,dType);
		if(deviceObj.os.category.isIOS && deviceObj.os.category.isElectronicbook){
			deviceObj.os.category.isIOS=false;
			
		}
		if(deviceObj.os.category.isIOS){
			deviceObj.os.category.iCode=platformCode.ios;
			isPlatFormSet=true;
		}else{
            
			deviceObj.os.category.isWindows=detectWindows(osPlatform,UAStr,deviceObj,dType,platformCode);
			deviceObj.os.category.isTV=detectTV(osPlatform,UAStr,deviceObj,dType);
			if(!(deviceObj.os.category.isWindows||deviceObj.os.category.isTV)){
			
				// linux, android, windows, mac, webTV
                
				deviceObj.os.category.isLinux=detectLinux(osPlatform,UAStr,deviceObj,dType);				
				deviceObj.os.category.isAndroid=detectAndroid(osPlatform,UAStr,deviceObj,dType);
				deviceObj.os.category.isElectronicbook=detectEbook(osPlatform,UAStr,deviceObj,dType);
				deviceObj.os.category.isChromeOs=detectChromeOs(osPlatform,UAStr,deviceObj,dType);				
				deviceObj.os.category.isMac=detectMac(osPlatform,UAStr,deviceObj,dType);
				
				if(deviceObj.os.category.isLinux||deviceObj.os.category.isElectronicbook ||deviceObj.os.category.isAndroid||deviceObj.os.category.isMac||deviceObj.os.category.isChromeOs){
					isPlatFormSet=true;
					if(deviceObj.os.category.isLinux && deviceObj.os.category.isAndroid){
						deviceObj.os.category.isLinux=false;
					}
					if(deviceObj.os.category.isLinux && deviceObj.os.category.isElectronicbook){
						deviceObj.os.category.isLinux=false;                    	
					}
					if(deviceObj.os.category.isAndroid && deviceObj.os.category.isElectronicbook){
                      	deviceObj.os.category.isAndroid=false;						
                    }
					if(deviceObj.os.category.isAndroid){
						deviceObj.os.category.iCode=platformCode.android;
						
					}
				}
			}
			else {
					isPlatFormSet=true;		
			} 
		
		}
		if(!isPlatFormSet){
			if(detectBlackberry(osPlatform,UAStr,deviceObj,dType)){
				// black berry
				deviceObj.os.category.iCode=platformCode.blackBerry;
				isPlatFormSet=true;		
			}
			else if (detectNokia(osPlatform,UAStr,deviceObj,dType)){
				isPlatFormSet=true;	
			}			
			else if(detectPalm(osPlatform,UAStr,deviceObj,dType)){
				isPlatFormSet=true;
			}
			else if(detectOtherPlatform(osPlatform,UAStr,deviceObj,dType)){
			   // other plat form
				isPlatFormSet=true;
			}
			
			else if(detectGameConsole(osPlatform,UAStr,deviceObj,dType)){
				//game console
				isPlatFormSet=true; 
			}			
		}
		if(!isPlatFormSet)	{
			deviceObj.os.name="Unknown";
		}
	}

/************platform detect functions**************/	
	function detectIOS(osPlatform,UAStr,deviceObj,dType){
		var isIOS=false;
		if(!is('windows',UAStr)){
			if(is('iphone',UAStr)){
				deviceObj.os.name="iPhone ios";
				deviceObj.type	=dType.iPhone;
				isIOS=true;					
			}
			else if(is('ipod',UAStr)){
				deviceObj.os.name="iPod ios";
				deviceObj.type	=dType.iPhone;
				isIOS=true;					
			}
			else if(is('ipad',UAStr)){
				deviceObj.os.name="iPad ios";
				deviceObj.type	=dType.iPad;
				isIOS=true;					
			}
			if(isIOS){		
				//deviceObj.os.version=(testReg(/os\s([\d_]+)/,UAStr) ? RegExp.$1 : "").replace(/_/g, ".");
				deviceObj.os.version = getVersion(/os\s([\d_]+)/,UAStr,1);
				//alert(deviceObj.os.name+" "+deviceObj.os.version);
			}
		}
		return isIOS;	
	}
	
	function detectLinux(osPlatform,UAStr,deviceObj,dType){
		var isLinuxFound=false;
		if (is("unix",osPlatform)||is("x11",UAStr) || is("inux",UAStr)) {
			deviceObj.os.name = "linux";
			isLinuxFound=true;
		}
		return isLinuxFound;			
	}	
	
	function detectAndroid(osPlatform,UAStr,deviceObj,dType){
		var isAndroid=false;
		if (is('android',UAStr)||is('skyfire',UAStr)||is('htc_flyer',UAStr)) {
			//alert("android");
			deviceObj.os.name = "android";
			//deviceObj.os.version=testReg(/android\s([\d\.]+)/,UAStr) ? RegExp.$1 : "";
            deviceObj.os.version = getVersion(/android\s([\d\.]+)/,UAStr,0);
			/*if(!deviceObj.os.version){
				// firefox does not return OS version, neet to get the rv.
				// mozilla/5.0 (android; mobile; rv:32.0) gecko/32.0 firefox/32.0
				var androidRV=getVersion(/rv:([0-9]{1,}[\.0-9]{0,})/,UAStr,0);
			}*/
			isAndroid=true;
		} 
		return isAndroid;			
	}	
	
	function detectChromeOs(osPlatform,UAStr,deviceObj,dType){
		var isChromeOS=false;
		if(is('cros',UAStr)){
			deviceObj.os.name = "Chrome os";
			//deviceObj.os.version = getVersion(/cros\s.*i([\d\.]+)/,UAStr,0);
		}
		return isChromeOS;
	}	
	
	function detectWindows(osPlatform,UAStr,deviceObj,dType,platformCode){
		var isWindows=false;
		if(is('win',UAStr)||is('16bit',UAStr)){
			// add platform condition because chrome emulator changed UAStr
					//alert("set Windows" +" "+osPlatform +" "+ is('win',osPlatform) + is('win',UAStr)+ is('16bit',UAStr));
					deviceObj.os.name="windows";
					deviceObj.os.category.iCode=platformCode.windows;
					if (is("windows nt 10.0",UAStr)) {
						deviceObj.os.version="10.0";
					}	else if (is("windows nt 6.3",UAStr)) {
						deviceObj.os.version="8.1";
					} else if (is("windows nt 6.2",UAStr) || testReg(/\(windows 8\)/,UAStr)) { //windows 8 chrome mac fix
						deviceObj.os.version="8";
					} else if (is("windows nt 6.1",UAStr)) {
						deviceObj.os.version="7";
					} else if (is("windows nt 6.0",UAStr)) {
						deviceObj.os.version="vista";
					} else if (is("windows nt 5.2",UAStr) || is("windows nt 5.1",UAStr) || is("windows xp",UAStr)) {
						deviceObj.os.version="xp";
					} else if (is("windows nt 5.0",UAStr) || is("windows 2000",UAStr)) {
						deviceObj.os.version="2k";
					} else if (is("winnt",UAStr) || is("windows nt",UAStr)) {
						deviceObj.os.version="nt";
					} else if (is("win98",UAStr) || is("windows 98",UAStr)) {
						deviceObj.os.version="98";
					} else if (is("win95",UAStr) || is("windows 95",UAStr)) {
						deviceObj.os.version="95";
					} else if (is("windows phone",UAStr)) {
						//deviceObj.os.version=  getNextWord(UAStr,"windows phone"," ");
						//deviceObj.os.version=testReg(/windows phone\s([\d\.]+)/,UAStr) ? RegExp.$1 : "";	
						deviceObj.os.name="windows phone";
                        deviceObj.os.version =getVersion(/windows phone\s([\d\.]+)/,UAStr,0);
						deviceObj.os.category.iCode=platformCode.windowsphone;
					}else if (testReg(/windows ce|xblwp7|zunewp7|wm5 pie/,UAStr)) {
						deviceObj.os.name="windows phone";
					}else if(testReg(/windows nt [0-9.]+\; arm\;.*(tablet|armbjs)/,UAStr)) {
						// Only the Surface tablets with Windows RT are considered mobile.
						// msdn.microsoft.com/en-us/library/ie/hh920767(v=vs.85).aspx
						deviceObj.os.name="Surface Tablet";
						deviceObj.os.category.iCode=platformCode.windowsTablet;
					}
					
					isWindows=true;						
		}	
		return isWindows;	
	}	
	
	function detectMac(osPlatform,UAStr,deviceObj,dType){
		var isMac=false;
		if (is("macintel",osPlatform) ||is("mac",UAStr) || is("darwin",UAStr)) {
					deviceObj.os.name = "mac os";
					if (is("68k",UAStr) || is("68000",UAStr)) {
						deviceObj.os.version="68k";
					} else if (is("ppc",UAStr) || is("powerpc",UAStr)) {
						deviceObj.os.version="ppc";
					} else if (is("os x",UAStr)) {
						//deviceObj.os.version=(testReg(/os\sx\s([\d_]+)/,UAStr) ? RegExp.$1 : "os x").replace(/_/g, ".");
                        deviceObj.os.version = getVersion(/os\sx\s([\d_]+)/,UAStr,1);
					}
					isMac=true;
		} 	
		return isMac;
	}
	
	function detectEbook(osPlatform,UAStr,deviceObj,dType){
		var isEbook=false;
		if (is("kindle",UAStr)||is("silk",UAStr)) {
			deviceObj.os.name = "kindle";			
            deviceObj.os.version = getVersion(/kindle\/?([\d\.]+)/,UAStr,0);
			isEbook=true;
					
			// docs.aws.amazon.com/silk/latest/developerguide/user-agent.html
			if(is("mobile",UAStr)||is("kindle fire",UAStr)){
				//	kindle fire
                deviceObj.os.version = getVersion(/version\/?([\d\.]+)/,UAStr,0);
				deviceObj.os.category.iCode=99;
				deviceObj.type = dType.oSmartTablet;
				isEbook=true;
			}
			else{
				if(!is("silk",UAStr)){
					// this is the  monochrome Kindles
					var match = /(?:; ([^;)]+) build\/.*)?\bsilk\/([0-9._-]+)\b(.*\bmobile safari\b)?/.exec(UAStr);
					if (match) {
						//("Detected Silk version "+match[2]+" on device "+(match[1] || "Kindle Fire")+" in mode "+(match[3] ? "Mobile" : "Default (desktop)"));
                      deviceObj.os.version = (match[1] || "kindle fire")+" in mode "+(match[3] ? "mobile" : "Default (desktop)")+ " Silk version" +match[2];
					}
					deviceObj.type = dType.genericDevice;					
                }else{
				// silk in kindle fire gen 1
					deviceObj.os.name = "kindle";	
					deviceObj.os.version = "";
					deviceObj.type = dType.oSmartTablet;
					isEbook=true;
				
				}
			}	
		}
		else if(testReg(/nook|nookcolor|nook browser|bnrv200|bnrv200a|bntv250|bntv250a|bntv400|bntv600|logicpd zoom2/,UAStr)){
				deviceObj.type = dType.oSmartTablet;
				deviceObj.os.name = "Nook";
				isEbook=true;
		}	
	    return isEbook;
	}	
	
	function detectPalm(osPlatform,UAStr,deviceObj,dType){
		var isPalm=false;
		if (is("blazer",UAStr)||is("palm",UAStr)) {
			deviceObj.os.name = "Palm";
			isPalm=true;
		}
		return isPalm;			
	}
	
	function detectOtherPlatform(osPlatform,UAStr,deviceObj,dType){
		var isOtherPlatFrom=false;
		if (is("sunos",UAStr)) {
			deviceObj.os.name = "sun";
			isOtherPlatFrom=true;		
		} 
		else if (is("mib",UAStr)) {
			deviceObj.os.name = "Motorola";
			isOtherPlatFrom=true;
		} 
		else if (is("aix",UAStr)) {
			deviceObj.os.name = "aix";// IBM
			isOtherPlatFrom=true;
		} 		
		else if (is("irix",UAStr)) {
			deviceObj.os.name = "irix";
			isOtherPlatFrom=true;
		} 
		else if (is("freebsd",UAStr)) {
			deviceObj.os.name = "freebsd";
			isOtherPlatFrom=true;
		} 
		else if (is("bsd",UAStr)) {
			deviceObj.os.name = "bsd";
			isOtherPlatFrom=true;
		}
		else if (is("bada",UAStr)) {
			deviceObj.os.name = "Bada";
			isOtherPlatFrom=true;
		}	
		return isOtherPlatFrom;				
	}	
	
	function detectNokia(osPlatform,UAStr,deviceObj,dType){
		var isNokia=false;
		if(testReg(/nokia|symbian|series60|series40|\bs60\b/,UAStr)){
			isNokia=true;
			deviceObj.type = dType.genericPhone;
			deviceObj.os.name = "Nokia";
		}
		else if(testReg(/symbos|series70|series80|series90|doris|gobrowser|syb-[0-9]+|maemo/,UAStr)){
			isNokia=true;
			deviceObj.os.name = "Nokia";			
		}	
		return isNokia;	
	}	
	
	function detectBlackberry(osPlatform,UAStr,deviceObj,dType){
		var isBlackBerry=false;
		if(testReg(/\bbb10\b|blackberry|vnd.rim|rim[0-9]+/,UAStr)){
			//deviceObj.type = dType.oSmartPhone;
			deviceObj.os.name = "Blackberry";			
			isBlackBerry=true;
		}	
		else if(testReg(/playbook|rimstablet/,UAStr)){
			deviceObj.type = dType.oSmartTablet;
			deviceObj.os.name = "Blackberry";			
			isBlackBerry=true;
		}			
		return isBlackBerry;	
	}
	
	
	
	function detectTV(osPlatform,UAStr,deviceObj,dType){
		var isWebTV=false;
		if (testReg(/googletv|webtv|tv|smarttv|internet.tv|netcast|nettv|appletv|boxee|kylo|roku|dlnadoc|ce\-html/,UAStr)) {
			deviceObj.os.name = "web TV";
            deviceObj.os.version = ""
			isWebTV=true;
		}
		return isWebTV;		
	}

   function detectGameConsole(osPlatform,UAStr,deviceObj,dType){
		var isGameConsole=false;
		if (testReg(/xbox|playstation.3|wii|playstation|nintendo|nintendo wiiu|nintendo 3ds|nitro|bunjalloo|\bpsp\b/,UAStr)) {
			deviceObj.os.name = "game console";
			isGameConsole=true;
		}
		return isGameConsole;		
	}
   /************detect browser***********************/ 
 	function get_browser(deviceObj,dType,sPlatform,UAStr){
		var isBrowserSet=false;
	   if(deviceObj.os.category.isWindows){
			var checkIE=getInternetExplorerVersion(sPlatform,UAStr,deviceObj,dType);
			if(checkIE[0]){
				isBrowserSet=true;
			}
		}
		if(!isBrowserSet){
			var checkSilk=getSilkVersion(sPlatform,UAStr,deviceObj,dType);
			if(checkSilk){
				isBrowserSet=true;					
			}
		}
		if(!isBrowserSet){
			var checkOpera=getOperaVersion(sPlatform,UAStr,deviceObj,dType);
			if(checkOpera){
				isBrowserSet=true;					
			}
		}
		if(!isBrowserSet){
			var checkFirefox=getFFVersion(sPlatform,UAStr,deviceObj,dType);
			if(checkFirefox){
				isBrowserSet=true;	
			}
			
		}
		if(!isBrowserSet){
			var checkchrome=getChromeVersion(sPlatform,UAStr,deviceObj,dType);
			if(checkchrome){
				isBrowserSet=true;	
			}			
		}		
		if(!isBrowserSet){
			if(deviceObj.os.category.isElectronicbook){
				deviceObj.browserBuild.version="";
				deviceObj.browserBuild.name='E-Book browser';	
				isBrowserSet=true;
			}
		}
		
		if(!isBrowserSet){
			var checkSafari=getSafariVersion(sPlatform,UAStr,deviceObj,dType);
			if(checkSafari){
				isBrowserSet=true;	
			}			
		}			
		if(!isBrowserSet){
			var checkOtherBrowser=getOtherBrowser(sPlatform,UAStr,deviceObj,dType);
			if(checkOtherBrowser){
				isBrowserSet=true;	
			}
			
		}		

		if(!isBrowserSet){
			deviceObj.browserBuild.name="unknown"
		}		
	}  		
	
	
	function getInternetExplorerVersion(sPlatform,UAStr,deviceObj,dType){
		var rv = -1,crv=-1;		
		var IEInfo=[];
		IEInfo[0]=false;
		var IEMatch1=getVersion(/msie\s([\d\.]+)/,UAStr,0);	
		var IEMatch2=getVersion(/trident\/?([\d\.]+)/,UAStr,0);	
		var IE11Match=getVersion(/trident\/.*rv:([0-9]{1,}[\.0-9]{0,})/,UAStr,0);

		if (IEMatch1!=null){
			IEInfo[0]=true;
			rv = parseFloat(IEMatch1);
			IEInfo[1]=rv;
			if(IEMatch2!=null){
				crv= parseFloat(IEMatch2);
			}
			if(rv<8&&crv>=4){
				deviceObj.compView=1;
				// recode IE version---[changed on 12/8]
				if(crv==4){
					IEInfo[1]=8;
				}
				else if(crv==5){
					IEInfo[1]=9;
				}
				else if(crv==6){
					IEInfo[1]=10;
				}
				else if(crv==7){
					IEInfo[1]=11;
				}
				else if(crv>7){
					IEInfo[1]=11+'+';
				}
			}
			else{
				/*if(is("compatible",UAStr)){
					deviceObj.compView=1;
				}*/
				
			}

		}
		else if (IE11Match!=null){
			IEInfo[0]=true;
			rv = parseFloat(IE11Match);
			IEInfo[1]=rv;
		}
		if(IEInfo[0]){
			deviceObj.browserBuild.name='IE';
			if(rv>=0){
				deviceObj.browserBuild.version=''+IEInfo[1];
			}
			else{
				deviceObj.browserBuild.version='unknown';
			 }
			if(deviceObj.compView>0){
				deviceObj.browserBuild.version+=' compatible';
			}
		}
		return IEInfo;
	 }			
		
	 function getOperaVersion(sPlatform,UAStr,deviceObj,dType){
		 var isOpera=false;
		 deviceObj.browserBuild.version=getVersion(/opera.*mobi.*version\/?([\d\.]+)/,UAStr,0);
		 if(deviceObj.browserBuild.version!=null){
				isOpera=true;
				deviceObj.browserBuild.name='Opera mobile';			 
		 }
		 if(!isOpera){
			  deviceObj.browserBuild.version=getVersion(/opera.*mini\/?([\d\.]+)/,UAStr,0);
			   if(deviceObj.browserBuild.version!=null){
					isOpera=true;
					deviceObj.browserBuild.name='Opera mini';					   
			   }
		 }
		 if(!isOpera){
			  deviceObj.browserBuild.version=getVersion(/coast\/?([\d\.]+)/,UAStr,0);
			   if(deviceObj.browserBuild.version!=null){
					isOpera=true;
					deviceObj.browserBuild.name='Opera coast';					   
			   }
		 }		 
		 if(!isOpera){
			  deviceObj.browserBuild.version=getVersion(/opr\/?([\d\.]+)/,UAStr,0);
			   if(deviceObj.browserBuild.version!=null){
					isOpera=true;
					deviceObj.browserBuild.name='Opera';					   
			   }
		 }
		 if(!isOpera){
			  deviceObj.browserBuild.version=getVersion(/opera\/?([\d\.]+)/,UAStr,0);
			   if(deviceObj.browserBuild.version!=null){
					isOpera=true;
					deviceObj.browserBuild.name='Opera';					   
			   }
		 }	
		 return isOpera;	 	
	 }
	
	 
