	 function getSafariVersion(sPlatform,UAStr,deviceObj,dType){
		 var isSafari=false;
		 deviceObj.browserBuild.version=getVersion(/version\/?([\d\.]+)/,UAStr,0);
		/* if(is('win',osPlatform)){
		    deviceObj.browserBuild.version=getVersion(/version\/?([\d\.]+)/,UAStr,0);
		 }else{
			deviceObj.browserBuild.version=getVersion(/safari\/?([\d\.]+)/,UAStr,0);
		 }*/
		 if(deviceObj.browserBuild.version!=null){
			  isSafari=true;
			  deviceObj.browserBuild.name='Safari';	
		 }
		if(deviceObj.os.category.isAndroid){
			deviceObj.browserBuild.name='android default safari-based';	
			deviceObj.browserBuild.version="unknown";		
		}	 		 
		 return isSafari;		 
	 } 
	 
	 function getOtherBrowser(sPlatform,UAStr,deviceObj,dType){
		 var isOtherBrowser=false;
		 deviceObj.browserBuild.version=getVersion(/dolfin\/?([\d\.]+)/,UAStr,0);
		 if(deviceObj.browserBuild.version!=null){
				isOtherBrowser=true;
				deviceObj.browserBuild.name='Dolfin';			 	
		 }
		 if(!isOtherBrowser){
			  deviceObj.browserBuild.version=getVersion(/bolt\/?([\d\.]+)/,UAStr,0);
			   if(deviceObj.browserBuild.version!=null){
					isOtherBrowser=true;
					deviceObj.browserBuild.name='Bolt';					   
			   }
		 }	
		 if(!isOtherBrowser){
			  deviceObj.browserBuild.version=getVersion(/baidubrowser\/?([\d\.]+)/,UAStr,0);
			   if(deviceObj.browserBuild.version!=null){
					isOtherBrowser=true;
					deviceObj.browserBuild.name='Baidu Browser';					   
			   }
		 }	
		 return isOtherBrowser; 		 
	 }		 
	 
		
		
    /************* helper functions*****************/
		
	// simplified and localized indexOf method 
	function is(key,searchStr) {
		return searchStr.indexOf(key) > -1;
	}
	// localized string trim method
	function trim(value) {
		return value.replace(/^\s+|\s+$/g, "");
	}
	
	
	function setfullString(osObj){
		if(osObj.version==''||osObj.version==null){
		 	return osObj.name;	
		}
		else{
			return osObj.name+' '+osObj.version;
		}
	}
	
	function testReg(regex,searchStr) {
		return regex.test(searchStr);
	}
	function getNextWord(txt,searchStr,splitor){
		var n = txt.lastIndexOf(searchStr);
		var word=txt.substring(n+1).split(splitor)[0]
		return word;
	}
  
  	function getVersion(regex, UAStr, spliterType){
		var version = null;
		var aVersion = regex.exec(UAStr);
		//alert(aVersion);
		if(aVersion!=null){
			if(spliterType==0)
				version = aVersion[1].toString();
			else if(spliterType==1)				
				//version = aVersion[1].toString().replace(/_/g, ".");
                //getVersion(/android\s([\d\.]+)/,UAStr,/_/g, ".");
                //version = aVersion[1].toString().replace(subStrReplace, newSubStrReplace);
				version = aVersion[1].toString().replace(/_/g, ".");
		}
		return version;
	}  
