	function setHistoryData(qid,newValue,splitor){
		var q=f(qid);
		var theNewValue="";
		if (q.toBoolean()) {
			var currentValue=q.get();
			theNewValue=currentValue.toString()+splitor+newValue.toString();
		}
		else{
			theNewValue=''+newValue.toString();			
		}
		q.set(theNewValue);
	}
	
