function QSprobCheck() {
    var probQSblocksPerm = survey_setting()["QSblockCodesAlways"];
    var probQSblocksAdhoc = survey_setting()["QSblockCodesAdhoc"];
    var foundBlockedCode = false;
    var qnSS = f("sampsource");
    var i = 0;
    var codeToBlock = '';

    if(qnSS.toBoolean()) {
        var ss = qnSS.value();

        for (i = 0; i < probQSblocksPerm.length; i++) {
            codeToBlock = probQSblocksPerm[i];

            if (codeToBlock == ss) {
                foundBlockedCode = true;
            }
        }

        for (i = 0; i < probQSblocksAdhoc.length; i++) {
            codeToBlock = probQSblocksAdhoc[i];

            if (codeToBlock == ss) {
                foundBlockedCode = true;
            }
        }
    }

    return foundBlockedCode;
}

