function getExplainText(opt) {
  var i: int = 0;
  var txt: String = "";
  var qTypes = getQuestionTypes();
  var qTypesArr = new Array("SINGLE", "MULTI", "GRID", "OPEN", "RANKING/OPENTEXTLIST", "NUMERICLIST", "NUMERIC");
  var optDNRcodes = new Array("11", "12", "13", "4", "4", "5", "5");
  var optRDLcodes = new Array("1", "2", "3", "4", "4", "5", "5");
  var optRDNcodes = new Array("14", "15", "16", "4", "4", "5", "5");
  var useArr = new Array("23", "24", "25", "26", "26", "27", "27");

  if (opt == "DNR") { useArr = optDNRcodes; }
  else if (opt == "RDL") { useArr = optRDLcodes; }
  else if (opt == "RDN") { useArr = optRDNcodes; }

  for (i = 0; i < qTypesArr.length; i++) {
    var eachType = qTypesArr[i];
    var code = useArr[i];

    if (eachType == qTypes) {
      txt = f('xMESSAGES')[code].label();
    }
  }

  return txt;
}

