function dvlp_echo(msg, color) 
{
	if(!GetDeviceInfo().IsMobile && !IsSms())
    {
      	var qn = f('recordType');
      	var qnEcho = f('dvlp_echos');
      
      	if(qn.toBoolean())
        {
            if(qn.any('test')) 
            {
	            color = typeof color != 'undefined' && color != null ? color : '#f00';  
                var displayThis = "<div class='dvlp_echo' style='color:"+color+";'>"+msg+"</div>";
              	var txt = "";
              
              	if(qnEcho.toBoolean())
                {
                  	txt = qnEcho.get();
                }
              	else
                {
                  	txt = "<div class='dvlp_echo'>RespID: "+CurrentID()+"</div>";
                }
              
              	txt += displayThis;
              	
              	qnEcho.set(txt);
            }
        }
  	}
}

