function getQIDLinks(arrQIDS: String[])
{
	var txt : String = "";

	if(!isNodeWithoutID())
	{
		var excludeQIDs = ['tstemail','xRVIDCompleted','CngTelNum','CngDialTelNum','Verify_TelNum','StartLinked','TypeUniqKey','Dial_Outcome','xRecordOptOut','termination','CAWIEmailAddress','apptyp','l','MakeComments','Comments','contact_person','Money','MoneyRF','MoneyConfirm','themeColours','numCommaDisplay','HLP_Lang','TR1','TR2captchaImagesShow','TR2captchaCorrectGroup','TR2captchaQn','TR2','TR3toShow','TR3toSelect','TR3qn','TR3','TR3firstAttempt','TR4showPC','TR4correctVal','TR4qn','TR4','eg1Q1','eg1Q1b','eg2Q1','eg2Q1b','eg3Q1mobile','eg3Q1','eg4Q1','eg4Q1clickOrder','eg6Q1','eg7Q1','zipCode','zipCodeb','zipCodeState2','zipCode2','zipCode2b','eg5Q1','eg8usState','eg8usStateRegion','eg9Q1','eg10Q1','eg11','hECKmoneyName','hECKmoneyAddress','hECKmoneyState','hECKmoneyZip','hECKmoneyContact','hECKnoMoney','COMMENT2','ccpaQn'];
		//dvlp_echo("arrQIDS.length" + arrQIDS.length,'blue');

		for(var i=0; i<arrQIDS.length; i++)
		{
			var qID = arrQIDS[i];
			var processQIDlink : Boolean = true;
		
			for(var j=0; j<excludeQIDs.length; j++)
			{
				var excludeQID = excludeQIDs[j];
			
				if(qID==excludeQID)
				{
					processQIDlink = false; // qID matches, so exclude from output
				}
			}
		
			if(processQIDlink)
			{
				var urlHREF = GetRespondentUrl(qID);
				txt += "<a href='"+urlHREF+"'>"+qID+"</a> ";
			}
		}
	}
	
	return txt;
}

