function showLanguageLinks()
{
  	var txt = "";
  	var showlinks = survey_setting()['ShowLanguageLinks'];
  	var hideLinksForOP : Boolean = true;
  
    if (f("sampsource").any('2') || IsCati())
    {
		hideLinksForOP = false;
    }
  
  	if(hideLinksForOP)
    {
        if(showlinks.ToLower() == 'yes')
        {
            // Only show language links if survey_setting has ShowLanguageLinks set to true
            var qnLang = f("l");
            var availableLanguageCodes = qnLang.domainValues(); // gets the language codes used in this survey
            var availableLanguageLabels = qnLang.domainLabels(); // gets the language codes used in this survey
            var numberOfLanguagesAvailable = availableLanguageCodes.length;
            var qid = CurrentForm();
          
            if(!isNodeWithoutID())
            {
                var currentQnURL = GetRespondentUrl(qid,false); // default is Web URL
                
                if(qnLang.toBoolean())
                {
                    // Always show once logged in... andcan be hidden in the event f("l").set(null) is used, should the goToBlock (switch language) be used
                    if(IsCati())
                    {
                        currentQnURL = GetCatiRespondentUrl(qid,false);
                    }
                  
                    if(numberOfLanguagesAvailable>1)
                    {
                        // Only create language links bottom of page if the survey is has more than one language (see Reusable List called "Survey languages")
                        txt += "<style>";
                        txt += "#langLinkArea {font-size:75%; margin-left:auto; margin-right:auto; text-align:center;}";
                        txt += "#langLinkArea a {margin-left:4px; margin-right:4px; border:none; color:rgba(48, 48, 48, 0.65); text-decoration:underline; font-weight:normal;}";
                        txt += "#langLinkArea a:hover {color:rgba(2, 161, 226, 0.5); text-decoration:none; font-weight:normal;opacity: 1;}";
                        txt += "</style>";
                        txt += "<div id='langLinkArea'>";
                 
                        for(var i=0; i<numberOfLanguagesAvailable; i++)
                        {
                            var langCode = availableLanguageCodes[i];
                            var langLabel = availableLanguageLabels[i];
                            currentQnURL += "&l="+langCode;
                            txt += "<a href='"+currentQnURL+"'>"+langLabel+"</a>";
                        }
                      
                        txt += "</div>";
                    }
                }
            }
        }
    }
  
  	return txt;
}

