function mustAnswer(qid) {
    if (qid) {
        // Do nothing
    }
    else {
        var qid = CurrentForm()
    } 

	var WebBlankValue = survey_setting()['WebBlankValue'];
	var precodeArr;
	var currentPrecode;
	var currentValue;
	var i;


	switch (qid) {
		//Enter any grids from program here that need to be backcoded as web blanks
		case 'yourQID':

			var codes = f(qid).domainValues();
			for (i = 0; i < codes.length; i++) {
				currentPrecode = codes[i].toString();
				if (!f(qid)[currentPrecode].toBoolean()) {
					RaiseError();
					SetQuestionErrorMessage(CurrentLang(), GetCustomText(42));
				}
			}
			dvlp_echo(qid + ' = ' + f(qid).values(), 'green');
			break;

	}

	//EVALUATE SINGLES  
	if (getQuestionTypes() == 'SINGLE' || getQuestionTypes() == 'OPEN') {      	//qid.indexOf(GetQIDs('single')) == -1
		if (!f(qid).toBoolean()) {
			RaiseError();
			SetQuestionErrorMessage(CurrentLang(), GetCustomText(42));
		}
	}
	else if (f(qid).getType() == 'COMPOUND') {

		if (!f(qid).toBoolean()) {
			RaiseError();
			SetQuestionErrorMessage(CurrentLang(), GetCustomText(42));
		}
	}
}

