function standardMask(qid)
{
  	// qid must be manually entered to prevent issues when question is later piped or linked by Answer mask in a following question
  	// i.e. Q41 showing Q40 answers: if Q40 used CurrentForm() then when Q41 shows Q40 answers it will re-run the mask on Q40 but pass Q41 through instead.
    // please always enter the qid when using standardMask() to avoid complications i.e. standardMask('Q40')
	var s = new Set();

  	if(IsCati())
    {
		s =  a(qid);
    }
  	else
    {
		s = a(qid).diff(set(maxCode(qid)));
    }

  	return s;
}

function softErrorQIDcheck(qid)
{
    var qnSoftErrTracker = f("xQIDsAttemptedSkipAtLeastOnce");
    var qidNotFound : Boolean = true;
    var checkQIDsStr : String = "";

    if (qnSoftErrTracker.toBoolean())
    {
        checkQIDsStr = qnSoftErrTracker.get();
    }

    var checkQIDsArr = checkQIDsStr.split(",");

    for (var i = 0; i < checkQIDsArr.length; i++) {
        var checkQID = checkQIDsArr[i];

        if (checkQID == qid) {
            qidNotFound = false;
        }
    }

    // If QID found in ExemptQuestions list, do not track
    if (ExemptQuestions()) { 
        qidNotFound = false;
    }

    if(qidNotFound)
    {
        // Add QID now so soft error won't show again
        qnSoftErrTracker.set(checkQIDsStr+","+qid); 
    }

    return qidNotFound;
}

function webBlank1QnNum(qid)
