    var errMsg = GetCustomText(234);
    var wbCode = survey_setting()['WebBlankValue'];
    dvlp_echo("wb code from webblank function: " + wbCode, "blue");

    if(!qn.toBoolean())
    {
        var qidNotFound : Boolean = softErrorQIDcheck(qid)

        if(qidNotFound)
        {
            RaiseError();
            SetQuestionErrorMessage(CurrentLang(),errMsg);
        }
        else
        {
            qn.set(wbCode); // Just set Refused
        }
    }
}

