        h3strikes[2].set(scount2);

        if(qidNotFound)
        {
            RaiseError();
            SetQuestionErrorMessage(CurrentLang(),errMsg);
        }
        else
        {
            qn.set(wbCode); // Just set Refused
        }
    }
}

