        var qidNotFound : Boolean = softErrorQIDcheck(qid);

        //increment outs for threestrikes
        var h3strikes = f('h3strikes');
        if (!h3strikes[2].toBoolean()) {
            h3strikes[2].set(0)
        }

        var OUTS = h3strikes[2].toNumber()
        var scount2 = (OUTS + 1);
        h3strikes[2].set(scount2);

        if(qidNotFound)
        {
            RaiseError();
            SetQuestionErrorMessage(CurrentLang(),errMsg);
        }
        else
        {
            qn2.set(wbCode); // Just set Refused
        }
    }
}

