function setStateRegion(qid)
{
    var qn1 = f(qid);
    var qn2 = f(qid + "Region");
    var region = "";

    if (qn1.toBoolean()) 
    {
        var stateCode = qn1.get();
        var stateArr = new Array("AL", "AK", "AZ", "AR", "CA", "CO", "CT", "DE", "DC", "FL", "GA", "HI", "ID", "IL", "IN", "IA", "KS", "KY", "LA", "ME", "MD", "MA", "MI", "MN", "MS", "MO", "MT", "NE", "NV", "NH", "NJ", "NM", "NY", "NC", "ND", "OH", "OK", "OR", "PA", "RI", "SC", "SD", "TN", "TX", "UT", "VT", "VA", "WA", "WV", "WI", "WY", "MH");
        var regionArr = new Array("3", "4", "4", "3", "4", "4", "1", "3", "3", "3", "3", "4", "4", "2", "2", "2", "2", "3", "3", "1", "3", "1", "2", "2", "3", "2", "4", "2", "4", "1", "1", "4", "1", "3", "2", "2", "3", "4", "1", "1", "3", "2", "3", "3", "4", "1", "3", "4", "3", "2", "4", "4");

        for (var i=0; i<stateArr.length; i++) 
        {
            var code = stateArr[i];
            var regionCode = regionArr[i];

            if (code == stateCode) 
            {
                region = regionCode;
            }
        }

        if(region!="")
        {
            qn2.set(region); // Set only if match found
        }
    }
}

function translateToEnglish(qIDfrom,qIDto)
{
  	var curLangID = CurrentLang();
  	var qnOrig = f(qIDfrom);
	var qn2EN = f(qIDto);

	if(qnOrig.toBoolean())
	{
  		var getTxt = qnOrig.get();
  		var translatedTxt = "";
  
  		if(curLangID==9)
    	{
      		translatedTxt = getTxt; // Already English, set anyway
    	}
  		else
    	{
			translatedTxt = MicrosoftTranslateText(getTxt,curLangID,9); // Any language to English
    	}
  
  		qn2EN.set(translatedTxt);	
	}
}

