function setAllEndOfSurveyInfo(secondsForAutoNext)
{
  	SetxTIMES(); // Set survey end date/time stamps and time differences.
  	setRespondentStatus(); // Set RespondentStatus with same as Stop node Extended status
    setInterviewEndStamp(); // interviewEnd variable should replace interview_end in the data Template for the export
    var redirectURL = "";
      
    if(!f('SurveyEndDate').toBoolean())
    {
        storeCurrentDate('SurveyEndDate');
    }
    
    if(!IsInRdgMode())
    {
        var LOI_SEC = f('hid_LOI').toNumber()
        var SRVY_LOI_SEC = f('xMinSrvyLoi').toNumber()

    
        //if(LOI_SEC<SRVY_LOI_SEC)
        if((LOI_SEC<420 && f('WATCHING1').any('1','2')) || (LOI_SEC<240 && f('WATCHING1').any('3','4','5')))
        {
            f('xSpeeder').set('1');
        }
        
        if(IsWeb())
        {
            if(f('sampsource').toBoolean())
            {
                
                var ss = f('sampsource').get();
                var surveyStatus = GetStatus();
              
                if(surveyStatus=="quotafull")
                {
                    f('xQfUrl').set(ss); // Set Quotafull Redirect variable to same as sampsource
                    redirectURL = f('xQfUrl').valueLabel();
                }
                else if(surveyStatus=="screened" || surveyStatus=="error")
                {
                    f('xTermUrl').set(ss); // Set Screened Redirect variable to same as sampsource
                    redirectURL = f('xTermUrl').valueLabel();
                }
                else if(surveyStatus=="complete")
                {
                    CompRate();  //run response rate on any complete
                    f('xCompUrl').set(ss); // Set Complete Redirect variable to same as sampsource
                    redirectURL = f('xCompUrl').valueLabel();
                    f("completeFlag").set('fully');
                }
              
                if ( IsPanel() && f('MONEYW').any('1') && f('ViApiUrlReg').toBoolean() ){
                	redirectURL = f('ViApiUrlReg').get();
                }

    			redirectURL = redirectURL.Trim();
                if (f('sampsource').any('3')) { 
                   redirectURL = signLink(redirectURL);
                }              
                f("endLinkUsed").set(redirectURL);
            }
        }
    }
  	
    var txt = ""
    if (!IsCati() && !IsInRdgMode() && !IsSms())
    {
            txt     = "<style>.finishlater {display:none;}</style>"; // return empty string for piping out nothing reason
  		var qnSS    = f("sampsource");
  		var seconds = 600; // 600 seconds is 10 minutes for CATI
      
        if(secondsForAutoNext==undefined)
    	{
			seconds = 5; // 5 seconds = default time for a Web Survey responder that is not a Panel Provider
    	}
      	else 
        {
          	seconds = secondsForAutoNext; // use whatever value is piped through the Stop Node function
        }
      
		if(qnSS.toNumber()<=1)
        {
        	seconds = 10; // 10 seconds = default time for a Web Survey responder that is not an external Panel Provider
        }
        //vendors
        else if (qnSS.any('3', '4','12'))
        {
           	seconds = 0; // Is definitely Ipsos or Dynata i.e. a Panel provider, so autonext as fast as possible
        }
      
        seconds = seconds*1000 //convert seconds to milliseconds
          
        if(redirectURL.length>0)
        {
          	txt += "<style>.cf-navigation__button {display:none;}</style>"; // Hide the final page navigation button
            txt += "<script>";
            txt += "setTimeout(function(){window.location.href = '"+redirectURL+"';},"+seconds+");";
            txt += "</script>";
        }
    }

  	return txt;
}

function setRespondentStatus(extendedStatusCode)
{
	if(extendedStatusCode==undefined)
	{
		var GEScode = GetExtendedStatus();
		f('RespondentStatus').set(GEScode);
	}
	else
	{
		f('RespondentStatus').set(extendedStatusCode);
		// Like not a stop node, so set the typical stop node items too
		SetExtendedStatus(extendedStatusCode);
		SetInterviewEnd();
		// status is likely a No Change situation, if the Status is needed please write a new script where you need it to be set i.e. SetStatus("complete");
	}

	//updated respondent value with current status
	SetRespondentValue("RespondentStatus", f('RespondentStatus').get());

	if (IsCati()) 
	{
		StopRecording();
		dvlp_echo("setDispoStatus SetExtendedStatus(Dispo) = "+GetExtendedStatus(),'Red');
	}

	if(f("recordType").any('live'))
	{
  		UpDatePanelHistory();
	}
  
	return "";
}

