//var qid = "qnMultiGrid";
//var strlin = "straightLine";


function straithLineMultGrid(qid, strlin) {

var qnSL = f(strlin);
var allQIDs = Get3DGridQuestionIds(qid);
var firstQnAnsStructure = '';
var countAll = 0;
var countSame = 0;

for(var i=0; i<allQIDs.length; i++)
{
    var eachQID = allQIDs[i].toString();
    var eachQn = f(eachQID);
    
    if (eachQn.size()>0)
    {
        countAll++; // Add 1 to the overall answered counter

        var allAnsweredCodes = eachQn.categories();
        var allAnsweredCodesStr = allAnsweredCodes.toString();
        
        if (firstQnAnsStructure == '')
        {
            firstQnAnsStructure = allAnsweredCodesStr; // Set first hit
            countSame++; // Add 1 to the first ever so same is able to keep up with countAll
        }
        else
        {
            // check if first answer matches all next answers
            if (allAnsweredCodesStr == firstQnAnsStructure)
            {
                countSame++; // Add 1 to the next items that match
            }
        }
    }
}

if(countAll==countSame)
{
    qnSL.set("fail");
}
else
{
    qnSL.set("pass");
}

}

