function AutoCloseSurvey() {
	var str = "";
	
	if(!IsCati())
	{
		var url = CloseSurveyNoLink();
		var seconds = parseInt(survey_setting()['WebPageTimeLimit']);
		var milliSeconds = seconds * 1000;

		str += "<script>\n";
