function getQuestionTypes(){
	try{
    var qid = CurrentForm()
		var type = f(qid).getType();
		//dvlp_echo("f(qid).getType() = "+type,'blue');
		var ret=type;
		switch(type){
			case 'CODED'			 : ret='SINGLE';	break;
			case 'COMPOUND' 		 :
				var codes =	f(qid).domainValues();
				var innerType=f(qid)[codes[0]].getType();
				switch(innerType) {
					case 'DICHOTOMY' : ret='MULTI'; break;
					case 'CODED'	 : ret='GRID'; break;
					case 'OPEN'		 : ret='RANKING/OPENTEXTLIST'; break;
					case 'NUMERIC' : ret='NUMERICLIST'; break;
				} 
				break;
			case 'OPEN' : ret='OPEN';	break;
			case 'NUMERIC' : ret='NUMERIC';	break;
			case '3DGrid' :
				var l3dgrid = Get3DGridQuestionIds(qid)
				for(var i=0,isMultGrid=true;i<l3dgrid.length;i++) {
					if(f(l3dgrid[i]).getType()!="COMPOUND") 										{isMultGrid=false; break;}
					else if(f(l3dgrid[i])[f(l3dgrid[i]).domainValues()[0]].getType()!="DICHOTOMY")  {isMultGrid=false; break;}
				}
				if(isMultGrid) ret='MULTIGRID'
				break;
			case ''	: ret = 'INFO'; break;
		}
		
	}catch(err){
		ret = 'INFO';
	}
	//dvlp_echo("return = "+ret,'blue');
	return ret; 
}

function qclear(qid) {
  var dataform = f(qid);
  var question_type = dataform.COMPOUND?"MULTI":"SINGLE";

  if(question_type=="MULTI") {
	  var precodes = dataform.categories();
	  for ( var ii=0; ii<precodes.length; ii++ )
		dataform[precodes[ii]].set(null);
  }
  else
  	dataform.set(null);
}

//Input "[1,2,3,4,5]" (no quotes)
//Returns "1,2,3,4,5" (no quotes)

function arrayToSet(arrValues) {
  //dvlp_echo('arrValues = ' + arrValues,'red');
  var setCodes = new Set();
  for(var i=0;i<arrValues.length;i++)
    setCodes.add(arrValues[i]);
    //dvlp_echo('setCodes = ' + setCodes,'orange');
    return setCodes;
}

// This validation checks a 5-digit zip code. 
// The zip code must be numeric, all whole numbers, 
// with no spaces or punctuation. 
// If a multi-open used, remember that qZipID should have 
// an underscore in it with the precode (e.g. 'Q1_1'). 

function checkZipCode(qZipID) {
	var zipCode = f(qZipID);
	var zipCodeStr = zipCode.toString().Trim();
    
  	var LookUpDB = survey_setting()['Zip2022Database'];
   	var LookUpTB = survey_setting()['Zip2022Table'];		
     
    var ParseVar = parseInt(f(qZipID),10);
    dvlp_echo('var ParseVar = ' + ParseVar ,'red');
  
    var IsValidZip =  GetDBColumnValue(LookUpDB,LookUpTB,ParseVar,'ZIPCode',9)           
    dvlp_echo("ValidZip = "+ IsValidZip, "green");
        
	if (!IsNumeric(zipCode) || zipCodeStr.length != 5){
		RaiseError();
        SetQuestionErrorMessage(LangIDs.en, "Please enter valid 5 digit zip code.");
		SetErrorMessage(LangIDs.en, "Please enter valid 5 digit zip code.");	
		SetErrorMessage(LangIDs.es, "Please enter valid 5 digit zip code.");
	}  
  	else if (!IsValidZip){
		RaiseError();
        SetQuestionErrorMessage(LangIDs.en, "This doesn't appear to be a valid zip code.");
		SetErrorMessage(LangIDs.en, "This doesn't appear to be a valid zip code.");	
		SetErrorMessage(LangIDs.es, "This doesn't appear to be a valid zip code.");	
	} 
  	else {
      return true;
    }
}

