// Will return date after offsetting timezone from CENTRAL server
// Usage: f("DATE").set(OurDate(+1));

function OurDate()
{
   var offset = 1 //(Eastern as server is Central)
   var MinMilli = 1000 * 60         //Initialize variables.
   var HrMilli = MinMilli * 60
   var d = new Date();                  //Create Date object.
   var t1 = d.getTime();                //Get current time.
   var t2 = t1 + (HrMilli * offset );   //Adjust for Different timezones
   var server_time = new Date(t1);
   var local_time = new Date(t2);
   var loc_month = local_time.getMonth() + 1;
   var loc_year = local_time.getFullYear();  
   var loc_day = local_time.getDate();
   var loc_date = (loc_year * 10000) + (loc_month * 100 ) + ( loc_day * 1 )
   return(loc_date);   
}

// Will return time after offsetting timezone from server
// Usage: f("TIME").set(Ourtime(+5));

function OurTime(offset)
{
   var offset = 1 //(Eastern as server is Central)
   var MinMilli = 1000 * 60;         
   var HrMilli = MinMilli * 60;
   var d = new Date();                  
   var t1 = d.getTime();                
   var t2 = t1 + (HrMilli * offset);
   var server_time = new Date(t1);
   var local_time = new Date(t2);
   var loc_hour = local_time.getHours();
   var loc_mins = local_time.getMinutes();
   var loc_secs = local_time.getSeconds();

   if ( loc_mins < 10 )
   { loc_mins = "0" + loc_mins; }

   if ( loc_secs < 10 )
   { loc_secs = "0" + loc_secs; }

// change format for hours
   if ( loc_hour >= -5 && loc_hour <= 0 )
   { loc_hour += 24; }

   var loc_time = loc_hour +":"+ loc_mins +":"+ loc_secs;
   return(loc_time);   
}

/**
 *  HelperFunctions JScript for Confirmit Surveys
 *		
 *
 *	Version history:
 *		- 1.2.1
 *		- 1.2.2			comment out newtonsoft call
 *		- 1.2.3			add proper doc/comments
 */


/**
 * JSON object parser/stringify/toQueryString/escape
 */

function JSON() {
	return {
		parseXML: function( xmlStr ) {
			return xmlToJson( xmlStrToXmlDoc( xmlStr ) );
		},
		parse : function (str) {
			var _json;
			try {
				eval("_json = " + str + ";");
			} catch (e) {
				_json = {};
			}
			return _json;
		},
		stringify : function (obj, isHashtable) {
			var t = typeof(obj);
			var _return;
			isHashtable = isHashtable || false;
			if(!isHashtable) {
				if (t != "object" || obj === null) {
					// simple data type
					if (t == "string")
						obj = '"' + obj + '"';
					_return = String(obj);
				} else {
					// recurse array or object
					var n,
						v,
						json = [],
						arr = (obj && obj.constructor == Array);
					
					for (n in obj) {
						v = obj[n];
						t = typeof(v);
						if (t == "string")
							v = '"' + this.escape(v) + '"';
						else if (t == "object" && v !== null)
							v = this.stringify(v);
						json.push((arr ? "" : '"' + n + '":') + String(v));
					}
					_return = (arr ? "[" : "{") + String(json) + (arr ? "]" : "}");
				}
			} else {
				// _return = Newtonsoft.Json.JsonConvert.SerializeObject(obj);
			}
			return _return;
		},
		toQueryString : function (queries) {
			var query_strings = [];
			for (var key in queries) {
				query_strings.push(key + '=' + encodeURIComponent(queries[key]));
			}
			return query_strings.join('&');
		},
		escape: function( str ) {
			return str
					.replace( /\u0022/g, '\\"' )			// \" represents the quotation mark character (U+0022).
					.replace( /\u005C/g, '\\' )				// \\ represents the reverse solidus character (U+005C).
					.replace( /\u002F/g, '\/' )				// \/ represents the solidus character (U+002F).
					.replace( /\u0008/g, '\\b' )			// \b represents the backspace character (U+0008).
					.replace( /\u000C/g, '\\f' )			// \f represents the form feed character (U+000C).
					.replace( /\u000A/g, '\\n' )			// \n represents the line feed character (U+000A).
					.replace( /\u000D/g, '\\r' )			// \r represents the carriage return character (U+000D).
					.replace( /\u0009/g, '\\t' );			// \t represents the character tabulation character (U+0009).
		}
	}
}


/**
 * convert characters to unicode values
 * 
 * @param  {string} unicodeTxt		The string to be encoded
 */
function strToHtmlEntities(unicodeTxt) {
	var htmlEntitiesText = '';
	for (var i = 0; i < unicodeTxt.length; i++) {
		if (unicodeTxt.charCodeAt(i) > 127) {
			htmlEntitiesText += '&#' + unicodeTxt.charCodeAt(i) + ';';
		} else {
			htmlEntitiesText += unicodeTxt.charAt(i);
		}
	}
	return htmlEntitiesText;
}

/**
 * Update object based on another object
 * 
 * @param  {object} orig	The object to be updated
 * @param  {object} data	The object to get the updates from
 * @param  {bool} strict	Check if property exists before updating/merging
 */
function extend(orig, data, strict) {
	if (orig != null && data != null) {
		for (var i in data) {
			if (strict != null && strict === true) {
				if (typeof orig[i] != 'undefined') orig[i] = data[i];
			} else {
				orig[i] = data[i];
			}
		}
	}
	return null;
}

/**
 * convert ms value to HH:MM:SS format
 * 
 * @param  {int} duration	Time in milliseconds
 */
function msToTime(duration) {
    var milliseconds = parseInt((duration%1000)/100),
		seconds = parseInt((duration/1000)%60),
		minutes = parseInt((duration/(1000*60))%60),
		hours = parseInt((duration/(1000*60*60))%24);

    hours   = (hours < 10) ? "0" + hours : hours;
    minutes = (minutes < 10) ? "0" + minutes : minutes;
    seconds = (seconds < 10) ? "0" + seconds : seconds;

    return hours + ":" + minutes + ":" + seconds + "." + milliseconds;
}

/**
 * remove leading and trailing spaces/tabs/newlines
 * 
 * @param  {string} str		The string to be trimmed
 */
function etrim( str ) {
	var rtrim = /^[\s\uFEFF\xA0]+|[\s\uFEFF\xA0]+$/g;
	return str.replace(rtrim, '');
}

/**
 * convert xml string to XML DOM object
 * 
 * @param  {string} xmlStr		The XML string to be parsed
 */
function xmlStrToXmlDoc( xmlStr ) {
	var xmlDoc = new ActiveXObject("Microsoft.XMLDOM");
	xmlDoc.loadXML( xmlStr );
	
	return xmlDoc;
}

/**
 * convert XML DOM object to JSON
 * 
 * @param  {string} xml		The XML string to be parsed
 */
function xmlToJson(xml) {
	// Create the return object
	var obj = {};

	if (xml.nodeType == 1) { // element
		// do attributes
		if (xml.attributes.length > 0) {
			obj["@attributes"] = {};
			for (var j = 0; j < xml.attributes.length; j++) {
				var attribute = xml.attributes.item(j);
				obj["@attributes"][attribute.nodeName] = attribute.nodeValue;
			}
		}
	} else if (xml.nodeType == 3) { // text
		obj = xml.nodeValue;
	}

	// do children
	if (xml.hasChildNodes()) {
		for(var i = 0; i < xml.childNodes.length; i++) {
			var item = xml.childNodes.item(i);
			var nodeName = item.nodeName;
			if (typeof(obj[nodeName]) == "undefined") {
				obj[nodeName] = xmlToJson(item);
			} else {
				if (typeof(obj[nodeName].push) == "undefined") {
					var old = obj[nodeName];
					obj[nodeName] = [];
					obj[nodeName].push(old);
				}
				obj[nodeName].push(xmlToJson(item));
			}
		}
	}
	return obj;
};

/**
 * Convert XML (string) to XMLDOM object
 * 
 * @param  {string} xmlStr		The XML string to be parsed
 */
function xml( xmlStr ) {
	var xmlDoc = new ActiveXObject("Microsoft.XMLDOM");
		xmlDoc.loadXML( xmlStr );
	
	function GetXmlDoc() {
		return xmlDoc;
	}
	
	function find( queryString ) {
		return xmlDoc.selectSingleNode( queryString );
	}
	
	var methods = {
		getXmlDoc: GetXmlDoc,
		find: find
	}
	
	return methods;
}

/**
 * Strip HTML and PHP tags from a string
 * 
 * @param  {string} input		The string to be checked/stripped
 * @param  {string} allowed		The HTML tags to allow
 */
function strip_tags(input, allowed) {
	allowed = (((allowed || '') + '')
		.toLowerCase()
		.match(/<[a-z][a-z0-9]*>/g) || [])
		.join(''); // making sure the allowed arg is a string containing only tags in lowercase (<a><b><c>)
	var tags = /<\/?([a-z][a-z0-9]*)\b[^>]*>/gi;
	return input.replace(tags, function ($0, $1) {
				return allowed.indexOf('<' + $1.toLowerCase() + '>') > -1 ? $0 : '';
			});
}

/**
 * Quote string with slashes
 * Add a backslash in front of single quote, double quote, backslash ['"\]
 * 
 * @param  {string} str		The string to be escaped.
 */
function addslashes(str) {
	return (str + '')
		.replace(/[\\"']/g, '\\$&')
		.replace(/\u0000/g, '\\0')
}

// Get Functions - functions that return something

