// Use on multi-opens only
// This function returns the Set of precodes 
// where the answer to the multi-open is greater than zero.
function GetSetGreaterThanZero(qMultiOpen){
   var allPrecodesArr = f(qMultiOpen).domainValues();
   var returnSet = new Set();

   for (var i = 0; i < allPrecodesArr.length; i++)   {
     var currentPrecode = allPrecodesArr[i];
     var currentValue = f(qMultiOpen)[currentPrecode].toNumber();

     if (currentValue > 0)
      returnSet.add(currentPrecode)
   }
   
  return returnSet;
} 

// Use on multi-opens only
// This function returns the sum of a column of a multi-open.
function GetColumnSum(qMultiOpen){
	var totalSumForColumn = 0;

	// domainValues is necessary since we need to set any unanswered options to zero
	// otherwise, the unanswered option return null, which is not a number
	var allPrecodesArr = f(qMultiOpen).domainValues(); // retrieves an array of all possible Answer precodes

	for (var i = 0; i < allPrecodesArr.length; i++)	{	
		var currentPrecode = allPrecodesArr[i];
			var currentValue = f(qMultiOpen)[currentPrecode].toNumber();
		   	   if (f(qMultiOpen)[currentPrecode].toBoolean())
				totalSumForColumn += currentValue;
		     	   else
				totalSumForColumn += 0;
	} // end for loop

	return totalSumForColumn;
} 

// This function will return a random item from a given Set.
function PickRandomPrecodeFromSet(getSet){
	var getArray = getSet.members();
	return PickRandomPrecode(getArray);

} 

// This function will return a random item from a given Array.
function PickRandomPrecode(getArray){
	var len = getArray.length;
  	var randx = Math.floor( Math.random() * len );
	var randomPrecode = getArray[randx];

	return randomPrecode;

} 

// This function returns a Set of random precodes
// with a given number precodes up to nr.
function GetXRandSetFromSet(fromSet, nr){
	var checkSet = fromSet;
	var randomSet = new Set();

  	for (var i = 0; i < nr && checkSet.size() > 0; i++)	{
		var randPrecode = PickRandomPrecodeFromSet(checkSet);
		randomSet.add(randPrecode);
		checkSet = checkSet.diff(set(randPrecode));
	} 

	return randomSet;
} 

// This function will return the lowest priority item from which
// there is a match to the items in a given Array.
function PickLowestFromArray(priorityArr, checkArr){
	checkArr.sort();

	var returnElement = null;
	var isMatched = false;

	for (var j=0; j < priorityArr.length && !isMatched; j++){
		var currentPriority = priorityArr[j];
		currentPriority = parseInt(currentPriority, 10);

		for (var i=0; i < checkArr.length && !isMatched; i++){
			var currentCheck = checkArr[i];
			currentCheck = parseInt(currentCheck, 10);

			if (currentPriority == currentCheck)			{
				returnElement = currentPriority;
				// dvlp_echo("***MATCHED! ***", blue)
				isMatched = true;
				break;
			} 
		} 
	} 
	//dvlp_echo("returnElement = " + returnElement, blue)
	return returnElement;

} 

// This function will return the precode of the #1 rank
// entered in a ranking question.
function GetTopRankCode(rankQID){
	var rankArr = f(rankQID).domainValues();
	var topRankPrecode = "";

	for (var i = 0; i < rankArr.length; i++){
		var currentPrecode = rankArr[i];

		   if (f(rankQID)[currentPrecode].toNumber() == 1) {
			topRankPrecode = currentPrecode;
			break;
		   }
	} 
	//dvlp_echo("Precode of #1 Rank = " + topRankPrecode, blue)
	return topRankPrecode;

}

