// Used to recode the ones and zeros of a Multi 
// to the associated string of precodes answered.
// The result is put into a hidden open-text question.
// Note: fieldwidthPerCode is the number of digits needed for each precode. 
// This function will pad with zeros if necessary to reach fieldwidthPerCode.
// Final array is sorted before setting to the Open.
function RecodeMultiToOpen(qMulti, qOpen, fieldwidthPerCode){
	f(qOpen).set(null);

	var precodeArr = f(qMulti).categories();
	var precodeFilledArr = new Array();

	for (var i = 0; i < precodeArr.length; i++)	{
		var currentPrecode = precodeArr[i].toString();

		while (currentPrecode.length != fieldwidthPerCode)		{
			currentPrecode = "0" + currentPrecode;
		} // end while loop
		precodeFilledArr[i] = currentPrecode;
	} 

	var precodeStr = '';
	var sortedArr = precodeFilledArr.sort();
	for (var i = 0; i < sortedArr.length; i++)	{
		var currentPrecode = sortedArr[i];
		precodeStr += currentPrecode;
		
	} 

	f(qOpen).set(precodeStr);

}

// utility functions - functions that do something

// General Notes:
// Parameters such as qid or precodes should be typed as strings, e.g. "q1" or 'q1'

// This function takes any array and 
// converts it to a Confirmit Set.
function Array2Set(getArray){
	var newSet = new Set();

	for (var i = 0; i < getArray.length; i++)	{
		var currentMember = getArray[i];
		   if (currentMember != null)
			newSet.add(currentMember);
	} 
	return newSet;
} 


// Use in question text with hats, ^.
// This function will pipe the Other Specify from a Single, if specified, 
// otherwise, it pipes the selected answer text into the question text.
// Example: ^PipeOtherSingle('q1', '98')^
function PipeOtherSingle(qSingle, otherPrecode){
	var pipeText = "";

	   if (f(qSingle).value() == otherPrecode)	   {
		var otherqSingle = qSingle + "_" + otherPrecode + "_other";
		pipeText = f(otherqSingle);
	   } 
	   else
		pipeText = f(qSingle);
	return pipeText;
} 

// Use in question text with hats, ^.
// This function will pipe the Other Specify from a Multi, if specified, 
// otherwise, it pipes the selected answer texts into the question text.
// Example: ^PipeOtherMulti('q1', '98')^
function PipeOtherMulti(qMulti, otherPrecode)
{
	var pipeText = "";

	   if (f(qMulti)[otherPrecode].get() == 1)	   {
		var otherqMulti = qMulti + "_" + otherPrecode + "_other";
		pipeText = f(otherqMulti);
	   } 
	   else
		pipeText = f(qMulti);
	return pipeText;
} 

// Use in question text with hats, ^.
// This function will return the answer text associated with the #1 rank
// entered in a multi open ranking question.
// Uses the function GetTopRankCode.
// Example: ^PipeTopRankText('q1')^
function PipeTopRankText(rankQID){
	var topRankPrecode = GetTopRankCode(rankQID);

	if (topRankPrecode != "")
		var topRankLabel = f(rankQID)[topRankPrecode].label();

//dvlp_echo("#1 Rank = " + topRankLabel,'blue');
	return topRankLabel;

} 

// Use in question text with hats, ^.
// This function shows an HTML a bulleted list from a Multi.
// Example: ^ShowBulletedListFromMulti('q1')^
function ShowBulletedListFromMulti(qMulti){
	var precodeArr = f(qMulti).categories();
	var returnText = "";
	returnText += "<ul>";

	for(var i=0; i < precodeArr.length; i++)	{
		var currentPrecode = precodeArr[i];
		var currentLabel = f(qMulti)[currentPrecode].label();
		returnText += "<li>" + currentLabel + "</li>";
		returnText += "<br>";
	} 
	returnText += "</ul>";
	return returnText;
} 

// Use in question text with hats, ^.
// This function shows a simple HTML table from a Single.
// Example: ^ShowTableFromSingle('q1')^
// It uses style sheets for look and feel. 
// Just need to define the class named "showtable". 
// If you don't include this class on the page,
// then it will just show with white background.
function ShowTableFromSingle(qSingle){
	var currentLabel = f(qSingle).valueLabel();
	var returnText = "";
	returnText += "<table width=300 border=1 cellpadding=1 cellspacing=1>\n";
	returnText += "<tr>\n";
	returnText += "<td align=center class=showtable>" + currentLabel + "</td>\n";		
	returnText += "</tr>\n";
	returnText += "</table>\n";
	return returnText;
} 

// Use in question text with hats, ^.
// This function shows a simple HTML table from a Multi.
// Example: ^ShowTableFromMulti('q1', 3)^
// It uses style sheets for look and feel. 
// Just need to define the class named "showtable". 
// If you don't include this class on the page,
// then it will just show with white background.
function ShowTableFromMulti(qMulti, numColumns){
	var precodeArr = f(qMulti).categories();
	var length = precodeArr.length;
	var numRows = length / numColumns;

	var returnText = "";
	returnText += "<table width=600 border=0 cellpadding=1 cellspacing=1>\n";

	for (var j=0; j < numRows; j++)	{		
		returnText += "<tr>\n";
		for (var i=0; i < numColumns; i++)		{
			var count = (i*numRows) + j;
			var currentPrecode = precodeArr[count];
			var currentLabel = f(qMulti)[currentPrecode].label();
			returnText += "<td align=center class=showtable>" + currentLabel + "</td>\n";
		} 
		returnText += "</tr>\n";
	} 
	returnText += "</table>\n";
	return returnText;
} 

// used in loops only
// This function sets a hidden variable to the 
// number of loop iterations the respondent saw.
// Also stores the order shown for the loop.
// OutsideQID is a hidden open, outside the loop
// InsideQID is a hidden open, inside the loop
// Call this function in a script node at the beginning of the loop.
function SetLoopCounter(OutsideQID, InsideQID){
	var lastcount = f(OutsideQID);
	   if (Forward())	   {
  	   	   if (lastcount.toBoolean())		   {
			var IterationNumber = lastcount.toNumber();
			IterationNumber++;
			f(OutsideQID).set(IterationNumber);
		   }  
	   	   else		   {
			f(OutsideQID).set(1);
		   } 
	   } 	
	var newcount = f(OutsideQID);
	// InsideQID stores the order inside the loop
	f(InsideQID).set(newcount);
	//dvlp_echo("Loop count = " + newcount,'blue');
} 


// use for Multi-opens only
// This function sets all cells in a multi-open to 0.
// It always overwrites, so be careful.
// You would call this function in a script node, just before the question.

function SetMultiOpenToZero(qMultiOpen){
  var precodesArr = f(qMultiOpen).domainValues(); 

  	for (var i=0; i < precodesArr.length; i++)    	{ 
		var currentPrecode = precodesArr[i];
		f(qMultiOpen)[currentPrecode].set(0);
	} 
}

// Include Functions


// This function returns True if any of the following are true:
//  Singles: Any members (at least one) of the getPrecodeSet
//   from the qid's Answer list are checked
//  Multis: Any members (at least one) of the getPrecodeSet
//   from the qid's Answer list are checked off
//  Grids: Any members (at least one) of the getPrecodeSet
//   from the qid's Scale list are checked off
// Note: IncAny is really a special case of
//       IncAtLeast with getNum set to 1
// This function works like function include_or() but
// can be used on several types of questions.
function IncAny(qid, getPrecodeSet){
	return IncAtLeast(qid, getPrecodeSet, 1);
} // end function

// This function returns True if any of the following are true:
// 	Singles: At least getNum members of the getPrecodeSet 
//			from the qid's Answer list are checked
// 	Multis: At least getNum members of the getPrecodeSet 
//			from the qid's Answer list are checked off
// 	Grids: At least getNum members of the getPrecodeSet 
//			from the qid's Scale list are checked off
function IncAtLeast(qid, getPrecodeSet, getNum){

	// global declarations
	var answerArr = new Array();
	var answerSet = new Set();
	var scaleArr = new Array();
	var scaleSet = new Set();
	var isTrue = new Boolean();

	// global initializations
	var x = f(qid);
	isTrue = false;

   if (x.size() >= 1)   {
	   // Singles
	   if (x.CODED)	   {

		// dvlp_echo("in Singles section",'blue');
		
		var answer = x.value(); // retrieve the selected precode
		answerArr[0] = answer; // add this precode to an array

		// populate the set from the array
		answerSet = Array2Set(answerArr);

		   // *** Check if the selected precode is in the getPrecodeSet  
		   if (answerSet.isect(getPrecodeSet).size() >= getNum)
			isTrue = true; 

	   } 
	   // Multis and Grids
	   else if (x.COMPOUND)	   {
		// this retrieves an array of all the answered Answer precodes
		answerArr = x.categories();

		// this retrieves an array of all the answered Scale precodes
		scaleArr = x.values();

		// populate the appropriate set from each array
		answerSet = Array2Set(answerArr);
		scaleSet = Array2Set(scaleArr);

		// repPrecode is the first precode in the array
		var repPrecode = answerArr[0].toString();

		// y is the first question answered.
		// It is used as a represenative to find out if question
		// is a multi or a grid.
		var y = f(qid)[repPrecode];
		   // Multis
		   if (y.DICHOTOMY)		   {

			// dvlp_echo("in Multis section",'blue');

			   // *** Check at least getNum of the selected Answer precodes are in the getPrecodeSet  
			   if (answerSet.isect(getPrecodeSet).size() >= getNum)
				isTrue = true; 

		   } 
		   // Grids
		   else if (y.CODED)	   {

			// dvlp_echo("in Grids section",'blue');

			   // *** Check at least getNum of the selected Scale precodes are in the getPrecodeSet  
			   if (scaleSet.isect(getPrecodeSet).size() >= getNum)
				isTrue = true; 
		   } // end else if
	   } // end else if
   } 

	return isTrue;

} // end function

// Generic Grid Functions

// General Notes:
// Parameters such as qid or precodes should be typed as strings, e.g. "q1" or 'q1'


// This function returns the Set of Answer List precodes 
// where the Scale precode of a Grid is equal to a given number.
// This function can be used on its own in a script, as a question mask or 
// as a condition to enter a question using .size() > 0
// checkScalePrecode can be either a string or a number,
// because it is converted to a number inside the function.
function GetGridSetEqualTo(fromGridQID, checkScalePrecode){
	var returnSet = new Set();

	// this is a special case of GetGridSetBetween
	returnSet = GetGridSetBetween(fromGridQID, checkScalePrecode, checkScalePrecode);
	
	//dvlp_echo("The Set of answer precodes from " + fromGridQID + " with Scale precode equal to " + checkScalePrecode + " = " + returnSet,'blue');
	return returnSet; 
} 

// This function returns the Set of Answer List precodes 
// where the Scale precode of a Grid is between 
// a minimum precode and a maximum number, inclusive.
// This function can be used on its own in a script, as a question mask or 
// as a condition to enter a question using .size() > 0
// minPrecode and maxPrecode can be either a string or a number,
// because they are converted to numbers inside the function.
function GetGridSetBetween(fromGridQID, minPrecode, maxPrecode){
	var returnSet = new Set();
	var precodeArr = f(fromGridQID).categories();

	// convert Scale precodes to numbers
	var minPrecodeNum = parseInt(minPrecode, 10);
	var maxPrecodeNum = parseInt(maxPrecode, 10);

	for (var i = 0; i < precodeArr.length; i++)	{
		var currentPrecode = precodeArr[i];
		var currentValue = f(fromGridQID)[currentPrecode].toNumber();
		
		   if (currentValue >= minPrecodeNum  && currentValue <= maxPrecodeNum )
			returnSet.add(currentPrecode);		
	} 
	//dvlp_echo("The Set of answer precodes from " + fromGridQID + " with Scale precodes between " + minPrecode + " and " + maxPrecode + " = " + returnSet,'blue');

	return returnSet; 

} 

// This function is a boolean function that returns true if
// all of the Scale precodes of a Grid are equal to a given precode.
// This function can be used on its own in a script or
// as a condition to enter a question.
function AreAllEqualTo(fromGridQID, checkScalePrecode){
	var returnSet = new Set();
	var allequal = false;
	checkScalePrecode = checkScalePrecode.toString();

	var precodeArr = f(fromGridQID).categories(); 
   	if (f(fromGridQID).size() > 0 )   	{
		var count = 0;

		for (var i = 0; i < precodeArr.length; i++)		{
			var currentPrecode = precodeArr[i];
			var currentValue = f(fromGridQID)[currentPrecode].toString();
		
		   	if (currentValue == checkScalePrecode )
				count++;		
		} 

	   	if (count == precodeArr.length)
			allequal = true; 

   	} 
	//dvlp_echo("Are all answers from Grid," + fromGridQID + ", equal to Scale precode " + checkScalePrecode + "? " + allequal,'blue');
	return allequal;

} 

// ********************************************
// **** Grid functions that set something *****
// ********************************************

// This function will set the given answer of a Grid
// to a given Scale precode
function SetAGrid(setGridQID, setAnswerPrecode, setScalePrecode){
	f(setGridQID)[setAnswerPrecode].set(setScalePrecode);
} 

// This function sets a Multi question based on the answers from
// a given Scale precode of a Grid. 
// This assumes that the Answer Lists of the Multi contains
// at least all of the Answer List precodes from the Grid.
// checkScalePrecode can be either a string or a number,
// because it is converted to a number inside the function.
// This function will NOT clear out the multi before setting it.
// This is a special case of SetMultiFromGridSetBetween
function SetMultiFromGridSetEqualTo(fromGridQID, toMultiQID, checkScalePrecode){
	// this is a special case of setMultiFromGridSetBetween
	SetMultiFromGridSetBetween(fromGridQID, toMultiQID, checkScalePrecode, checkScalePrecode);
	//dvlp_echo("Multi question, " + toMultiQID + ", set to the Set of answer precodes from " + fromGridQID + " with Scale precode equal to " + checkScalePrecode + " = " + f(toMultiQID).categoryLabels(),'blue');


} 

// This function sets a Multi question to the Set of answers
// where the Scale precode of a Grid is between 
// a minimum precode and a maximum number, inclusive.
// minPrecode and maxPrecode can be either a string or a number,
// because they are converted to numbers inside the function.
// This assumes that the Answer Lists of the Multi contains
// at least all of the Answer List precodes from the Grid.
// This function will NOT clear out the multi before setting it.
function SetMultiFromGridSetBetween(fromGridQID, toMultiQID, minPrecode, maxPrecode){
	var precodeArr = GetGridSetBetween(fromGridQID, minPrecode, maxPrecode).members();
	// could have also used my function here, SetMultiFromSet(fromSet, toMulti)
	// as commented below. 
	// var fromSet = GetGridSetBetween(fromGridQID, minPrecode, maxPrecode);
	// SetMultiFromSet(fromSet, toMultiQID);

	for (var i = 0; i < precodeArr.length; i++)	{
		var currentPrecode = precodeArr[i];
		f(toMultiQID)[currentPrecode].set(1);		
	} 

//dvlp_echo("Multi question, " + toMultiQID + ", set to the Set of answer precodes from " + fromGridQID + " with Scale precodes between " + minPrecode + " and " + maxPrecode + " = " + f(toMultiQID).categoryLabels(),'blue');

} 

// This function copies all the answers from one Grid to another Grid.
// This assumes that the 2nd Grid has at least the same precodes
// in the Answer List and the Scale when compared to the original Grid.
function CopyGridtoGrid(fromGridQID, toGridQID)
{
	var precodeArr = f(fromGridQID).categories(); 

	for (var i = 0; i < precodeArr.length; i++)
	{
		var currentPrecode = precodeArr[i].toString();
		var currentValue = f(fromGridQID)[currentPrecode].toString();
		
		SetAGrid(toGridQID, currentPrecode, currentValue);
		
	} 
	//dvlp_echo("The answers of Grid question, " + toGridQID + ", have been copied to " + fromGridQID,'blue');
}

function PunchGrid(srcqid,toqid,arrValues,arrPrecodes){
	qclear(toqid);

	if(typeof(arrPrecodes)=="undefined")
		arrPrecodes=f(toqid).domainValues();

		var setCodes = arrayToSet(arrValues);

		for(var i=0;i<arrPrecodes.length;i++){
			var response = f(srcqid)[arrPrecodes[i]].toNumber()

			if(setCodes.inc(response))	{
				f(toqid)[arrPrecodes[i]].set(1)
			}	
		}
}

function randomizeArray(arrValues){
	var setCodes = arrayToSet(arrValues);
	var randArray = new Array();
	var arrTemp = new Array();
	var randIndex= 0;

	while(setCodes.size()>0){
		arrTemp = setCodes.members();
		randIndex = Math.floor(Math.random()*arrTemp.length);
		randArray.push(arrTemp[randIndex]);
		setCodes.remove(arrTemp[randIndex])
	}
	return randArray;
}

