function zeroFill(qid,code,fmt){
  
  //formatting
  //000 = 3 digits
  //000.00 = 3 digits and 2 decimals
  
  var q = qid;
  var format : String  = fmt;
  var ans : float = f(q+'_'+code+'_other').toNumber();
  f(q+'_'+code+'_other').set(ans.ToString(format));
  
}

