	return CSStext;
}

function getRandomInt(max) {
  //add 1 so it the lowest possible number is 1 and not 0
  return Math.floor(Math.random() * Math.floor(max))+1;
}

function DNR() {
  var str = "";
  if (IsCati()) {
    str += "<span class='catifont'>(" + GetCustomText(257) + ")</span> ";
  }
  return str
}

function TestDisclaimer() {
  var str = "";
  if (IsCati()) {
    str += "(TESTING ONLY: IF YOU SEE THIS AND DO NOT BELIEVE YOU SHOULD, REPORT TO PROGRAMMER) ";
  } else {
    str += "(TESTING ONLY: IF YOU SEE THIS AND DO NOT BELIEVE YOU SHOULD, STOP AND REPORT VIA EMAIL) ";    
  }
  return str
}

function inst(opt) {
  
  var str = "";
  if (opt == "DNR" ){ 
    if (IsCati()) {
      str += "<span class='catifont'>("+GetCustomText(261)+": "+GetCustomText(258)+")</span>";       
    }
  }
  if (opt == "RDL" ){ 
    if (IsCati()) {
      str += "<span class='catifont'>(" + GetCustomText(261) + ": " + GetCustomText(259) + ")</span>" 
    }

  }
  if (opt == "RDN" ){ 
    if (IsCati()) {
      str += "<span class='catifont'>(" + GetCustomText(261) + ": " + GetCustomText(260) + ")</span>"
    }
  }
  
  return str
}

function GOTO(qid,iter) 
{

var test = f('test').value();    
var lang = f('language').value();      
var url = "";
//doCustomNav();

if (qid)  
{
  
	if(iter)
	{
	    url = IsWeb() ? GetRespondentUrl(qid,iter) : GetCatiRespondentUrl(qid,iter);
        //url = IsWeb() ? GetRespondentUrl(qid,iter) : GetCatiRespondentUrl(qid,iter).Replace(domain, "survey.us.confirmit.com");
	}
	else
	{
        url = IsWeb() ? GetRespondentUrl(qid) : GetCatiRespondentUrl(qid);
        //url = IsWeb() ? GetRespondentUrl(qid) : GetCatiRespondentUrl(qid).Replace(domain, "survey.us.confirmit.com");
	}
	if (IsCati()) {
		url = GetCatiRespondentUrl(qid).Replace("survey.us.confirmit.com", "cati.us.confirmit.com");
	}
	    url += "&l=" + lang + "&test=" + test;;
	
	    Redirect(url, true);
} 
else
{

	//send email and send to gotoErr
	//build body of email:
    var currentQ = CurrentForm();
	var scripter = survey_setting()['ErrorEmail']
  
	var body : String = "An error has just occurred with goto.\r\n\r\n";
    body += "Current question noted: " + currentQ + "\r\n\r\n";
    body += "Current respid: " + CurrentID() + "\r\n\r\n";  
    body += "Current userid: " + f('userid') + "\r\n\r\n";    
	body += "Current Pid: " + CurrentPID() + "\r\n\r\n";    
	body += "Best Regards\r\n\r\n";

	//send mail:
	SendMail("mailer@us.confirmit.com",scripter,CurrentPID() + "Goto ERR!",body,"","");	
  
	var qid = 'gotoErr';
    var url = IsWeb() ? GetRespondentUrl(qid) : GetCatiRespondentUrl(qid);
    url += "&l=" + CurrentLang();
    Redirect(url, true);   
  
}
  
}

