}

//clearForm("q1_98_other");
function clearForm(form) 
{
  var q = f(form);                   
  if(q.COMPOUND) //form with multiple items
   {
    var fcodes = q.domainValues(); //all codes in form
    for(var i : int = 0;i<fcodes.length;i++) //iterate through code
     {
       q[fcodes[i]].set(null); //clear item
     }
   }
  else //form with one item
   {
    q.set(null);
   }
}

function ClearForms(qids)
{
	for( var i=0; i<qids.length; ++i)
	{
		var q = f(qids[i]);
		if(q.COMPOUND)
		{
			var codes = a(qids[i]);
			var d = codes.members();
			for(var j=0;j<d.length;++j)
			{
				q[d[j]].set(null);
			}
		}
		else
		{
			q.set(null);
		}
	}
}

