var numeric = document.getElementById(currentQuestion.id + '_input');
var div = document.createElement('div');
div.id = currentQuestion.id + '_div';
div.style.textAlign = 'right';
div.style.padding = '5px 0';
div.style.fontWeight = 'bold';
div.style.width = numeric.offsetWidth + 'px';
numeric.parentNode.insertBefore(div, numeric.nextSibling);
numeric.addEventListener('input',(e) => {
    var elem = e.target;
    var disp = elem.nextElementSibling;
    disp.innerText = Number(elem.value).toLocaleString('en-US');   
});

