function quotaAsk(val) {

var qb = 'percent_ask_' + val;
var qta = 'quota_ask_' + val

if (val==10) { var rndInt = 10; };   //requires quota_ask_10 to be created
if (val==25) { var rndInt = 4; };     //requires quota_ask_25 to be created
if (val==33) { var rndInt = 3; };     //requires quota_ask_33 to be created
if (val==50) { var rndInt = 2; };     //requires quota_ask_50 to be created

if (Forward() ) {
  
      if (!f(qb).toBoolean()) {
        f(qb).set(new Array(GetLeastFilledQuotaCodes(qta,1)));
      }
    
      if (!f(qb).toBoolean()) {      
        var num = getRandomInt(rndInt)
        f(qb).set(num);
      }
  
} else {

  //probably not needed, but if backing up they should clear and check and pick again, comment in
  //clearForm(qb);
}
} //end function

function CompRate(){

  var arrQIDS  = GetQuestionIds(true, false);  
  var LoopArr = survey_setting()['AllLoopIDs'];         //keep surveyHistory so function won't crash (false positive) add your loop elements

  var WebBlankValue = survey_setting()['WebBlankValue'];
  var SkipQ = 0;
  var SawQuestion = 0;
  var Nines = 0;
  var Answered = 0;
  
 

  DEBUG("--------------------------------------------",'black');
  DEBUG("------------------COMPRATE------------------",'purple');
  DEBUG("--------------------------------------------",'black');
  DEBUG("start SkipQ = " + SkipQ,'orange');
  DEBUG("start SawQuestion = " + SawQuestion,'blue');
  DEBUG("start WebBlank = " + Nines,'red');
  DEBUG("start Answered = " + Answered,'green');
  
  
  DEBUG("--------------------------------------------",'black');
  DEBUG("------START CHECKING REGULAR QUESTIONS------",'black');
  DEBUG("--------------------------------------------",'black');

  var i : int;
  for ( i=0; i<arrQIDS.length; i++ )  {
    var qid = arrQIDS[i]

    if ( qid == 'COMMENT1' || qid == 'COMMENT2' ){ 
      SkipQ = SkipQ+1;
      DEBUG(qid +" | SkipQ = "+SkipQ,'orange');
    }
    
    else if ( f(qid).getType() == 'CODED'){
      if ( f(qid).toBoolean() ) {
        SawQuestion = SawQuestion + 1;
        if (f(qid).any(WebBlankValue) ){
          Nines = Nines+1;
          DEBUG(qid +" | WebBlank = "+Nines,'red');
        }
        else {
          Answered = Answered+1;
          DEBUG(qid +" | Answered = "+Answered,'green');
        }
      }
      else {
        SkipQ = SkipQ+1;
        DEBUG(qid +" | SkipQ = "+SkipQ,'orange');
      }
    }

    else if ( f(qid).getType() == 'COMPOUND' && getQuestionTypesNew(qid) == 'MULTI'){
      if (f(qid).inc(WebBlankValue)){
        SawQuestion = SawQuestion + 1;
        Nines = Nines+1;
        DEBUG(qid +" | WebBlank = "+Nines,'red');
      }
      else if (f(qid).toBoolean()){
        SawQuestion = SawQuestion + 1;
        Answered = Answered+1;
        DEBUG(qid +" | Answered = "+Answered,'green');
      }
      else {
        SkipQ = SkipQ+1;
        DEBUG(qid +" | SkipQ = "+SkipQ,'orange');
      }
    }

    else if ( f(qid).getType() == 'OPEN'){
      if ( f(qid).toBoolean() ) {
        SawQuestion = SawQuestion + 1;
        if (f(qid) == WebBlankValue ){
          Nines = Nines+1;
          DEBUG(qid +" | WebBlank = "+Nines,'red');
        }
        else {
          Answered = Answered+1;
          DEBUG(qid +" | Answered = "+Answered,'green');
        }
      }
      else {
        SkipQ = SkipQ+1;
        DEBUG(qid +" | SkipQ = "+SkipQ,'orange');
      }
    } 
    else if ( getQuestionTypesNew(qid) == 'GRID'){  //f(qid).getType() == 'COMPOUND' &&
      var Iter;
      var PrecodesArr = f(qid).domainValues();
      //DEBUG(qid+ " = "+f(qid).domainValues(),'black');

      var zz : int;
      for ( zz=0; zz<PrecodesArr.length; zz++ ){
        Iter = PrecodesArr[zz]
        //DEBUG(qid+"_"+Iter,'purple');
        if ( f(qid)[Iter].toBoolean() ){
          SawQuestion = SawQuestion + 1
          if (f(qid)[Iter] == WebBlankValue){
            Nines = Nines+1;
            DEBUG(qid+"_"+Iter +" | WebBlank = "+Nines,'red');
          }
          else{
            Answered = Answered+1;
            DEBUG(qid+"_"+Iter +" | Answered = "+Answered,'green');
          }
        }
        else {
          SkipQ = SkipQ+1;
          DEBUG(qid+"_"+Iter +" | SkipQ = "+SkipQ,'orange');
        }
      }      
    }//END QUESTION TYPE EVAL
  }//END REGULAR QUESTIONS LOOP
  DEBUG("--------------------------------------------",'black');
  DEBUG("------------END REGULAR QUESTIONS-----------",'black');
  

  DEBUG("--------------------------------------------",'black');
  DEBUG("-------------START CHECKING LOOPS-----------",'black');
  DEBUG("--------------------------------------------",'black');
  DEBUG('LoopArr: '+LoopArr,'black');
  DEBUG("--------------------------------------------",'black');

  if ( LoopArr.length >= 1) {
      var k : int;
      for ( k=0; k<LoopArr.length; k++ )  {
        var LoopId = LoopArr[k]
        var PrecodesArr = f(LoopId).domainValues();

        DEBUG('LoopId: '+LoopId+ " = "+f(LoopId).domainValues(),'black');
        DEBUG("--------------------------------------------",'black');
      if ( PrecodesArr.length >= 1) {
        var z : int;
        for ( z=0; z<PrecodesArr.length; z++ ){
           var Iters = PrecodesArr[z]
           var QIDstr = GetQuestionIds(true, false,[LoopId]);

           //DEBUG('QIDstr '+QIDstr,'blue');
           //DEBUG('QIDstr.length '+QIDstr.length,'blue');
          if ( QIDstr.length >= 1) {
            var j : int;
            for (j=0; j<QIDstr.length; j++ )  {
              var qid = QIDstr[j]
              if ( f(qid,Iters).getType() == 'CODED'){
                if ( f(qid,Iters).toBoolean() ) {
                  SawQuestion = SawQuestion + 1;
                  if (f(qid,Iters).any(WebBlankValue) ){
                    Nines = Nines+1;
                    DEBUG(qid+"_"+Iters +" | WebBlank = "+Nines,'red');
                  }
                  else {
                    Answered = Answered+1;
                    DEBUG(qid+"_"+Iters +" | Answered = "+Answered,'green');
                  }
                }
                else {
                  SkipQ = SkipQ+1;
                  DEBUG(qid+"_"+Iters +" | SkipQ = "+SkipQ,'orange');
                }
              }

              else if ( f(qid,Iters).getType() == 'COMPOUND'){
                if (f(qid,Iters).inc(WebBlankValue)){
                  SawQuestion = SawQuestion + 1;
                  Nines = Nines+1;
                  DEBUG(qid+"_"+Iters +" | WebBlank = "+Nines,'red');
                }
                else if (f(qid,Iters).toBoolean()){
                  SawQuestion = SawQuestion + 1;
                  Answered = Answered+1;
                  DEBUG(qid+"_"+Iters +" | Answered = "+Answered,'green');
                }
                else {
                  SkipQ = SkipQ+1;
                  DEBUG(qid+"_"+Iters +" | SkipQ = "+SkipQ,'orange');
                }
              }
              else if ( f(qid,Iters).getType() == 'OPEN'){
                if ( f(qid,Iters).toBoolean() ) {
                  SawQuestion = SawQuestion + 1;
                  if (f(qid,Iters) == WebBlankValue ){
                    Nines = Nines+1;
                    DEBUG(qid+"_"+Iters +" | WebBlank = "+Nines,'red');
                  }
                  else {
                    Answered = Answered+1;
                    DEBUG(qid+"_"+Iters +" | Answered = "+Answered,'green');
                  }
                }
                else {
                  SkipQ = SkipQ+1;
                  DEBUG(qid+"_"+Iters +" | SkipQ = "+SkipQ,'orange');
                }
                DEBUG(qid+"_"+Iters +" | SkipQ = "+SkipQ,'orange');
              }
            }
          }
        }
       }
      }
  }
  DEBUG("-------------END CHECKING LOOPS-------------",'black');
  DEBUG("--------------------------------------------",'black');


  var Tot = SawQuestion
  var AS = Answered/SawQuestion
  var NS = Nines/SawQuestion

  var num = AS.toFixed(3);

  f('hCompRate')[1].set(SawQuestion);
  f('hCompRate')[2].set(Nines);
  f('hCompRate')[3].set(Answered);
  f('hCompRate')[4].set(num);

  f('hCompRateNumeric')[1].set(SawQuestion);
  f('hCompRateNumeric')[2].set(Nines);
  f('hCompRateNumeric')[3].set(Answered);
  f('hCompRateNumeric')[4].set(num);
  
  

  DEBUG("------------COMPRATE  RESULTS---------------",'purple');
  DEBUG("--------------------------------------------",'black');
  DEBUG("end SawQuestion = " + SawQuestion,'blue');
  DEBUG("end WebBlank = " + Nines,'red');
  DEBUG("end Answered = " + Answered,'green');
  DEBUG("--------------------------------------------",'black');
  DEBUG("Completion Rate = "+num,'purple');
  DEBUG("--------------------------------------------",'black');

  if (Forward() && IsPanel() && isFromSSRSopSample() ) {

    var surveyHistoryVars = ['pxQShown', 'pxQWbRf', 'pxQAns', 'pxQSrvyCompRate']
    var qShown = f('hCompRate')[1].toNumber();
    var qWbRF = f('hCompRate')[2].toNumber();
    var qAns = f('hCompRate')[3].toNumber();
    var qCompRate = f('hCompRate')[4].toNumber();

    var surveyHistoryVals: String[] = [qShown, qWbRF, qAns, qCompRate]

    UpdateSurveyHistoryPanelVariables(surveyHistoryVars, surveyHistoryVals);

    dvlp_echo('--------------------------', 'orange');
    dvlp_echo("Update surveyHistoryVars:  " + surveyHistoryVars + ' ', 'orange');
    dvlp_echo("Update surveyHistoryVals:  " + surveyHistoryVals + ' ', 'orange');
    dvlp_echo('--------------------------', 'orange');
  } 
  else if ( Forward() && !GetRespondentValue('PanelistID') ){
    dvlp_echo('-----Not Connected to Panel-----','purple');
    dvlp_echo("surveyHistoryVars:  "+surveyHistoryVars + ' = ' + surveyHistoryVals,'purple'); ;
    dvlp_echo('--------------------------------','purple');
  }
  

}//END FUNCTION

function getQuestionTypesNew(qid){
	try{
    //var qid = CurrentForm()
		var type = f(qid).getType();
		//dvlp_echo("f(qid).getType() = "+type,'blue');
		var ret=type;
		switch(type){
			case 'CODED'			 : ret='SINGLE'; 	break;
			case 'COMPOUND' 		 :
				var codes =	f(qid).domainValues();
				var innerType=f(qid)[codes[0]].getType();
				switch(innerType) {
					case 'DICHOTOMY' : ret='MULTI';  break;
					case 'CODED'	 : ret='GRID'; break;
					case 'OPEN'		 : ret='RANKING/OPENTEXTLIST'; break;
					case 'NUMERIC' : ret='NUMERICLIST'; break;
				} 
				break;
			case 'OPEN' : ret='OPEN';	break;
			case 'NUMERIC' : ret='NUMERIC';	break;
			case '3DGrid' :
				var l3dgrid = Get3DGridQuestionIds(qid)
				for(var i=0,isMultGrid=true;i<l3dgrid.length;i++) {
					if(f(l3dgrid[i]).getType()!="COMPOUND") 										{isMultGrid=false; break;}
					else if(f(l3dgrid[i])[f(l3dgrid[i]).domainValues()[0]].getType()!="DICHOTOMY")  {isMultGrid=false; break;}
				}
				if(isMultGrid) ret='MULTIGRID'
				break;
			case ''	: ret = 'INFO'; break;
		}
		
	}catch(err){
		ret = 'INFO';
	}
	//dvlp_echo("return = "+ret,'blue');
	return ret; 
}

