		if (f('TEST').any('1', '3') || !IsInProductionMode()) {
	    //Response.Write("<!DOCTYPE html>");
		//Response.Write("<span style=\"color:" + color + ";font-family:'Lucida Console','Courier New';font-size:8pt;line-height:8pt;display:block;\">" + msg + "</span>");
		}
  }
}

