function ResponseRate() 
{
    var WBcode = survey_setting()['WebBlankValue'];
	var multis = [];
	var nums = [];    
	var opens = [];      
	var singles = [];

	//only use this array if 1 qid in loop and loop name is qidLoop  
	var loops = [];
	//use when loop has multiple qids, must create a separate array for each loop  
	var custLoops = []; 
  
	var qctr = 0;
	var xctr = 0;

	//open
	for (var i = 0; i < opens.length; i++) 
    {
		var q = f(opens[i]);
      
      	if(q.toBoolean())
        {
			//add to asked q
			qctr += 1;	
		}
	}


	//multi
	for (var i = 0; i < multis.length; i++) {
      	var qid = multis[i];
		var q = f(qid);
      	var qWB = f(qid+'_'+WBcode);
      
      	if(q.toBoolean() || qWB.toBoolean())
        {
			//add to asked q
			qctr += 1;	
		}
      
		if(q.any(WBcode))
        {
			//add to skipped q
			xctr += 1;	
        }	
	}

    //singles  (include grids)
    for (var i = 0; i < singles.length; i++)
    {
        var q = f(singles[i]);
      
        if(q.toBoolean()) 
        {
            //add to asked q
            qctr += 1;	
        }
      
        if(q.any(WBcode)) 
        {
            //add to skipped q
            xctr += 1;	
        }	
    }
 
    //numeric   
    for (var i = 0; i < nums.length; i++)
    {
        var q = f(nums[i]);
      
        if(q.toBoolean())
        {
            //add to asked q
            qctr += 1;	
        }
    }
  
    //nums refused/blank - can adjust the response but if different responses, need to create separate arrays, such as nums999, nums9999
    for (var i = 0; i < nums.length; i++)
    {
        var q = f(nums[i]);
      
        if (q.toNumber()==parseInt(WBcode))
        {
            //add to skipped q
            xctr += 1;	
        }
    }  

    //loops
    for(var i = 0; i < loops.length; i++)
    {
        var lst = "";
        lst += loops[i];
        lst += 'Loop';
        var p = f(lst).domainValues();
      
        for (var x = 0; x < p.length; x++)
        {
        	var q = f(loops[i],p[x]);	
          
          	if(q.toBoolean()) 
            {
            	//add to asked q
            	qctr += 1;	
          	}
          	
          	if(q.any(WBcode)) 
            {
            	//add to skipped q
            	xctr += 1;	
          	}		
        }    
    }

    //custom loops - used when multiple qids in loop and they do not share the name with the loop they are in
    for (var i = 0; i < custLoops.length; i++) 
    {
        var lst = "";
        lst += 'qidLoop'; //must setup for each loop that has multiple qids
        var p = f(lst).domainValues();
      
    	for (var x = 0; x < p.length; x++) 
        {
          	var q = f(custLoops[i],p[x]);	
          
          	if(q.toBoolean()) 
          	{
            	//add to asked q
            	qctr += 1;	
          	}
          
    		if(q.any(WBcode)) 
            {
            	//add to skipped q
            	xctr += 1;	
          	}			
      	}    
  	}

    //(QCTR - XCTR)/QCTR
    var calc = ((qctr-xctr)/qctr);
    var percalc = calc*100;
    
    f('qctr').set(qctr);
    f('xctr').set(xctr);
    f('calc').set(calc)
    f('percalc').set(percalc)
      
    dvlp_echo("qctr: "+qctr,'blue');  
    dvlp_echo("xctr: "+xctr,'blue');    
    dvlp_echo("calc: "+calc,'blue');    
    dvlp_echo("percalc: "+percalc,'blue');    
}

