function WebBlank(){
  var qid = CurrentForm()
  var WebBlankValue = survey_setting()['WebBlankValue'];


  if ( getQuestionTypes() == 'OPEN' ){        
    if (Forward() && !f(qid).toBoolean() ) {
      f(qid).set(WebBlankValue);
