    }
    else if (!Forward() && f(qid).toBoolean() && f(qid) == WebBlankValue ) {
      f(qid).set(null);
      dvlp_echo(qid + ' = ' + f(qid),'9932cc');
    }
  }
  
  else if ( getQuestionTypes() == 'SINGLE' ){        
    if ( !f(qid).toBoolean() ) {
      f(qid).set(WebBlankValue);
      dvlp_echo(qid + ' = ' + f(qid).value(),'#9932cc');
    }
  }

  if ( getQuestionTypes() == 'MULTI' ){       
    if ( !f(qid).toBoolean() ) {
      f(qid)[WebBlankValue].set(1);
      dvlp_echo(qid+'_'+WebBlankValue+' = ' + f(qid)[WebBlankValue],'#9932cc');
    }
  }

  if ( getQuestionTypes() == 'GRID' ){        
    var codes = f(qid).domainValues();
    for (var i = 0; i < codes.length; i++)  {
        var currentPrecode = codes[i].toString();
        if ( !f(qid)[currentPrecode].toBoolean() ) {
          f(qid)[currentPrecode].set(WebBlankValue);
        }
    }
    dvlp_echo('WebBlank '+qid + ' = ' + f(qid).values(),'#9932cc');
  }
}//end function


