function ListSeparator(qid, separator) {
    var body: String = "";
    var form = f(qid);
    body += form.categoryLabels();
    if (form.size() > 1) {
        body = body.substring(0, body.lastIndexOf(",")) + " "+separator+" " +
            body.substring(body.lastIndexOf(",") + 1, body.length);
    }
    var sections : String[] = body.split(",");
    var finalText : String = sections[0];
    for (var i = 1; i < sections.length; i++) {
        finalText += ", " + sections[i];
    }
    return finalText;
}

