function othNumCheck(q, punch, min, max, dec) {

  //dec = Y or N  
  if (dec !== "Y") {
    var dec = "N";
  }

  var oth = q + "_" + punch + "_other";
  var strnum = "";
  strnum += f(oth);

  //check for first character as $ and strip
  var firstchar = strnum.slice(0, 1);
  if (firstchar == '$') {
    strnum = strnum.substring(1)
  }
  f(oth).set(strnum);

  //put back as number
  if (f(oth).toBoolean()) {
    var num = f(oth).toNumber();
    f(oth).set(num);

    if (f(q).any(punch)) {
      if (!IsNumeric(f(oth).toNumber())) {
        clearForm(q);   //clear punch
        clearForm(oth); //clear text
        ErrorMsg(GetCustomText(62));
      } else {
        if (f(oth).toNumber() < min || f(oth).toNumber() > max) {
          clearForm(q);   //clear punch
          clearForm(oth); //clear value
          ErrorMsg(GetCustomText(80));
        }

        if (dec == 'N') {
          if (numberDec_test(num)) {
            clearForm(q);   //clear punch
            clearForm(oth); //clear value
            ErrorMsg(GetCustomText(74));
          }
        }

      }
    }
  }
}

function numberDec_test(n)
{
   var result = (n - Math.floor(n)) !== 0; 
   
  if (result)
    return true;
   else
     return false
  }

