function isValidDate(dateString) {
  var yyyy = dateString.slice(0,4);
  var yyyy2 = parseInt(yyyy);
  var mm1 = dateString.slice(4,6);
  var mm2 = parseInt(mm1)-1;
  if (mm2<10) { 
    var mm = "0" + mm2;
  } else {
    var mm = mm2.toString();
  }
  var dd = dateString.slice(6,8);
  var dd2 = parseInt(dd);
  var fmtDate = "" + yyyy + "-" + mm + "-" + dd;
  //Response.Write("<br>Date: " + fmtDate);
  
  var regEx = /^\d{4}-\d{2}-\d{2}$/;
  if(!fmtDate.match(regEx)) return false;  // Invalid format
  
  var d = new Date(yyyy,mm,dd);
  //Response.Write("<br>Date: " + d);
  var dNum = d.getTime();
  //Response.Write("<br>Date: " + dNum);  
  
  //months without 31 days
  if ((mm2==3 || mm2==5 || mm2==8 || mm2==10) && dd2==31) {
    Response.Write("<br>Month not 31 days");  
    return false;
  }
  
  // check for february 29th
  if (mm2 == 1) { 
    var isleap = (yyyy2 % 4 == 0 && (yyyy2 % 100 != 0 || yyyy2 % 400 == 0));
    if (dd2>29 || (dd2==29 && !isleap)) {
      //Response.Write("<br>Feb not good date");  
      return false;
    }
  }
   
}

