}

//This script takes the respondent's date of birth (in this case it has been entered 
//as three separate questions – day, month and year) and calculates a numeric age 

//The month calculation subtracts one because the date stores the months as 0-11
function calculateAge(mm,dd,yyyy) {
if(f(yyyy).toBoolean()) { 
   var year = f(yyyy);
   var month = f(mm).toNumber()-1;
   var day = f(dd);
}

var birthday= new Date(year,month,day);

var today = new Date();
var years = today.getFullYear()-birthday.getFullYear();

//set the year of DOB to the current year to easily compare.  
birthday.setYear(today.getFullYear());

// If your birthday hasn't occurred yet this year, subtract 1.
if(today.valueOf() < birthday.valueOf())
{
years=years-1;
}

return years;
  
dvlp_echo('years:  ' + years, 'blue')  //testing code
}

//This script takes the respondent's date of birth (in this case it has been entered 
//as three separate questions – day, month and year) and calculates a numeric age 

//The month calculation subtracts one because the date stores the months as 0-11
//This script takes the respondent's date of birth (in this case it has been entered 
//as three separate questions – day, month and year) and calculates a numeric age 

//The month calculation subtracts one because the date stores the months as 0-11
function calculateAgeByMonth(mm,yyyy) {
if(f(yyyy).toBoolean()) { 
   var year = f(yyyy);
   var month = f(mm).toNumber()-1;
   var day = 1;
}

var birthday= new Date(year,month,day);

var today = new Date();
var years = today.getFullYear()-birthday.getFullYear();

//set the year of DOB to the current year to easily compare.
birthday.setYear(today.getFullYear());

// If your birthday hasn't occurred yet this year, subtract 1.
if(today.valueOf() < birthday.valueOf())
{
years=years-1;
}

return years;
  
dvlp_echo('years:  ' + years, 'blue')  //testing code
}

//This script takes the respondent's date of birth (in this case it has been entered 
//as three separate questions – day, month and year) and calculates a numeric value 

//The month calculation subtracts one because the date stores the months as 0-11
function calculateMonths(mm,dd,yyyy) {
if(f(yyyy).toBoolean()) { 
   var year = f(yyyy);
   var month = f(mm).toNumber()-1;
   var day = f(dd);
}

var birthday= new Date(year,month,day);

var today = new Date();
var months = today.getMonth()-birthday.getMonth()+(12*(today.getFullYear() - birthday.getFullYear())) ;

//set the month of DOB to the current month to easily compare.  
birthday.setMonth(today.getMonth());

// If your birthday hasn't occurred yet this month, subtract 1.
if(today.valueOf() < birthday.valueOf())
{
months=months-1;
}

return months;
  
dvlp_echo('months:  ' + months, 'blue')  //testing code
}

