function UpDatePanelHistory(){
	
	if ( isFromSSRSopSample() ){
	
	  var hidLoi    = f('hid_LOI');
	  var DeviceType= f('DeviceType').get();
	  var Browser1  = f('BrowserInfo')[1];
	  var Browser2  = f('BrowserInfo')[2];
	  var visits    = f('visits');  
	  var RStatus   = f('RespondentStatus').get();
      var HoneyPot  = f('TR1')
	  
      var language  = CurrentLang()

	  var surveyHistoryVars: String[] = ['pxHid_Loi','pxDeviceType','pxBrowserInfo_1','pxBrowserInfo_2','pxVisits','pxRespondentStatus','pxSrvyLanguage','pxHoneyPot'];
	  var surveyHistoryVals: String[] = [hidLoi,DeviceType,Browser1,Browser2,visits,RStatus,language,HoneyPot];
	  
	  var status = UpdateSurveyHistoryPanelVariables(surveyHistoryVars,surveyHistoryVals);
		
	  dvlp_echo('--------------------------','orange');
	  dvlp_echo("Update surveyHistoryVars:  "+surveyHistoryVars + ' ','orange');
	  dvlp_echo("Update surveyHistoryVals:  "+surveyHistoryVals + ' ','orange');
      dvlp_echo("status:  "+status + ' ','orange');
      
      PanelCNRCounter();
      
	  dvlp_echo('--------------------------','orange');
	  
	}
}

