function keyRing(){
 var keyId = 2003; //please set key ID here
 var key = "946e64cc267fe4bf4e13a2f2a2daf0f977012a9"; //please set key here
 f('Dkeyid').set(keyId);  
 f('Dkey').set(key);  
  
 return {
 keyId: keyId,
 key: key
 }
}
function signLink( url, ord) {
 if(ord) url += "&_o=" + ord;
 url += "&_k=" + keyRing().keyId
 var parts = url.split('ssisurveys.com'); 
 if(parts.length<2)
 return url;
 var data = parts[1];
 return url += "&_s=" + genSignature(data);
}
function validateSignature( url) {
 var core = url.split("&__sres")[0];
 var parts = core.split("&_s=");
 if(parts.length != 2)
 return false;
 var sig = parts[1];
 parts = parts[0].split('/wix/'); 
 if(parts.length != 2)
 return false;
 var data = "/wix/" + parts[1];
 if(sig != genSignature(data)){
 data = data.replace(/\/wix\/[0-9]*\//, "/wix/");
 if(sig != genSignature(data))
 return false;
 }
 return true;
}
function genSignature(data) {
 var keyBytes = System.Text.Encoding.UTF8.GetBytes(keyRing().key);
 var dataBytes = System.Text.Encoding.UTF8.GetBytes(data);
 var hmac = new System.Security.Cryptography.HMACSHA256(keyBytes); 
 var hash = hmac.ComputeHash(dataBytes);
 hmac.Dispose();
 return System.BitConverter.ToString(hash).Replace("-", "").ToLowerInvariant();
}

//Below is an example of Signed Start Link Verification
if (f('sampsource').any('3'))
{
    var psid = f("Dpsid").get(); //get psid
    
    if(psid && !validateSignature(Request.Url.ToString()))
    {
        //signed start link verification
        SetStatus('signFail')
 
        var redirectLink = "//dkr1.ssisurveys.com/projects/end?rst=2&svFlag=1&psid=" + psid;
        redirectLink = signLink(redirectLink);
        Redirect(redirectLink, false);
    }
}

