    {
  		qn.set(ipsosReturnURL);
        f('ipsosID').set(ipsosId);
	  	// Force sampsource to always be Ipsos where Live data found and Ipsos URL string variables are fully provided
		f("sampsource").set('4');
		SetRespondentValue("sampsource","4");
    }
}

function getIpsosURL(val)
{
  	var qn = f('IpsosRedirectFinal');
  	var qn1 = f('IpsosRedirectUrl');
  	var qn1a = f('IpsosExt_st');
  	var qn1b = f('IpsosIntlen');
  	var qn1c = f('IpsosTermpoint8');
  	var qn2 = f('hid_LOI');
  	var qn3 = f('RespondentStatus');
  	var url = qn1.get()+"&intlen="+qn2.get();
  	qn1b.set(qn2.get());

  	if(val=="complete")
    {
      	url += "&ext_st=1";
      	qn1a.set('1');
    }
  	else
    {
      	url += "&ext_st=2&termpoint8="+qn3.get();
      	qn1a.set('2');
      	qn1c.set(qn3.get());
    }
  
  	qn.set(url);

  	return url;
}

var qn = f('researchResultsState');
    
if(!qn.toBoolean())
{
  	var rrState = Request.QueryString('sstate');
	var rrId = Request.QueryString('rrid');
 
  	if(rrState!=null)
    {
  		qn.set(rrState);
        f('researchResultsRRID').set(rrId);
	  	// Force sampsource to always be Research Results where Live data found
		f("sampsource").set('37');
		SetRespondentValue("sampsource","37");
    }
}

var qn = f("bProbabilityBased");

if(!qn.toBoolean()) {
    qn.set('0');
}

if ( IsCati() && !f('visits').toBoolean() ){
  if ( IsPanel() ) {
	if (Forward() && GetRespondentValue('PanelistID')) {	
		var CNR = f('CNRCOUNTER');
		CNR = CNR+1
		var surveyVars: String[] = ['CNRCounter'];
		var surveyVals: String[] = [CNR];	  
		var status2 = UpdatePanelVariables(surveyVars,surveyVals);
	
		if ( f('recordtype').any('test') ) {
			Response.Write('<span style="color:orange"; font-family:"Lucida Console";font-size:8pt;line-height:8pt;display:block;">Update surveyVars:  '+surveyVars + '</span>');
			Response.Write('<span style="color:orange"; font-family:"Lucida Console";font-size:8pt;line-height:8pt;display:block;">Update surveyVals:  '+surveyVals + '</span>');
			Response.Write('<span style="color:orange"; font-family:"Lucida Console";font-size:8pt;line-height:8pt;display:block;">status:  '+status2 + '</span>');
		}
	}
  }
}

