Script.ScriptCode:
// Clear any previously stored dvlp_echos before testing
f("endStopMessage").set(null);

// Clear any previously stored dvlp_echos before testing
f("dvlp_echos").set(null);

//clear inbound flags related to call
f('CallSpecificInbound').set(null);

var now : DateTime = DateTime.Now;
f("interviewStart").set(now); // Use in Data Template exports for Survey Designer data exports instead of interview_start

if(!f("interviewStartFirst").toBoolean()) {
	f("interviewStartFirst").set(now);
}

if(!f('LastDate').toBoolean()) 
{
	var s = new Date();
  	f('LastDate').set(s);
}
  
var DateNow = new Date();
f('CurrDate').set(DateNow);

if(f('CurrDate') > f('LastDate')) 
{
	f('LastDate').set(DateNow);
	f('CallSpecificInboundLoop').set(null);
}

//Set Interview Channel CAWI, CATI, etc
f('xChannel').set(getChannel());

f('AUSID').set(survey_setting()['AUSID'].toString().toUpperCase());

f("viApiAmount").set(survey_setting()['VirtualIncentive']);

//Pull entire querysting from URL //
var qs = Request.QueryString;

if(!f('QS').toBoolean())
{
	f('QS').set(qs);
}

//test=1 (test interview.) 
//test=3 for sample providers to test sample but bypass Rvid
//else test=2 live record
var qnTEST = f('TEST');
var qnRecordType = f('recordType');

if(!qnTEST.toBoolean())
{
  	if(IsInRdgMode())
    {
      	qnTEST.set('1'); // Declare as TEST
      	qnRecordType.set('rdg'); // Declare as RDG
    }
  	else
  	{
      	var val = Request.QueryString('test');
      
        if(val=='1')
        {
            qnTEST.set('1'); // Declare as TEST
          	qnRecordType.set('test'); // Declare as Test
          	SetRespondentValue("recordType","test");
        }
		else if (val == '4') {
			qnTEST.set('4'); // Declare as TEST
			qnRecordType.set('testLikeLive'); // Declare as Test
			SetRespondentValue("recordType", "testLikeLive");
		}
        else if(val=='3')
        {
            qnTEST.set('3'); // Declare as RVID SKIP (for 3rd party sample providers when checking their redirects)
          	qnRecordType.set('test'); // Declare as Test
          	SetRespondentValue("recordType","test");
        }
        else
        {
           	if(!qnRecordType.toBoolean())
            {
            	qnTEST.set('2'); // Declare as LIVE
          		qnRecordType.set('live'); // Declare as Live
          		SetRespondentValue("recordType","live");
            }
          	else
            {
              	if(qnRecordType.any('live'))
                {
                  	qnTEST.set('2'); // Declare as LIVE
                }
				else if(qnRecordType.any('testLikeLive'))
				{
					qnTEST.set('4'); // Declare as TEST LIKE LIVE
				}
              	else
                {
                  	qnTEST.set('1'); // Declare as TEST
                }
            }
        }
    }
}
else
{
    if(!qnRecordType.toBoolean())
    {
      	if(qnTEST.any('1'))
        {
          	qnRecordType.set('test');
          	SetRespondentValue("recordType","test");
        }
		else if (qnTEST.any('4'))
		{
			qnRecordType.set('testLikeLive');
			SetRespondentValue("recordType", "testLikeLive");
		}
		else if(qnTEST.any('2','3'))
        {
          	qnRecordType.set('live');
          	SetRespondentValue("recordType","live");
        }
    }
}

// Set total respondent, counter for anyone who has clicked on link
f("TOTAL_RESPONDENTS").set('1');


//Set TimeStamp START for LOI
if(!f('xTimestamp_1').toBoolean())
{
	var a = new Date();
	var b = Math.floor((a.getTime()))
	f('xTimestamp_1').set(b);
      
	var date = OurDate(-5);
	var time = OurTime(-5);
	f("xTimestamp_3").set(date + "|" + time); 
    
	dvlp_echo('xTimestamp_1 Milli = '+f('xTimestamp_1'),'red');  	
	dvlp_echo('xTimestamp_3 Date|Time = '+f('xTimestamp_3'),'purple');     
}

if(!IsInRdgMode())
{
  	var qnQuesTimeLimit = f('xQuesTimeLimit');
  	var qnSpeeder = f('xSpeeder');
	var setting = survey_setting();

	if(IsCati())
	{
		qnQuesTimeLimit.set(setting['CatiPageTimeLimit']);
	}
	else if(IsWeb())
    {
  		qnQuesTimeLimit.set(setting['WebPageTimeLimit']);
	}

  
	//set all to NOT speeder, calculate MinSrvyLoi in Seconds
	if(!qnSpeeder.toBoolean())
    {
    	qnSpeeder.set('0')   // All begin survey as NOT speeder 

	    var MinSrvyLoi = setting['MinSurveyLOI'];     
    	var MinSrvy_LOI_Sec = MinSrvyLoi * 60;	//convert minutes to seconds  
    	f('xMinSrvyLoi').set(MinSrvy_LOI_Sec);
	}
}


var qnSampsource = f('sampsource');
var qnLogo = f('logo');
var qnSupport = f('support');
var ss = "";

if(!qnSampsource.toBoolean())
{
  	if(IsInRdgMode())
    {
      	// This is RDG mode, so always assume sampsource is '2'
  		ss = '1';				// Get the sample/BG data ahead of passing the BG variable
	  	qnSampsource.set(ss);	// set sampsource from BG var
		qnLogo.set(ss);			// set logo for survey layout
		qnSupport.set(ss);		// set support info for survey layout      	
    }
  	else
  	{
        if(Request.QueryString('sampsource'))
        {
            ss = Request.QueryString('sampsource');
            qnSampsource.set(ss);	//set sampsource by querystring--ONLY for during testing    	
            qnLogo.set(ss);			//set logo for survey layout
            qnSupport.set(ss);		//set support info for survey layout
          	SetRespondentValue('sampsource',ss); // Store in Respondent DB for any re-entry memory reason
        }
		else
        {
            // Sampsource information is missing from Sample, Request URL parameters or scripted in any other "hidden" way... default to sampsource = '1'
  			ss = '1'; 				// SSRS branding
			SetRespondentValue("sampsource",ss);	// Set Respondent Database for sampsoucre to prevent any re-entry clearing down
		  	qnSampsource.set(ss);	// set sampsource from BG var
			qnLogo.set(ss);			// set logo for survey layout
			qnSupport.set(ss);		// set support info for survey layout
		}
    } 
}
else
{
	ss = qnSampsource.get();	// get sampsource value from BG var
