if(!qnRespondentStatus.toBoolean() || (qnRespondentStatus.toBoolean() && qnRespondentStatus.any('16','95')))
{
	// If RespondentStatus is Null or Fresh Sample (16) or Web Fresh Sample (95)
	qnRespondentStatus.set('99'); // Set RespondentStatus to Incomplete (99)
	SetRespondentValue("RespondentStatus","99"); // Set RespondentStatus to Incomplete (99)
}


// This will allow us to enter a respondents survey IF survey set to
// Limited survey with login page (Requires an uploaded respondent list with userid & password fields)

if(IsInProductionMode())
{
