}


//increment the number of times an R returns to the survey.
var qnVisits = f('visits');
var iter = 0;	// for survey history loop

if(!qnVisits.toBoolean())
{
  	iter = 1;
}
else
{
	iter = qnVisits.toNumber()+1;
}

qnVisits.set(iter);

if(!IsInRdgMode())
{
