        GetRenderingMode	: GetRenderingMode(),							// get the rendering mode (e.g., web/smartphone/etc)
        IsDesktop					: GetDeviceInfo().IsDesktop,			// ---- start ----
        IsTouch						: GetDeviceInfo().IsTouch,				// 
        IsTablet					: GetDeviceInfo().IsTablet,				// 
