    dvlp_echo("GetRenderingMode		 = "+GetRenderingMode()					,'blue');
    dvlp_echo("IsDesktop		 = "+GetDeviceInfo().IsDesktop					,'blue');
    dvlp_echo("IsTouch			 = "+GetDeviceInfo().IsTouch						,'blue');
    dvlp_echo("IsTablet		 = "+GetDeviceInfo().IsTablet						,'blue');
    dvlp_echo("IsGeneric		 = "+GetDeviceInfo().IsGeneric					,'blue');
    dvlp_echo("IsMobile		 = "+GetDeviceInfo().IsMobile						,'blue');
    dvlp_echo("ScreenResolution = "+GetDeviceInfo().ScreenResolution				,'blue');
    dvlp_echo("HttpReferrer	 = "+Request.ServerVariables("HTTP_REFERER")		,'blue');
    dvlp_echo("userAgent		 = "+Request.ServerVariables("HTTP_USER_AGENT")	,'blue');
    dvlp_echo("DeviceType 		 = "+GetDeviceInfo().DeviceType.toString()			,'blue');
    */

	if(f('xChannel').any('1','3','4'))
	{
		if(!f('xBrowserSupportInfo').toBoolean())
    	{
			f('xBrowserSupportInfo').set(JSON().stringify([surveyInfo]));
    	}
		else
    	{
			var history = JSON().parse(f('xBrowserSupportInfo').get());
			var previous = history[history.length-1];
			var diff = false;

			for(var i in surveyInfo) 
    	    {
				if(surveyInfo[i]!=previous[i])
            	{
					diff=true;
	            }
              
				if(diff)
    			{
					history.push(surveyInfo);
					f('xBrowserSupportInfo').set(JSON().stringify(history));
            	}
    		}
		}
	}

  	processDeviceAndBrowserInfo();
  
    //dvlp_echo("= <br>");
    //dvlp_echo("f('xBrowserSupportInfo') = "+f('xBrowserSupportInfo'),'blue');

	function isBrowserSupported()
	{
		var supported = true;	//!AdvancedWIFeaturesEnabled();
	
	  	if(f("BrowserInfo_1").get().toLowerCase()=="ie" && f("BrowserInfo_2").get()=="8")
    	{
        	supported = false;
    	}

		return supported;
	}

	//dvlp_echo("f('BrowserInfo_1') = "+f('BrowserInfo_1'),'blue');
	//dvlp_echo("f('BrowserInfo_2') = "+f('BrowserInfo_2'),'blue');

	//do attempt mode
	f('AttChannel',iter).set(f('xChannel'));

	//do attempt number
	f('AttNumber',iter).set(iter);

    // do Date and Time
	SetInterviewStart();
	var start = new Date(InterviewStart().getTime());
	f('AttDate',iter).set(now);
    f('AttDateTime',iter).set(now); // Changed from start var
    f('Time_Last_Attempt').set(now);
    
  	if(GetSurveyChannel()=="Cati")
    {
        //for call history loop
        iter = GetCallAttemptCount();
        iter = iter * 1;
    
        f('CallDateTime',iter).set(start);
        f('Time_last_call').set(start);
      
        //do calls
        f('NoofCalls').set(iter);
          
        // do Interviewer Name
        f('LastCallIntName').set(GetCatiInterviewerName());
        f('Int_Name',iter).set(GetCatiInterviewerName());
    
        // do Site
        var str = f('LastCallIntName').get();
        var site = str.slice(0,2);
        f('LastSite').set(site);
        f('Site',iter).set(site);
    }
  
    //section timer clear
    clearSLT();

    if(!f('xSuspend').any('1'))
    {
		clearTimes();
    }
    
    var study = survey_setting()['AUSID'];
    var res = study.slice(5, 6);
    f('campaignLetter').set(res);
}

UpDatePanelHistory();

var ppIDvars = new Array("Duig","Dtid","Dowid","wspid","Dpsid","ipsosId","bSmpuniqueID","researchResultsRRID");
var qnPSID = f("psid");

for(var i=0; i<ppIDvars.length; i++) {
