}

var qn = f("VIapiCredential");

if(!qn.toBoolean())
{
    qn.set('DEV'); // Default to DEV

    if(f("recordType").any('live'))
    {
        f("VIapiCredential").set('PROD');
    }
}

f("QR_SURVEY_CODE_latestEntryOnly").set(null);

if (Request.QueryString("QR") != null)
{
    var QRcode = Request("QR");
    f('QR_SURVEY_CODE').set(QRcode);
    f('QR_SURVEY_CODE_latestEntryOnly').set(QRcode);
}

if (Request.QueryString("QR_SURVEY_CODE") != null) 
{
    var QRcode = Request("QR_SURVEY_CODE");
    f('QR_SURVEY_CODE').set(QRcode);
    f('QR_SURVEY_CODE_latestEntryOnly').set(QRcode);
}

var url = "";

if(GetSurveyChannel()=="Cati")
{
	url = GetCatiRespondentUrl("Start block",true);
}
else
{
  	url = GetRespondentUrl("Start block",true);
}

var splitUrl = url.split("__sid__=");
var CCPAurl = "https://survey.us.confirmit.com/wix/p346974191485.aspx?ppPID="+CurrentPID()+"&ppRID="+CurrentID()+"&ppSID="+splitUrl[1]+"&ppSMC="+f("bSSRS_MATCH_CODE").get();
f("CCPAurl").set(CCPAurl);

if(!f("ccpaClickCounter").toBoolean())
{
	f("ccpaClickCounter").set(0);
}

function updateCCPAcounter()
{
  	var qn = f("ccpaClickCounter");
  	if(!qn.toBoolean())
	{
		qn.set(0);
	}
  	qn.set(qn.toNumber()+1);
	f("ccpaFilterQn").set("|"+qn.toNumber());
  	return "done";
}

function processDeviceAndBrowserInfo()
{
    getBrowserCollection(f('xDevice_updateForQuota').get());
    // once advanced wI feature is passed do not update quota vars
    f('xDevice_updateForQuota').set(0);
    
    var platform = f('xbrowser_Platform_Code');
    var deviceInfo = GetDeviceInfo();
    var deviceType = f('DeviceType');
    var deviceCategory = f('DeviceCategory')
    var xbrowser_preType = f('xbrowser_preType');
    
    if(platform==1 && deviceInfo.IsMobile && deviceInfo.IsTouch) {deviceType.set(2);}
    else if(platform==1 && deviceInfo.IsTouch && deviceInfo.IsTablet) {deviceType.set(3);}
    else if(platform==2 && deviceInfo.IsMobile && deviceInfo.IsTouch) {deviceType.set(4);}
    else if(platform==2 && deviceInfo.IsTouch && deviceInfo.IsTablet) {deviceType.set(5);}
    else if(platform.none('1','2','3','4','5') && deviceInfo.IsMobile && deviceInfo.IsTouch) {deviceType.set(6);}
    else if(platform.none('1','2','3','4','5') && deviceInfo.IsTablet && deviceInfo.IsTouch) {deviceType.set(7);}
    else if(platform==3 && deviceInfo.IsMobile && deviceInfo.IsTouch) {deviceType.set(10);}
    else if(platform==4 && deviceInfo.IsTablet && deviceInfo.IsTouch) {deviceType.set(11);}
    else if(platform==3 && deviceInfo.IsMobile && !deviceInfo.IsTouch) {deviceType.set(12);}
    else if(platform==4 && deviceInfo.IsTablet && !deviceInfo.IsTouch) {deviceType.set(13);}
    else if(xbrowser_preType==14) {deviceType.set(14);}
    else if(platform==2 && deviceInfo.IsMobile && !deviceInfo.IsTouch) {deviceType.set(15);}
    else if(platform==2 && deviceInfo.IsTablet && !deviceInfo.IsTouch) {deviceType.set(16);}
    else if(xbrowser_preType==1 || deviceInfo.IsDesktop || platform==5) {deviceType.set(1);}
    else if(deviceInfo.IsGeneric) {deviceType.set(8);}
    else if(!deviceInfo.IsGeneric) {deviceType.set(9);}
    else {deviceType.set(99);}
    
    if(deviceType.any('1')) {deviceCategory.set(1);}
    else if(deviceType.any('3','5','7','11','13')) {deviceCategory.set(2);}
    else if(deviceType.any('2','4','6','10','12')) {deviceCategory.set(3);}
    else if(deviceType.any('8','9','14','15','16')) {deviceCategory.set(4);}
    else if(deviceType.any('99')) {deviceCategory.set(9);}
    
    f('hDevice',f('visits').toNumber()).set(deviceCategory);
}

var q = f('dtype');

if(!q.toBoolean())
{
	if(IsCatiInbound())
    {
  		q.set('1'); // INBOUND

		if(!f('EverInbound').toBoolean())
        {
     		f('EverInbound').set('1');
		}
 	}
 	else
    {
		q.set('0'); // OUTBOUND
  		SetRespondentValue('dtype','0');
    }
}

