function IsManualCatiStation(){
	if ( GetSurveyChannel() == 'Cati' ) {
      
      qclear('AUSID');  //clear AUSID
      
	  //alternative option--look for MAN anywhere in string
		//.get().toUpperCase().indexOf("MAN") != -1  
		
		var txt = GetCatiStationId().toString().toUpperCase()   //f('xJunk').toString().toUpperCase()  
	    //txt = txt.toUpperCase()
		var section = txt.slice(0,3);
		var station;
	    
	 if (section == 'MAN')   {
	  	station = true; 
	 }
	 else {
	   	station = false;  	
	 }

	 f('xCatiStation').set(txt) //MANWFH1234 
     
   var tmp = survey_setting()['AUSID'].toString().toUpperCase() + '-' + GetCatiStationId().toString().toUpperCase() //U1081W-MANWFH1234    
   f('AUSID').set(tmp);
    
    

	 dvlp_echo("------------------------------------", "black");
	 dvlp_echo("string = "+ section, "green");   	
	 dvlp_echo("Manual Station = "+ station, "green");
     dvlp_echo("AUSID + Station = "+ tmp, "green");
	 dvlp_echo("------------------------------------", "black");
	    
	 return station;
	}
	else{
	  return false;
	}   
	  
}

if ( !f('EverInbound').toBoolean() ) {
     f('EverInbound').set('1');
   }

f('CallSpecificInbound').set('2');
//Add to current day inbound data inbound type flag and inbound date for current call
var d = new Date();
if (f('CallSpecificInboundLoop').toBoolean()) {
  var x = f('CallSpecificInboundLoop') + "-" + f('CallSpecificInbound') + d.toString();
}
  else {
  var x = f('CallSpecificInbound') + d.toString();
 }
f('CallSpecificInboundLoop').set(x);

Open.ValidationCode:
var DialTelNum = f('CngDialTelNum');
var DialTelNumStr = DialTelNum.toString();

if(!IsNumeric(DialTelNum) || DialTelNumStr.length != 10)
