Multi.StartupScript:
// $("#hECKmoneyContact_content").css('display','none'); 
// This is an example line of code to hide a whole question. The above is for Email/Telephone to be hidden.
// This way you do not need to amend the code below

$(document).ready(function(){
  	$(".cf-open-list-answer__text").each(function(){
        var eachField = $(this);
        var txt = eachField.text();
        
        if(txt.includes(": "))
        {
            var newTxt = txt.split(": ");
            eachField.text(newTxt[1]);
        }
    });
});

$(function() {
    var moneyName = Confirmit.page.getQuestion("hECKmoneyName");
    var moneyAddress = Confirmit.page.getQuestion("hECKmoneyAddress");
    var moneyState = Confirmit.page.getQuestion("hECKmoneyState");
    var moneyZip = Confirmit.page.getQuestion("hECKmoneyZip");
    var moneyContact = Confirmit.page.getQuestion("hECKmoneyContact");
    var noMoney = Confirmit.page.getQuestion("hECKnoMoney");

    moneyName.changeEvent.on(function(e){
        if (moneyName.values['first']!=null || moneyName.values['last']!=null) {
            noMoney.setValue('');
        }
    });

    moneyAddress.changeEvent.on(function(e){
        if (moneyAddress.values['apt']!=null || moneyAddress.values['street']!=null || moneyAddress.values['city']!=null) {
            noMoney.setValue('');
        }
    });

    moneyState.changeEvent.on(function(e){
        if (moneyState.values['US']!=null){
            noMoney.setValue('');
        }
    });
    
    moneyZip.changeEvent.on(function(e){
        if (moneyZip.values['code']!=null) {
            noMoney.setValue('');
        }
    });

    moneyContact.changeEvent.on(function(e){
        if (moneyContact.values['email']!=null || moneyContact.values['telephone']!=null) {
            noMoney.setValue('');
        }
    });

    noMoney.changeEvent.on(function(){
        if (noMoney.value!=null) {
            moneyName.setValue('first','');
            moneyName.setValue('last','');
            moneyAddress.setValue('apt','');
            moneyAddress.setValue('street','');
            moneyAddress.setValue('city','');
            moneyState.setValue('US','');
            moneyZip.setValue('code','');
            moneyContact.setValue('email','');
            moneyContact.setValue('telephone','');
            noMoney.setValue('1');
        }
    });
});

Multi.ValidationCode:
var allMoneyQIDs = new Array("hECKmoneyName_first","hECKmoneyName_last","hECKmoneyAddress_apt","hECKmoneyAddress_street","hECKmoneyAddress_city","hECKmoneyState_US","hECKmoneyZip_code","hECKmoneyContact_email","hECKmoneyContact_telephone","hECKnoMoney");
var noQnsAnswered : Boolean = true;
var i : int = 0;
var eachQID = "";
var eachQn;

for(i=0; i<allMoneyQIDs.length; i++)
{
    eachQID = allMoneyQIDs[i];
    eachQn = f(eachQID);

    if(eachQn.toBoolean())
    {
        noQnsAnswered = false;
    }
}

if(noQnsAnswered)
{
    RaiseError();
    SetQuestionErrorMessage(CurrentLang(),f("xMESSAGES_32").label());
}
else
{
    if(!f("hECKnoMoney").toBoolean())
    {
        // Check for bare minimum to be answered for money to be processed
        var mustAnswerMoneyQIDs = new Array("hECKmoneyName_first","hECKmoneyName_last","hECKmoneyAddress_street","hECKmoneyAddress_city","hECKmoneyState_US","hECKmoneyZip_code");
        var noOfMustAnswerQnsAnswered : int = 0;
        var needToAnswer = mustAnswerMoneyQIDs.length;

        for (i=0; i<needToAnswer; i++)
        {
            eachQID = mustAnswerMoneyQIDs[i];
            eachQn = f(eachQID);

            if(eachQn.toBoolean())
            {
                // Please provide name, address, state and zip to continue, otherwise select "No Money" requested
                noOfMustAnswerQnsAnswered++;
            }
        }

        if(noOfMustAnswerQnsAnswered != needToAnswer)
        {
            RaiseError();
            SetQuestionErrorMessage(CurrentLang(),f("xMESSAGES_33").label());
        }
    }
}

var dbdQn = f("zipCodeDBDqn");
var qid = CurrentForm();
var qn = f(qid+"_code");
var qnState = f("hECKmoneyState_US");

if (qn.toBoolean()) 
{
    var zipEntered = qn.get();
    zipEntered = zipEntered.Trim();

    if (zipEntered.length != 5)
    {
        // Zip codes need to be 5 numbers long
        RaiseError();
        SetQuestionErrorMessage(CurrentLang(),f("xMESSAGES_34").label());
    }
    else
    {
        // Zip code is 5 characters long
        qn.set(zipEntered); // Ensure the data maintained is the cleaned version
        var zipEnteredAsDouble : Double = Double(zipEntered);

        if (Double.IsNaN(zipEnteredAsDouble))
        {
            // Not a Number entered
            RaiseError();
            SetQuestionErrorMessage(CurrentLang(), f("xMESSAGES_34").label());
        }
        else
        {
            // is 5 characters and all numbers so valid type, now check against database
            var checkZipState = dbdQn.GetAdditionalColumnValue(zipEnteredAsDouble, "State", 9);

            if (checkZipState)
            {
                // Match found, set State
                var selectedState = qnState.get();

                if (selectedState != checkZipState) 
                {
                    // ZIP does not match selected State
                    var qidNotInSoftErrorCheck = softErrorQIDcheck(qid);

                    if(qidNotInSoftErrorCheck)
                    {
                        // QID is not in Soft Error check, so show this error message once only.
                        RaiseError();
                        SetQuestionErrorMessage(CurrentLang(), f("xMESSAGES_35").label());
                    }
                }
            }
            else
            {
                // Zip not found on database
                RaiseError();
                SetQuestionErrorMessage(CurrentLang(), f("xMESSAGES_34").label());
            }
        }
    }
}

var qid = CurrentForm();
var qnEmail = f(qid+"_email");
var qnPhone = f(qid+"_telephone");
var errQn = f("xMESSAGES");

if(qnEmail.toBoolean())
{
    var emailEntered : String = qnEmail.get();

    if(!IsEmail(emailEntered))
    {
        RaiseError();
        SetQuestionErrorMessage(CurrentLang(),errQn['30'].label());
    }
}

if(qnPhone.toBoolean()) 
{
    var phoneEntered : String = qnPhone.get();
    var re = /^(?:\d|\+)(?:\d| )+$/;
    // Accepted format: start with + or digit followed by digits or spaces then after
    
    if (!re.test(phoneEntered))
    {
        RaiseError();
        SetQuestionErrorMessage(CurrentLang(), errQn['28'].label());
    }
}

Script.ScriptCode:
function hECKshowDetails()
{
    var txt: String = "<div class='hECKtitle'>";
    
    if(CurrentLang()==10)
    {
        txt += "Solo para confirmar:";
    }
    else 
    {
        txt += "Just to confirm...";
    }

    txt += "</div>";

    if (f("hECKnoMoney").any('1'))
    {
        txt += "<div class='hECKrow'>";
        txt += "<span class='hECKtitle'>Respondent <u>does not</u> want the money</span>";
        txt += "</div>";
    }
    else 
    {
        var allMoneyQIDs = new Array("hECKmoneyName_first", "hECKmoneyName_last", "hECKmoneyAddress_apt", "hECKmoneyAddress_street", "hECKmoneyAddress_city", "hECKmoneyState_US", "hECKmoneyZip_code", "hECKmoneyContact_email", "hECKmoneyContact_telephone");
        txt += "<div class='hECKmainArea'>";
        
        for(var i=0; i<allMoneyQIDs.length; i++)
        {
            var eachQID = allMoneyQIDs[i];
            var qn = f(eachQID);

            txt += "<div class='hECKrow'>";
            txt += "<span class='hECKlabel'>"+qn.label()+"</span>";
            txt += "<span class='hECKanswer'>";

            if(qn.toBoolean())
            {
                if(eachQID=="hECKmoneyState_US")
                {
                    txt += qn.valueLabel();
                }
                else
                {
                    txt += qn.get();
                }
            }
            else 
            {
                txt += "<i>Not provided</i>";
            }

            txt += "</span>";
            txt += "</div>";
        }

        txt += "<div class='hECKrow' style='margin-top:20px;'>";
        txt += "<span class='hECKtitle'>Respondent <u>does</u> want the money</span>";
        txt += "</div>";
    }

    txt += "</div>";
    txt +="<style>";
    txt += ".hECKtitle {font-style:italic; display:block; margin-bottom:20px;}";
    txt += ".hECKrow {display:flex; text-align: left;}";
    txt += ".hECKlabel {font-weight:bold; width:50%; float:left;}";
    txt += ".hECKanswer {font-weight:normal; display:block;}";
    txt += "</style>"

    return txt;
}

