function getAssociatedCode(checkThis)
{
	var checkThisArr = checkThis.split("_");
    var lookUpThisCode = checkThisArr[1]; // Gets everything after underscore
	var QIDmapCode = new Array("first_1","last_2","street_3","apt_4","city_5","US_6","code_7","email_8","telephone_9");
	var codeIs = "";
  
  	for (var i=0; i<QIDmapCode.length; i++) 
    {
      	var eachMapCode = QIDmapCode[i];
      	var eachMapCodeArr = eachMapCode.split("_");
      	var eachMapName = eachMapCodeArr[0]; // part before underscore
      	var eachMapCode = eachMapCodeArr[1]; // part after underscore
      	
      	if(eachMapName == lookUpThisCode)
        {
          	codeIs = eachMapCode;
        }
    }
  
  	return codeIs;
}

