function getVIURL()
{
    var username   = survey_setting()['VIusername']
    var password   = survey_setting()['VICredentialInUse']
    var programId  = survey_setting()['VIprogramID']
    var sku        = survey_setting()['VIsku']
    var amount	   = survey_setting()['VirtualIncentive']
    var clientId   =  CurrentPID() +'_'+ CurrentID()
    var firstName  = f('recordType').any('test','testLikeLive') ? 'Test Panelist' : IsPanel() ? f('RespondentName') : 'First Name' //GetPanelVariables('FNAME') 
    var lastName   = 'Last Name'  //GetPanelVariables('LNAME') 
    var email      = f('email').toString().toLowerCase().Trim()
    var pid        = CurrentPID() 				//UDF1 - VI User Defined Field #1
    var form       = survey_setting()['AUSID'].toString().toUpperCase() 			//UDF2
        form       = form + "~NFL Broadcasting Tracking" //UDF2
    var rid        = CurrentID() //UDF3
    var panelId    = f('recordType').any('test','testLikeLive') ? CurrentID() : IsPanel() ? f('PanelistId') : CurrentID() //UDF4
    var smpUniqueId  = f('bSmpUniqueID').toBoolean() ? f('bSmpUniqueID') : f('userid').toBoolean() ? f('userid') : 'NA'    //UDF5
        
    var vURL = VirtualIncentives.Reward.Order(username,password,programId,sku,amount,clientId,firstName,lastName,email,pid,form,rid,panelId,smpUniqueId);
	//vURL = 'https://ssrsopinionpanel.com/'
  
    if(!f('ViApiUrlReg').toBoolean() ) 
    {
      f('ViApiUrlReg').set(vURL);
    }
  //dvlp_echo('ViApiUrlReg = ' + f('ViApiUrlReg'),'red');
}

