mustAnswer2QnSingle();

var dbdQn = f("zipCodeDBDqn");
var qid = CurrentForm();
var qn = f(qid);

if(qn.toBoolean())
{
    var zipEntered = qn.get();
    zipEntered = zipEntered.Trim();
    
    if(zipEntered.length!=5)
    {
        // Zip codes need to be 5 numbers long
        RaiseError();
        SetQuestionErrorMessage(CurrentLang(),f("xMESSAGES_34").label());
    }
    else
    {
        // Zip code is 5 characters long
        qn.set(zipEntered); // Ensure the data maintained is the cleaned version
        var zipEnteredAsDouble : Double = Double(zipEntered);

        if(Double.IsNaN(zipEnteredAsDouble))
        {
            // Not a Number entered
            RaiseError();
            SetQuestionErrorMessage(CurrentLang(),f("xMESSAGES_34").label());
        }
        else
        {
            // is 5 characters and all numbers so valid type, now check against database
            var checkZipState = dbdQn.GetAdditionalColumnValue(zipEnteredAsDouble,"State",CurrentLang());

            if(checkZipState)
            {
                // Match found, set State
                f(qid+"State").set(checkZipState);
                setStateRegion(qid+"State");
                //get2022ZipInfo(qid)
                //Checking HMA based on zip code
                CheckZipHMA(qid)
            }
            else
            {
                // Zip not found on database
                RaiseError();
                SetQuestionErrorMessage(CurrentLang(),f("xMESSAGES_34").label());
            }

            //additional zip info
            var checkZipCenRegion = dbdQn.GetAdditionalColumnValue(zipEnteredAsDouble,"CensusRegion",CurrentLang());
//            var checkZipDensity = dbdQn.GetAdditionalColumnValue(zipEnteredAsDouble,"Pop18DensQuint",CurrentLang());
            var checkZipDMA = dbdQn.GetAdditionalColumnValue(zipEnteredAsDouble,"DMA",CurrentLang());
            f(qid+"CenRegion").set(checkZipCenRegion);
//            f(qid+"Density").set(checkZipDensity);
            f(qid+"DMA").set(checkZipDMA);

          
        }
    }
}

