Script.ScriptCode:
function useMADSprocessInThisSurvey()
{
  	return false; // change to true if wanted in this survey
}

/*
OTHER INSTRUCTIONS:
If your CATI setup is using ALL hours Scheduling Script, then it is already good.
If not, then Copy Rule 3 and the last Subrule in Rule 2 for handling ESC 119 and 120 to your Scheduling Script.

6 Data Processing Rules and 2 Rule Set Lists needs creating. 3 Rules in each Rule Set List.
Please copy the following rules like-for-like for your survey: 45959173, 45963851, 45963992, 45964160, 45964281 and 45964404.
Then add the first 3 rules to Rules Set List 1 (download) and second 3 rules to Rules Set List 2 (upload).
*/

function callLimitForWhenMADScheckOccurs()
{
	return 3; // The call limit for the first MADS check
}

function experimentCheck()
{
	var runMADScheck = true; // This means there is no experiment, therefore use on all, uinhide the below if experiment is required.
  
/*
	var runMADScheck = false;

  	if(f("Experiment_Flag").any('1'))
    {
		runMADScheck = true;
    }
*/
  
  	return runMADScheck;
}

var qid = "MADSdialStatus";
var callLimit = callLimitForWhenMADScheckOccurs();
var qn1 = f(qid);
var checkCallFailedCodes = new Array('2','3','5','7','31','32','33','62','67','68','70','72');
var excludeCallCounterOnCodes = new Array('15','24','26','29','1020');
var thisCallExtStatus = GetExtendedStatus();
var actualAttempts = f('attempts').toNumber();
var qnCatiVisits = f('catiAttempts');
var foundExcludeCallCounterOnCodes : Boolean = findMatch(thisCallExtStatus, excludeCallCounterOnCodes);
var iter = 0;

if(!foundExcludeCallCounterOnCodes)
{
    if(!qnCatiVisits.toBoolean()) {iter = 1;}
    else {iter = qnCatiVisits.toNumber()+1;}

	qnCatiVisits.set(iter);
	var thisCallAttempt = parseInt(qnCatiVisits.toNumber());

	if (useMADSprocessInThisSurvey()) {
		if(thisCallAttempt >= 1)
		{
			var foundFailedCode : Boolean = findMatch(thisCallExtStatus, checkCallFailedCodes);
			var thisSurveyStatus = GetStatus();
			var dontMatchStatusCodes = new Array('complete','quotafull','screened');
			var foundInDontMatchStatusCodes = findMatch(thisSurveyStatus, dontMatchStatusCodes);
			var MADStrackerTXT = "";

			if(!foundInDontMatchStatusCodes) 
			{
				// Not a complete, screened or quotafull response
				if (experimentCheck()) 
				{
					// Use Experiment or Use for all
					if (!f('xSuspend').toBoolean()) 
					{
						// Not a Suspend (survey not started)
						if(foundFailedCode) 
						{
							// this call matches against a dial outcome extended status code check
							var now : DateTime = DateTime.Now;
							var nowTXT : String = now.ToString("d MMM yy, H:mm:ss");
							
							if(!qn1.toBoolean() || qn1.toNumber()==1) 
							{
								if(thisCallAttempt < callLimit) 
								{
									qn1.set('1'); // under the callLimit - continue dialing
									SetRespondentValue(qid,"1");
									MADStrackerTXT = "This call = "+thisCallAttempt+", Limit = "+callLimit+", ESC = "+thisCallExtStatus+", MADSdialStatus = 1. ";
								}
								else if(thisCallAttempt >= callLimit)
								{
									qn1.set('2'); // callLimit achieved - no call answered activity - pause for MADS review - Ready for exporting
									SetRespondentValue(qid,"2");
									f("MADSdataHandler").set('1');
									MADStrackerTXT = "This call = "+thisCallAttempt+", Limit = "+callLimit+", ESC = "+thisCallExtStatus+" (becomes ESC 120), MADSdialStatus = 2, MADSdataHandler = 1. ";

									if(GetSurveyChannel()=="Cati")
									{
										// Prevent when testing outside CATI
										SetExtendedStatus(120); // Paused for MADS review   
									}
								}
							}
							
							if(f("MADStriggerTracker").toBoolean())
							{
								MADStrackerTXT = f("MADStriggerTracker").get() + nowTXT + ": " + MADStrackerTXT;
							}
							
							f("MADStriggerTracker").set(nowTXT + ": " + MADStrackerTXT);
						}
					}
				}
			}
		}
	}
}

function findMatch(itemToCheck,arr) {
    var returnVal : Boolean = false;

    for(var i in arr) {
        var checkCode = arr[i];

        if(itemToCheck == checkCode) {
            returnVal = true;
        }
    }
    
    return returnVal;
}

function TimeTracker( qid : String )
{
	var lastSta : DateTime; 
	var lastAct : DateTime;
	var doh : DateTime;
	var currentTime : DateTime;
	var dif : Int64; 
	var elapsed : TimeSpan;
	var elapsedTime : Double;
	const noOfDecimals : Int32 = 2; // Set the number of decimals that should be recorded
	const timeTacker : String = 'timeTracker';
  	var txt : String = '';
  	var qnErr = f("timeTrackerError");
  	var qnLastStart = f('timeTrackerLastStart');
  	var qnLastAction = f('timeTrackerLastAction');
  	var qnTimeTacker = f('timeTracker');
  	var qnTimeTrackerFirstOnPageQID = f('timeTrackerFirstOnPageQID');
  	var firstOnPageQID : String = "";
  	var dt : DateTime = DateTime.Now;
 
  	if(qnTimeTrackerFirstOnPageQID.toBoolean())
    {
      	firstOnPageQID = qnTimeTrackerFirstOnPageQID.get();
    }

  	if(firstOnPageQID==qid)
    {
        if(qnTimeTacker.toBoolean())
        {
            txt += qnTimeTacker.get()+",";
        }
      
        txt += "["+qid+",";
            
        try{
            lastSta = qnLastStart.toDate();
          	dt = new DateTime(lastSta.Year,lastSta.Month,lastSta.Day,lastSta.Hour,lastSta.Minute,lastSta.Second,lastSta.Millisecond);
        }
        catch (e){
            qnErr.set('qnLastStart.toDate(): '+e.message);
        }
        
        if (qnLastAction.toBoolean()){	
            try{
                lastAct = qnLastAction.toDate();
    	      	dt = new DateTime(lastAct.Year,lastAct.Month,lastAct.Day,lastAct.Hour,lastAct.Minute,lastAct.Second,lastAct.Millisecond);
              	txt += dt.ToString("yyMMddHHmmss")+","; // Seconds
            }
            catch (e){
                qnErr.set('qnLastAction.toDate(): '+e.message);
                txt += "NA,NA,";
            }	
        }
        else{
            lastAct = lastSta;
            doh = new DateTime(lastAct.Year,lastAct.Month,lastAct.Day,lastAct.Hour,lastAct.Minute,lastAct.Second,lastAct.Millisecond);
            qnLastAction.set(doh);
    	    dt = new DateTime(lastAct.Year,lastAct.Month,lastAct.Day,lastAct.Hour,lastAct.Minute,lastAct.Second,lastAct.Millisecond);
	        txt += dt.ToString("yyMMddHHmmss")+","; // Seconds
        }	
    
        if (lastSta > lastAct){
            lastAct = lastSta;
            doh = new DateTime(lastAct.Year,lastAct.Month,lastAct.Day,lastAct.Hour,lastAct.Minute,lastAct.Second,lastAct.Millisecond);
            qnLastAction.set(doh);
        }
    
        currentTime = DateTime.Now;
        dif = currentTime.Ticks - lastAct.Ticks; 
        elapsed = new TimeSpan(dif);
        elapsedTime = System.Math.Round(elapsed.TotalSeconds,noOfDecimals)
        txt += currentTime.ToString("yyMMddHHmmss")+","; // Seconds
        txt += elapsedTime.toString()+"]";
            
        qnTimeTacker.set(txt);
        var upd : DateTime = new DateTime(currentTime.Year,currentTime.Month,currentTime.Day,currentTime.Hour,currentTime.Minute,currentTime.Second,currentTime.Millisecond);
        
        try{
            qnLastAction.set(upd);
        }
        catch (e){
            qnErr.set('qnLastAction.set(upd): '+e.message);
        }
    }
}

function updateTimeTracker(){
	// Initial declaration of variables
  	var err : ExprObj = f('timeTrackerError');
	var real : ExprObj = f('timeTrackerRealStart');
	var last : ExprObj = f('timeTrackerLastStart');
  	var qnTimeTrackerFirstOnPageQID = f('timeTrackerFirstOnPageQID');
	var d1 : DateTime;
	var da : DateTime;
	
	// Check if realStart has a value. If no, set realStart and lastStart to the same value. If yes, update lastStart
	if (!real.toBoolean()){
		try{
	  		d1 = InterviewStart();
			da = new DateTime(d1.Year,d1.Month,d1.Day,d1.Hour,d1.Minute,d1.Second,d1.Millisecond);
			real.set(da);
			last.set(da);
		}
		catch (e){
			err.set(e.message);
		}	
	}
  	else {
		try{
	  		d1 = InterviewStart();
			da = new DateTime(d1.Year,d1.Month,d1.Day,d1.Hour,d1.Minute,d1.Second,d1.Millisecond);
			last.set(da);
		}
		catch (e){
			err.set(e.message);
		}	
	}
			
