  	f("smsCLI").set(respondentNumberUsedInSMSreply);
	f("smsActive").set("Y");
}

var dum = "survaccess";
var dumLastest = dum + "Latest";
var dumIntitial = dum + "Initial";
var dumMulti = dum + "All";
var dumSH = "SH" + dum;
var dumQS = "QSLastest";
var code = 0;
var qsStr = "";
var qnVisits = f('visits').toNumber();
var qs = Request.QueryString;

if(IsCati()) {
	var isIB = f('CallSpecificInbound').any('1','2') ? true : false; // Lloyd added a '2' as VM reply is considered inbound
	code = 1; // default to Outbound
	
	if(isIB){
		code = 2;
	}
}
else
{
	qsStr = String(qs);

	if (qsStr.length>0) {
		qsStr = qsStr.Trim();
		qsStr = qsStr.toLowerCase();
		f(dumQS).set(qsStr);
	}

	if (qsStr.indexOf("sms=")>=0) {
		code = 3;
	}
	else if (f("smsActive").any("Y")) {
		code = 4;
	}
	else if (qsStr.indexOf("qr=")>=0) {
		code = 6;
	}
	else if (qsStr.indexOf("email=")>=0) {
		code = 5;
	}
	else {
		code = 7;
	}
}

if(!f(dumIntitial).toBoolean())
{
	f(dumIntitial).set(code);
}

f(dum).set(code);
SetRespondentValue(dum,code);
f(dumLastest).set(code);
f(dumMulti)[code].set(1);
f(dumSH, qnVisits).set(code);

