	var codes2Randomised = shuffleArray(codes2);
    var codes = qn.domainValues();
    var codesRandomised = shuffleArray(codes);
    var counterF : int = 0;
    var counterI : int = 0;
    
  	if(!qn2.toBoolean())
    {
      	qn2.set(codes2Randomised[0]);
    }
  
    for(var i=0; i<codesRandomised.length; i++)
    {
        var code = codesRandomised[i];
        var codeFirstLetter = code.substring(0,1);
        var codeFirstLetterLower = codeFirstLetter.ToLower();
        
        if(codeFirstLetterLower=='f')
        {
            if(counterF<3)
            {
                qn[code].set('1');
                counterF++;
            }
        }
      
        if(codeFirstLetterLower=='i')
        {
            if(counterI<3)
            {
                qn[code].set('1');
                counterI++;
            }
        }
    }
}

