var qnRVIDscore =  f("relevantid_resultsScore");
var qnRVIDoutcome = f("relevantIDoutcome");
var qnFRAUDscore = f("xFraudScore");

if(qnRVIDscore.toBoolean()) {
	var RVIDscore = qnRVIDscore.toNumber();
  
  	if(RVIDscore>fraudScoreThreshold()) {
      	qnFRAUDscore.set('2'); // Fail
      	qnRVIDoutcome.set("fail");
    }
  	else {
      	qnFRAUDscore.set('1'); // Pass
      	qnRVIDoutcome.set("pass");
  	}

	var now : DateTime = DateTime.Now;
	f("relevantIDrunDate").set(now);
	f("relevantIDrun").set('1');
}
else {
	f("relevantIDrun").set('2');
}

function fraudScoreThreshold() {
  	return 30; // recommended default is 30
}

Multi.StartupScript:
$('form').append('<input type="hidden" id="qualityscore_collect_disabled">');
$('.cf-question__content').hide();
$('body').hide();

document.onreadystatechange = () => {
    if (document.readyState == "complete") {
        var submitted = 0;

        function submitForm() {
            if (!submitted) {
                submitted = 1;
                Confirmit._pageView._page.next();
            }
        }
        setTimeout(submitForm, 10000);

        try {
            imperium_qualityscore.AnalyzeData(AnalyzeDataReponse);
        }
        catch (e) {
            console.error(e);
            submitForm();
        }

        function AnalyzeDataReponse(jsonData) {
            try {
                if (jsonData.StatusCode == 200) {
                    var i=1; var currentQuestion = Confirmit.page.getQuestion('qualityscore');
                    currentQuestion.setValue("resultsScore", jsonData.Score)
                    currentQuestion.setValue("resultsTransactionGuid", jsonData.TransactionGuid)
                    currentQuestion.setValue("resultsMode", jsonData.Mode)
                    currentQuestion.setValue("resultsBackgroundAndTech", jsonData.BackgroundAndTech)
                    currentQuestion.setValue("resultsOpenEndBehaviors", jsonData.OpenEndBehaviors)
                    currentQuestion.setValue("resultsActiveBehaviors", jsonData.ActiveBehaviors)                 
                }
            }
            catch (e) { console.error(e); };
            submitForm();
        }
    }
};

