    f("QSactiveBehaviors").set(qnAB);
}

if (qnBT.toBoolean()) {
    f("QSbackgroundAndTech").set(qnBT);
}

if (qnOB.toBoolean()) {
    f("QSopenEndBehaviors").set(qnOB);
}
